CREATE OR REPLACE FUNCTION "public"."current_app_user_id"() RETURNS "uuid"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
  select u.id
  from public.users u
  where (
      u.auth_id = (select auth.uid())
      or (
        u.auth_id is null
        and lower(u.email) = lower(coalesce((select auth.jwt() ->> 'email'), ''))
      )
    )
    and u.is_active
    and u.account_status = 'ACTIVE'
  order by case when u.auth_id = (select auth.uid()) then 0 else 1 end
  limit 1;
$$;


ALTER FUNCTION "public"."current_app_user_id"() OWNER TO "postgres";

