CREATE OR REPLACE FUNCTION "public"."accrue_leave_balances"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$ DECLARE v_current_month INTEGER := EXTRACT(MONTH FROM NOW())::INTEGER; v_current_year INTEGER := EXTRACT(YEAR FROM NOW())::INTEGER; v_months_missing INTEGER; v_new_accrued NUMERIC; BEGIN IF NEW.year <> v_current_year THEN RETURN NEW; END IF; IF NEW.last_accrual_month >= v_current_month THEN RETURN NEW; END IF; v_months_missing := v_current_month - COALESCE(NEW.last_accrual_month, 0); v_new_accrued := COALESCE(NEW.accrued_days, 0) + COALESCE(NEW.monthly_accrual, 1.5) * v_months_missing; NEW.accrued_days := v_new_accrued; NEW.last_accrual_month := v_current_month; RETURN NEW; END; $$;


ALTER FUNCTION "public"."accrue_leave_balances"() OWNER TO "postgres";


