CREATE OR REPLACE FUNCTION "public"."ai_tool_cost_template_summary"("p_project_type" "text" DEFAULT NULL::"text", "p_keyword" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
declare
  v_kw text := '%' || lower(trim(coalesce(p_keyword, ''))) || '%';
  v_result jsonb;
begin
  with filtered as (
    select t.*
    from public.cost_templates t
    where t.status <> 'archived'
      and (p_project_type is null or lower(coalesce(t.project_type, '')) = lower(p_project_type))
      and (
        p_keyword is null
        or lower(t.code) like v_kw
        or lower(t.name) like v_kw
        or lower(coalesce(t.description, '')) like v_kw
      )
    order by case when t.status = 'active' then 0 else 1 end, t.effective_from desc, t.name
    limit 20
  )
  select jsonb_build_object(
    'total', count(*),
    'project_type_filter', p_project_type,
    'keyword', p_keyword,
    'templates', coalesce(jsonb_agg(
      jsonb_build_object(
        'id', f.id,
        'code', f.code,
        'name', f.name,
        'project_type', f.project_type,
        'status', f.status,
        'version_no', f.version_no,
        'effective_from', f.effective_from,
        'effective_to', f.effective_to,
        'assumptions', f.assumptions,
        'parameters', (
          select coalesce(jsonb_agg(jsonb_build_object(
            'code', p.code,
            'label', p.label,
            'data_type', p.data_type,
            'unit', p.unit,
            'is_required', p.is_required,
            'default_value', p.default_value,
            'options', p.options,
            'validation_rules', p.validation_rules
          ) order by p.sort_order), '[]'::jsonb)
          from public.cost_template_parameters p
          where p.template_id = f.id
        ),
        'sections', (
          select coalesce(jsonb_agg(jsonb_build_object(
            'code', s.code,
            'name', s.name,
            'sort_order', s.sort_order
          ) order by s.sort_order), '[]'::jsonb)
          from public.cost_template_sections s
          where s.template_id = f.id
        ),
        'sample_items', (
          select coalesce(jsonb_agg(jsonb_build_object(
            'code', i.code,
            'name', i.name,
            'item_type', i.item_type,
            'unit', i.unit,
            'quantity_formula', i.quantity_formula,
            'work_code', i.work_code,
            'norm_group_code', i.norm_group_code
          ) order by i.sort_order), '[]'::jsonb)
          from (
            select *
            from public.cost_template_items i
            where i.template_id = f.id
            order by i.sort_order
            limit 30
          ) i
        )
      )
    ), '[]'::jsonb)
  )
  into v_result
  from filtered f;

  return v_result;
end;
$$;


ALTER FUNCTION "public"."ai_tool_cost_template_summary"("p_project_type" "text", "p_keyword" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."ai_tool_daily_log_summary"("p_project_id" "text", "p_from_date" "date" DEFAULT NULL::"date", "p_to_date" "date" DEFAULT NULL::"date") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_result jsonb;
  v_total bigint;
  v_breakdown jsonb;
  v_recent jsonb;
begin
  select count(*) into v_total from daily_logs dl
  where dl.construction_site_id = p_project_id
    and (p_from_date is null or dl.log_date::date >= p_from_date)
    and (p_to_date is null or dl.log_date::date <= p_to_date);

  select coalesce(jsonb_object_agg(status, cnt), '{}'::jsonb) into v_breakdown
  from (
    select dl.status, count(*) as cnt from daily_logs dl
    where dl.construction_site_id = p_project_id
      and (p_from_date is null or dl.log_date::date >= p_from_date)
      and (p_to_date is null or dl.log_date::date <= p_to_date)
    group by dl.status
  ) sb;

  select coalesce(jsonb_agg(
    jsonb_build_object('id', dl2.id, 'log_date', dl2.log_date, 'status', dl2.status, 'weather', dl2.weather, 'created_at', dl2.created_at)
    order by dl2.log_date desc
  ), '[]'::jsonb) into v_recent
  from daily_logs dl2
  where dl2.construction_site_id = p_project_id
    and (p_from_date is null or dl2.log_date::date >= p_from_date)
    and (p_to_date is null or dl2.log_date::date <= p_to_date)
  limit 10;

  return jsonb_build_object('project_id', p_project_id, 'total_logs', v_total, 'status_breakdown', v_breakdown, 'recent_logs', v_recent);
end;
$$;


ALTER FUNCTION "public"."ai_tool_daily_log_summary"("p_project_id" "text", "p_from_date" "date", "p_to_date" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."ai_tool_employee_search"("p_keyword" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_result jsonb;
  v_kw text := '%' || lower(trim(coalesce(p_keyword, ''))) || '%';
  v_kw_unaccent text := '%' || lower(unaccent(trim(coalesce(p_keyword, '')))) || '%';
begin
  select jsonb_build_object(
    'keyword', trim(coalesce(p_keyword, '')),
    'total_found', count(*),
    'employees', coalesce(jsonb_agg(
      jsonb_build_object(
        'id', e.id,
        'employee_code', e.employee_code,
        'full_name', e.full_name,
        'title', e.title,
        'gender', e.gender,
        'phone', e.phone,
        'email', e.email,
        'date_of_birth', e.date_of_birth,
        'start_date', e.start_date,
        'official_date', e.official_date,
        'status', coalesce(e.status, 'active'),
        'marital_status', e.marital_status,
        'avatar_url', e.avatar_url,
        'department_name', ou.name,
        'position_name', hp.name,
        'site_name', hcs.name
      )
      order by e.full_name
    ), '[]'::jsonb)
  )
  into v_result
  from (
    select emp.*
    from employees emp
    where lower(emp.full_name) like v_kw
       or lower(unaccent(coalesce(emp.full_name, ''))) like v_kw_unaccent
       or lower(emp.employee_code) like v_kw
    limit 20
  ) e
  left join org_units ou on ou.id = e.org_unit_id
  left join hrm_positions hp on hp.id = e.position_id
  left join hrm_construction_sites hcs on hcs.id = e.construction_site_id;

  return v_result;
end;
$$;


ALTER FUNCTION "public"."ai_tool_employee_search"("p_keyword" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."ai_tool_employee_summary"("p_department_id" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare v_result jsonb;
begin
  select jsonb_build_object(
    'total_employees', count(*),
    'active', count(*) filter (where e.status = 'active' or e.status is null),
    'inactive', count(*) filter (where e.status = 'inactive'),
    'resigned', count(*) filter (where e.status = 'resigned'),
    'by_department', (select coalesce(jsonb_agg(jsonb_build_object('department', coalesce(ou.name, 'Chua phan phong'), 'count', d.cnt) order by d.cnt desc), '[]'::jsonb) from (select e2.org_unit_id, count(*) as cnt from employees e2 where (p_department_id is null or e2.org_unit_id::text = p_department_id) group by e2.org_unit_id) d left join org_units ou on ou.id = d.org_unit_id),
    'recent_employees', coalesce(jsonb_agg(jsonb_build_object('id', e.id, 'employee_code', e.employee_code, 'full_name', e.full_name, 'status', coalesce(e.status, 'active'), 'org_unit_id', e.org_unit_id) order by e.created_at desc nulls last) filter (where e.id is not null), '[]'::jsonb)
  ) into v_result from (select * from employees where (p_department_id is null or org_unit_id::text = p_department_id) limit 50) e;
  return v_result;
end; $$;


ALTER FUNCTION "public"."ai_tool_employee_summary"("p_department_id" "text") OWNER TO "postgres";


