CREATE OR REPLACE FUNCTION "public"."ai_tool_estimate_scenario_summary"("p_project_id" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT NULL::"text", "p_keyword" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
declare
  v_kw text := '%' || lower(trim(coalesce(p_keyword, ''))) || '%';
  v_result jsonb;
begin
  with filtered as (
    select es.*
    from public.estimate_scenarios es
    where (p_project_id is null or es.project_id = p_project_id or es.construction_site_id = p_project_id)
      and (p_status is null or es.status = p_status)
      and (
        p_keyword is null
        or lower(coalesce(es.code, '')) like v_kw
        or lower(es.name) like v_kw
        or lower(coalesce(es.customer_name, '')) like v_kw
        or lower(coalesce(es.project_type, '')) like v_kw
      )
    order by es.created_at desc
    limit 30
  )
  select jsonb_build_object(
    'total', count(*),
    'filters', jsonb_build_object(
      'project_id', p_project_id,
      'status', p_status,
      'keyword', p_keyword
    ),
    'summary', jsonb_build_object(
      'draft', count(*) filter (where status = 'draft'),
      'reviewed', count(*) filter (where status = 'reviewed'),
      'finalized', count(*) filter (where status = 'finalized'),
      'converted', count(*) filter (where status = 'converted'),
      'total_quote_amount', coalesce(sum(quote_amount), 0)
    ),
    'scenarios', coalesce(jsonb_agg(
      jsonb_build_object(
        'id', f.id,
        'code', f.code,
        'name', f.name,
        'project_id', f.project_id,
        'construction_site_id', f.construction_site_id,
        'customer_name', f.customer_name,
        'project_type', f.project_type,
        'status', f.status,
        'template_id', f.template_id,
        'template_version_no', f.template_version_no,
        'missing_parameters', f.missing_parameters,
        'assumptions', f.assumptions,
        'risk_warnings', f.risk_warnings,
        'confidence_score', f.confidence_score,
        'quote_amount', f.quote_amount,
        'currency', f.currency,
        'converted_project_id', f.converted_project_id,
        'converted_contract_id', f.converted_contract_id,
        'created_at', f.created_at,
        'updated_at', f.updated_at,
        'item_count', (
          select count(*)
          from public.estimate_items ei
          where ei.estimate_id = f.id
        )
      )
      order by f.created_at desc
    ), '[]'::jsonb)
  )
  into v_result
  from filtered f;

  return v_result;
end;
$$;


ALTER FUNCTION "public"."ai_tool_estimate_scenario_summary"("p_project_id" "text", "p_status" "text", "p_keyword" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."ai_tool_executive_dashboard"() RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare v_inv jsonb; v_proj jsonb; v_hr jsonb; v_mr jsonb; v_po jsonb; v_fin jsonb;
begin
  select jsonb_build_object('total_items', count(*), 'total_stock', coalesce(sum((select sum(val.value::numeric) from jsonb_each_text(coalesce(i.stock_by_warehouse, '{}'::jsonb)) as val)), 0), 'low_stock_count', count(*) filter (where (select sum(val.value::numeric) from jsonb_each_text(coalesce(i.stock_by_warehouse, '{}'::jsonb)) val) < coalesce(i.min_stock, 0) and coalesce(i.min_stock, 0) > 0))
  into v_inv from items i;

  select jsonb_build_object('total_projects', count(*))
  into v_proj from hrm_construction_sites;

  select jsonb_build_object('total_employees', count(*), 'active_employees', count(*) filter (where e.status = 'active' or e.status is null or e.status = E'\u0110ang l\u00e0m vi\u1ec7c'))
  into v_hr from employees e;

  select jsonb_build_object('total_mr', count(*), 'pending_mr', count(*) filter (where mr.status in ('pending', 'submitted', 'draft')))
  into v_mr from project_material_requests mr;

  select jsonb_build_object('total_po', count(*), 'pending_po', count(*) filter (where po.status in ('pending', 'submitted', 'draft')), 'total_po_value', coalesce(sum(po.total_amount), 0))
  into v_po from purchase_orders po;

  select jsonb_build_object('income_this_month', coalesce(sum(case when pt.type = 'income' then pt.amount else 0 end), 0), 'expense_this_month', coalesce(sum(case when pt.type = 'expense' then pt.amount else 0 end), 0))
  into v_fin from project_transactions pt where pt.date::date >= date_trunc('month', current_date)::date;

  return jsonb_build_object('generated_at', now(), 'inventory', v_inv, 'projects', v_proj, 'employees', v_hr, 'material_requests', v_mr, 'purchase_orders', v_po, 'finance_this_month', v_fin);
end; $$;


ALTER FUNCTION "public"."ai_tool_executive_dashboard"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."ai_tool_internal_norms_lookup"("p_keyword" "text", "p_region" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 20) RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
declare
  v_kw text := '%' || lower(trim(coalesce(p_keyword, ''))) || '%';
  v_limit integer := least(greatest(coalesce(p_limit, 20), 1), 50);
  v_result jsonb;
begin
  select jsonb_build_object(
    'keyword', trim(coalesce(p_keyword, '')),
    'region_filter', p_region,
    'security_note', 'Định mức nội bộ chỉ là căn cứ dự toán draft, cần người có quyền review.',
    'total_found', count(*),
    'norms', coalesce(jsonb_agg(
      jsonb_build_object(
        'id', s.id,
        'norm_code', s.norm_code,
        'work_code', s.work_code,
        'resource_code', s.resource_code,
        'resource_name', s.resource_name,
        'resource_type', s.resource_type,
        'unit', s.unit,
        'norm_quantity', s.norm_quantity,
        'waste_percent', s.waste_percent,
        'formula', s.formula,
        'applicable_parameters', s.applicable_parameters,
        'region', s.region,
        'version_no', s.version_no,
        'effective_from', s.effective_from,
        'effective_to', s.effective_to,
        'confidence_score', s.confidence_score
      )
      order by s.norm_code, s.region, s.effective_from desc
    ), '[]'::jsonb)
  )
  into v_result
  from (
    select *
    from public.internal_norms n
    where n.status = 'active'
      and (n.effective_from <= current_date)
      and (n.effective_to is null or n.effective_to >= current_date)
      and (p_region is null or lower(n.region) in ('all', lower(p_region)))
      and (
        lower(n.norm_code) like v_kw
        or lower(coalesce(n.work_code, '')) like v_kw
        or lower(coalesce(n.resource_code, '')) like v_kw
        or lower(n.resource_name) like v_kw
      )
    order by n.norm_code, n.region, n.effective_from desc
    limit v_limit
  ) s;

  return v_result;
end;
$$;


ALTER FUNCTION "public"."ai_tool_internal_norms_lookup"("p_keyword" "text", "p_region" "text", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."ai_tool_internal_price_book_lookup"("p_keyword" "text", "p_region" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 20) RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
declare
  v_kw text := '%' || lower(trim(coalesce(p_keyword, ''))) || '%';
  v_limit integer := least(greatest(coalesce(p_limit, 20), 1), 50);
  v_result jsonb;
begin
  select jsonb_build_object(
    'keyword', trim(coalesce(p_keyword, '')),
    'region_filter', p_region,
    'security_note', 'Đơn giá nội bộ là dữ liệu nhạy cảm; chỉ trả qua Edge Function sau khi xác nhận quyền.',
    'total_found', count(*),
    'prices', coalesce(jsonb_agg(
      jsonb_build_object(
        'id', s.id,
        'item_code', s.item_code,
        'item_name', s.item_name,
        'item_type', s.item_type,
        'category', s.category,
        'spec', s.spec,
        'unit', s.unit,
        'region', s.region,
        'brand', s.brand,
        'currency', s.currency,
        'unit_price', s.unit_price,
        'version_no', s.version_no,
        'effective_from', s.effective_from,
        'effective_to', s.effective_to,
        'status', s.status,
        'sensitivity_level', s.sensitivity_level
      )
      order by s.item_name, s.region, s.effective_from desc
    ), '[]'::jsonb)
