      and (
        lower(ipb.item_code) like v_kw
        or lower(ipb.item_name) like v_kw
        or lower(coalesce(ipb.category, '')) like v_kw
        or lower(coalesce(ipb.spec, '')) like v_kw
      )
    order by ipb.item_name, ipb.region, ipb.effective_from desc
