CREATE OR REPLACE FUNCTION "public"."ai_tool_inventory_summary"("p_warehouse_id" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_result jsonb;
begin
  with item_stocks as (
    select i.id, i.min_stock, i.price_in,
      case when p_warehouse_id is not null then coalesce((i.stock_by_warehouse ->> p_warehouse_id)::numeric, 0)
      else coalesce((select sum(val.value::numeric) from jsonb_each_text(coalesce(i.stock_by_warehouse, '{}'::jsonb)) as val), 0)
      end as total_stock
    from items i
  )
  select jsonb_build_object(
    'total_items', count(*),
    'total_stock', coalesce(sum(total_stock), 0),
    'low_stock_items', count(*) filter (where total_stock < coalesce(min_stock, 0) and coalesce(min_stock, 0) > 0),
    'total_value', round(coalesce(sum(coalesce(price_in, 0) * total_stock), 0), 0),
    'warehouse_filter', coalesce(p_warehouse_id, 'all'),
    'warehouses', (select coalesce(jsonb_agg(jsonb_build_object('id', w.id, 'name', w.name) order by w.name), '[]'::jsonb) from warehouses w)
  )
  into v_result from item_stocks;
  return v_result;
end;
$$;


ALTER FUNCTION "public"."ai_tool_inventory_summary"("p_warehouse_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."ai_tool_material_request_status"("p_project_id" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_total bigint;
  v_breakdown jsonb;
  v_recent jsonb;
begin
  select count(*) into v_total from project_material_requests mr
  where (p_project_id is null or mr.construction_site_id = p_project_id)
    and (p_status is null or mr.status = p_status);

  select coalesce(jsonb_object_agg(status, cnt), '{}'::jsonb) into v_breakdown
  from (select mr.status, count(*) as cnt from project_material_requests mr
    where (p_project_id is null or mr.construction_site_id = p_project_id)
      and (p_status is null or mr.status = p_status)
    group by mr.status) sb;

  select coalesce(jsonb_agg(
    jsonb_build_object('id', mr2.id, 'code', mr2.code, 'status', mr2.status,
      'requester', coalesce((select u.name from users u where u.id = mr2.created_by::text limit 1), mr2.created_by::text),
      'created_at', mr2.created_at, 'item_count', coalesce(jsonb_array_length(mr2.items), 0))
    order by mr2.created_at desc
  ), '[]'::jsonb) into v_recent
  from (select * from project_material_requests mr2
    where (p_project_id is null or mr2.construction_site_id = p_project_id)
      and (p_status is null or mr2.status = p_status)
    order by mr2.created_at desc limit 20) mr2;

  return jsonb_build_object('total', v_total, 'status_breakdown', v_breakdown, 'recent_requests', v_recent);
end;
$$;


