CREATE OR REPLACE FUNCTION "public"."ai_tool_material_search"("p_keyword" "text", "p_warehouse_id" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_result jsonb;
  v_kw text := '%' || lower(trim(coalesce(p_keyword, ''))) || '%';
begin
  select jsonb_build_object(
    'keyword', trim(coalesce(p_keyword, '')),
    'total_found', count(*),
    'items', coalesce(jsonb_agg(
      jsonb_build_object('id', s.id, 'sku', s.sku, 'name', s.name, 'category', s.category, 'unit', s.unit, 'price_in', s.price_in, 'price_out', s.price_out, 'total_stock', s.total_stock, 'min_stock', s.min_stock, 'supplier_id', s.supplier_id)
      order by s.name
    ), '[]'::jsonb)
  )
  into v_result
  from (
    select i.id, i.sku, i.name, i.category, i.unit, i.price_in, i.price_out, i.min_stock, i.supplier_id,
      case when p_warehouse_id is not null then coalesce((i.stock_by_warehouse ->> p_warehouse_id)::numeric, 0)
      else coalesce((select sum(val.value::numeric) from jsonb_each_text(coalesce(i.stock_by_warehouse, '{}'::jsonb)) as val), 0)
      end as total_stock
    from items i
    where lower(coalesce(i.name, '')) like v_kw or lower(coalesce(i.sku, '')) like v_kw
    limit 30
  ) s;
  return v_result;
end;
$$;


