CREATE OR REPLACE FUNCTION "public"."ai_tool_project_finance"("p_project_id" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare v_result jsonb;
begin
  select jsonb_build_object(
    'project_id', p_project_id,
    'project_name', coalesce((select h.name from hrm_construction_sites h where h.id = p_project_id limit 1), 'N/A'),
    'budget', jsonb_build_object('contract_value', coalesce(pf."contractValue", 0), 'budget_materials', coalesce(pf."budgetMaterials", 0), 'budget_labor', coalesce(pf."budgetLabor", 0), 'revenue_received', coalesce(pf."revenueReceived", 0), 'progress_percent', coalesce(pf."progressPercent", 0)),
    'transactions_summary', (select jsonb_build_object('total_income', coalesce(sum(case when pt.type = 'income' then pt.amount else 0 end), 0), 'total_expense', coalesce(sum(case when pt.type = 'expense' then pt.amount else 0 end), 0), 'net', coalesce(sum(case when pt.type = 'income' then pt.amount else 0 end) - sum(case when pt.type = 'expense' then pt.amount else 0 end), 0), 'transaction_count', count(*)) from project_transactions pt where pt."constructionSiteId" = p_project_id)
  ) into v_result from project_finances pf where pf."constructionSiteId" = p_project_id limit 1;
  if v_result is null then return jsonb_build_object('project_id', p_project_id, 'error', 'Chua co du lieu tai chinh cho du an nay.'); end if;
  return v_result;
end; $$;


