    'not_started', count(*) filter (where t.progress = 0 or t.progress is null),
    'tasks', coalesce(jsonb_agg(
      jsonb_build_object('id', t.id, 'name', t.name, 'progress', coalesce(t.progress, 0), 'gate_status', t.gate_status, 'start_date', t.start_date, 'end_date', t.end_date, 'parent_id', t.parent_id)
      order by t.start_date asc nulls last
    ) filter (where t.id is not null), '[]'::jsonb)
  )
  into v_result
  from project_tasks t where t.construction_site_id = p_project_id;
  return v_result;
end;
