  select jsonb_build_object('id', h.id, 'name', h.name, 'address', h.address)
  into v_site from hrm_construction_sites h where h.id = p_project_id;
  if v_site is null then return jsonb_build_object('error', 'Khong tim thay du an voi ID: ' || coalesce(p_project_id, 'null')); end if;
  select jsonb_build_object('contract_value', coalesce(pf."contractValue", 0), 'progress_percent', coalesce(pf."progressPercent", 0), 'budget_materials', coalesce(pf."budgetMaterials", 0), 'budget_labor', coalesce(pf."budgetLabor", 0), 'revenue_received', coalesce(pf."revenueReceived", 0), 'finance_status', coalesce(pf.status, 'N/A'))
  into v_finance from project_finances pf where pf."constructionSiteId" = p_project_id limit 1;
  select jsonb_build_object('total_tasks', count(*), 'completed_tasks', count(*) filter (where pt.progress >= 100), 'in_progress_tasks', count(*) filter (where pt.progress > 0 and pt.progress < 100), 'not_started_tasks', count(*) filter (where pt.progress = 0 or pt.progress is null), 'avg_progress', round(coalesce(avg(pt.progress), 0), 1))
  into v_task_summary from project_tasks pt where pt.construction_site_id = p_project_id;
  return jsonb_build_object('site', v_site, 'finance', coalesce(v_finance, '{}'::jsonb), 'tasks', coalesce(v_task_summary, '{}'::jsonb));
end; $$;


