CREATE OR REPLACE FUNCTION "public"."ai_tool_purchase_order_summary"("p_project_id" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_total bigint;
  v_total_val numeric;
  v_breakdown jsonb;
  v_recent jsonb;
begin
  select count(*), coalesce(sum(po.total_amount), 0) into v_total, v_total_val
  from purchase_orders po
  where (p_project_id is null or po.construction_site_id = p_project_id)
    and (p_status is null or po.status = p_status);

  select coalesce(jsonb_object_agg(status, cnt), '{}'::jsonb) into v_breakdown
  from (select po.status, count(*) as cnt from purchase_orders po
    where (p_project_id is null or po.construction_site_id = p_project_id)
      and (p_status is null or po.status = p_status)
    group by po.status) sb;

  select coalesce(jsonb_agg(
    jsonb_build_object('id', po3.id, 'code', po3.code, 'status', po3.status,
      'total_amount', coalesce(po3.total_amount, 0),
      'vendor', coalesce((select pv.name from project_vendors pv where pv.id = po3.vendor_id limit 1), 'N/A'),
      'created_at', po3.created_at)
    order by po3.created_at desc
  ), '[]'::jsonb) into v_recent
  from (select * from purchase_orders po3
    where (p_project_id is null or po3.construction_site_id = p_project_id)
      and (p_status is null or po3.status = p_status)
    order by po3.created_at desc limit 20) po3;

  return jsonb_build_object('total', v_total, 'total_value', v_total_val, 'status_breakdown', v_breakdown, 'recent_orders', v_recent);
end;
$$;


