CREATE OR REPLACE FUNCTION "public"."apply_stock_change"("p_item_id" "text", "p_warehouse_id" "text", "p_delta" numeric) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_stock jsonb;
  v_current numeric;
  v_next numeric;
begin
  if public.current_app_user_id() is null then
    raise exception 'authentication required';
  end if;
  if nullif(p_warehouse_id, '') is null then
    raise exception 'warehouse id is required';
  end if;

  select coalesce(stock_by_warehouse, '{}'::jsonb)
    into v_stock
  from public.items
  where id = p_item_id
  for update;
  if not found then
    raise exception 'item not found: %', p_item_id;
  end if;

  v_current := coalesce((v_stock ->> p_warehouse_id)::numeric, 0);
  v_next := v_current + coalesce(p_delta, 0);
  if v_next < -0.000000001 then
    raise exception 'insufficient stock for item %, warehouse %: available %, delta %',
      p_item_id, p_warehouse_id, v_current, p_delta;
  end if;
  if abs(v_next) < 0.000000001 then
    v_next := 0;
  end if;

  v_stock := jsonb_set(v_stock, array[p_warehouse_id], to_jsonb(v_next), true);

  update public.items
  set stock_by_warehouse = v_stock
  where id = p_item_id;

  return v_stock;
end;
$$;


ALTER FUNCTION "public"."apply_stock_change"("p_item_id" "text", "p_warehouse_id" "text", "p_delta" numeric) OWNER TO "postgres";


