CREATE OR REPLACE FUNCTION "public"."cancel_material_issue_order"("p_order_id" "uuid", "p_reason" "text") RETURNS "public"."material_issue_orders"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_actor uuid := public.current_app_user_id();
  v_order public.material_issue_orders%rowtype;
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  if coalesce(trim(p_reason), '') = '' then raise exception 'Bắt buộc nhập lý do huỷ.'; end if;
  select * into v_order from public.material_issue_orders where id = p_order_id for update;
  if not found then raise exception 'Không tìm thấy phiếu xuất cấp.'; end if;
  if v_order.status not in ('draft', 'submitted', 'wms_pending') then
    raise exception 'Phiếu đã phát sinh xuất kho hoặc quyết toán, không thể huỷ trực tiếp.';
  end if;
  if not (public.is_admin() or public.is_module_admin('WMS') or v_order.created_by = v_actor) then
    raise exception 'Bạn không có quyền huỷ phiếu này.';
  end if;
  if v_order.transaction_id is not null then
    update public.transactions
    set status = 'CANCELLED', approver_id = v_actor
    where id = v_order.transaction_id and status = 'PENDING';
  end if;
  update public.material_issue_orders
  set status = 'cancelled',
      cancelled_by = v_actor,
      cancelled_at = now(),
      cancel_reason = trim(p_reason)
  where id = p_order_id
  returning * into v_order;
  return v_order;
end;
$$;


ALTER FUNCTION "public"."cancel_material_issue_order"("p_order_id" "uuid", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."chat_v2_create_group_conversation"("p_name" "text", "p_member_ids" "uuid"[]) RETURNS "uuid"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
declare
  v_actor uuid := public.current_app_user_id();
  v_member_ids uuid[];
  v_member_id uuid;
  v_conversation_id uuid;
  v_group_name text;
begin
  if v_actor is null then
    raise exception 'Không xác định được người dùng hiện tại.';
  end if;

  select array_agg(distinct member_id)
  into v_member_ids
  from unnest(coalesce(p_member_ids, array[]::uuid[]) || array[v_actor]) as member_id
  where member_id is not null;

  if coalesce(array_length(v_member_ids, 1), 0) < 2 then
    raise exception 'Nhóm cần ít nhất 2 thành viên.';
  end if;

  foreach v_member_id in array v_member_ids
  loop
    if not app_private.chat_v2_has_app_access(v_member_id) then
      raise exception 'Thành viên không tồn tại, đã bị khóa hoặc chưa có quyền chat.';
    end if;
  end loop;

  v_group_name := nullif(trim(coalesce(p_name, '')), '');
  if v_group_name is null then
    v_group_name := 'Nhóm ' || array_length(v_member_ids, 1)::text || ' thành viên';
  end if;

  insert into public.chat_v2_conversations(type, name, created_by)
  values ('group', v_group_name, v_actor)
  returning id into v_conversation_id;

  insert into public.chat_v2_participants(conversation_id, user_id, role, last_read_at)
  values (v_conversation_id, v_actor, 'owner', now())
  on conflict (conversation_id, user_id) do nothing;

  foreach v_member_id in array v_member_ids
  loop
    if v_member_id <> v_actor then
      insert into public.chat_v2_participants(conversation_id, user_id, role, last_read_at)
      values (v_conversation_id, v_member_id, 'member', null)
      on conflict (conversation_id, user_id) do nothing;
    end if;
  end loop;

  return v_conversation_id;
end;
$$;


ALTER FUNCTION "public"."chat_v2_create_group_conversation"("p_name" "text", "p_member_ids" "uuid"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."chat_v2_get_or_create_direct_conversation"("p_target_user_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
declare
  v_actor uuid := public.current_app_user_id();
  v_low uuid;
  v_high uuid;
  v_conversation_id uuid;
begin
  if v_actor is null then
    raise exception 'Không xác định được người dùng hiện tại.';
  end if;
  if p_target_user_id is null or p_target_user_id = v_actor then
    raise exception 'Người nhận không hợp lệ.';
  end if;
  if not exists (select 1 from public.users u where u.id = p_target_user_id and coalesce(u.is_active, true)) then
    raise exception 'Người nhận không tồn tại hoặc đã bị khóa.';
  end if;

  v_low := least(v_actor, p_target_user_id);
  v_high := greatest(v_actor, p_target_user_id);

  perform pg_advisory_xact_lock(hashtext(v_low::text || ':' || v_high::text));

  select dp.conversation_id
  into v_conversation_id
  from public.chat_v2_direct_pairs dp
  where dp.user_low_id = v_low
    and dp.user_high_id = v_high;

  if v_conversation_id is not null then
    return v_conversation_id;
  end if;

  insert into public.chat_v2_conversations(type, created_by, metadata)
  values (
    'direct',
    v_actor,
    jsonb_build_object('directUserIds', jsonb_build_array(v_low, v_high))
  )
  returning id into v_conversation_id;

  insert into public.chat_v2_participants(conversation_id, user_id, role, last_read_at)
  values (v_conversation_id, v_actor, 'owner', now())
  on conflict (conversation_id, user_id) do nothing;

  insert into public.chat_v2_participants(conversation_id, user_id, role, last_read_at)
  values (v_conversation_id, p_target_user_id, 'member', null)
  on conflict (conversation_id, user_id) do nothing;

  insert into public.chat_v2_direct_pairs(user_low_id, user_high_id, conversation_id)
  values (v_low, v_high, v_conversation_id);

  return v_conversation_id;
end;
$$;


ALTER FUNCTION "public"."chat_v2_get_or_create_direct_conversation"("p_target_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."complete_user_account_lifecycle"("p_actor_user_id" "uuid", "p_operation_id" "uuid", "p_auth_result" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_operation app_private.user_account_operations%rowtype;
  v_final_revocation_summary jsonb := '{}'::jsonb;
begin
  perform app_private.assert_legacy_system_admin(p_actor_user_id);

  select * into v_operation
  from app_private.user_account_operations
  where id = p_operation_id
  for update;

  if v_operation.id is null then
    raise exception 'Account lifecycle operation does not exist'
      using errcode = 'P0002';
  end if;
  if v_operation.status = 'COMPLETED' then
    return app_private.account_operation_response(v_operation);
  end if;
  if v_operation.status not in ('DB_APPLIED', 'AUTH_RETRY') then
    raise exception 'Account lifecycle operation is not ready for completion'
      using errcode = '55000';
  end if;

  -- Close anything created between prepare and Auth completion before activation.
  v_final_revocation_summary := app_private.revoke_user_access_sources(
    v_operation.target_user_id,
    p_actor_user_id,
    v_operation.id,
    'account_lifecycle_final_sweep: ' || v_operation.reason
  );

  perform set_config('app.account_lifecycle_command', 'on', true);

  if v_operation.action = 'REACTIVATE' then
    update public.users
    set account_status = 'ACTIVE',
        is_active = true,
        role = 'EMPLOYEE',
        assigned_warehouse_id = null,
        allowed_modules = '{}'::text[],
        admin_modules = '{}'::text[],
        allowed_sub_modules = '{}'::jsonb,
        admin_sub_modules = '{}'::jsonb,
        reactivated_at = now(),
        reactivated_by = p_actor_user_id,
        reactivation_reason = v_operation.reason,
        account_operation_status = 'IDLE',
        account_operation_action = null,
        updated_at = now()
    where id = v_operation.target_user_id;
  else
    update public.users
    set account_operation_status = 'IDLE',
        account_operation_action = null,
        updated_at = now()
    where id = v_operation.target_user_id;
  end if;

  update app_private.user_account_operations
  set status = 'COMPLETED',
      auth_result = coalesce(p_auth_result, '{}'::jsonb),
      last_error = null,
      updated_at = now(),
      completed_at = now()
  where id = v_operation.id
  returning * into v_operation;

  insert into public.permission_audit_events (
    actor_user_id,
    target_user_id,
    event_type,
    before_grants,
    after_grants,
    metadata
  )
  values (
    p_actor_user_id,
    v_operation.target_user_id,
    case
      when v_operation.action = 'REACTIVATE' then 'account_reactivated_zero_rights'
      else 'account_disabled_auth_completed'
    end,
    '[]'::jsonb,
    '[]'::jsonb,
    jsonb_build_object(
      'operationId', v_operation.id,
      'reason', v_operation.reason,
      'authResult', coalesce(p_auth_result, '{}'::jsonb),
      'finalRevocationSummary', v_final_revocation_summary
    )
  );

  return app_private.account_operation_response(v_operation);
end;
$$;


ALTER FUNCTION "public"."complete_user_account_lifecycle"("p_actor_user_id" "uuid", "p_operation_id" "uuid", "p_auth_result" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."confirm_material_issue_receipt"("p_order_id" "uuid", "p_lines" "jsonb", "p_note" "text" DEFAULT NULL::"text", "p_attachments" "jsonb" DEFAULT '[]'::"jsonb", "p_signature_url" "text" DEFAULT NULL::"text") RETURNS "public"."material_issue_orders"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_actor uuid := public.current_app_user_id();
  v_actor_name text;
  v_order public.material_issue_orders%rowtype;
  v_receipt_id uuid := gen_random_uuid();
  v_receipt_no text;
  v_line jsonb;
  v_issue_line public.material_issue_lines%rowtype;
  v_qty numeric;
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  select * into v_order from public.material_issue_orders where id = p_order_id for update;
  if not found then raise exception 'Không tìm thấy phiếu xuất cấp.'; end if;
  if v_order.status not in ('issued', 'partially_received', 'received', 'settling', 'partially_returned') then
    raise exception 'Chỉ xác nhận nhận hàng sau khi WMS đã xuất kho.';
  end if;
  if not app_private.material_issue_can_process(v_order.source_warehouse_id, v_order.created_by, v_order.responsible_user_id, v_order.recipient_type, v_order.recipient_id) then
    raise exception 'Bạn không có quyền xác nhận phiếu này.';
  end if;
  if jsonb_typeof(p_lines) <> 'array' or jsonb_array_length(p_lines) = 0 then
    raise exception 'Chưa có dòng xác nhận nhận hàng.';
  end if;

  select coalesce(u.name, u.username, u.email) into v_actor_name from public.users u where u.id = v_actor;
  v_receipt_no := 'MIR-' || to_char(now(), 'YYYYMMDD') || '-' || upper(substr(replace(v_receipt_id::text, '-', ''), 1, 6));

  insert into public.material_issue_receipts(
    id, issue_order_id, receipt_no, received_by, received_by_name, note, signature_url, attachments
  ) values (
    v_receipt_id, p_order_id, v_receipt_no, v_actor, v_actor_name,
    nullif(trim(coalesce(p_note, '')), ''), nullif(p_signature_url, ''), coalesce(p_attachments, '[]'::jsonb)
  );

  for v_line in select value from jsonb_array_elements(p_lines)
  loop
    v_qty := coalesce(nullif(v_line ->> 'receivedQty', '')::numeric, 0);
    if v_qty < 0 then raise exception 'Số lượng nhận không hợp lệ.'; end if;
    select * into v_issue_line from public.material_issue_lines where id = (v_line ->> 'issueLineId')::uuid and issue_order_id = p_order_id for update;
    if not found then raise exception 'Không tìm thấy dòng phiếu xuất cấp.'; end if;
    if v_issue_line.received_qty + v_qty > v_issue_line.issued_qty then
      raise exception 'Số lượng nhận vượt số lượng đã xuất.';
    end if;

    insert into public.material_issue_receipt_lines(
      receipt_id, issue_line_id, item_id, received_qty, variance_reason
    ) values (
      v_receipt_id, v_issue_line.id, v_issue_line.item_id, v_qty, nullif(trim(coalesce(v_line ->> 'varianceReason', '')), '')
    );

    update public.material_issue_lines
    set received_qty = received_qty + v_qty
    where id = v_issue_line.id;

    insert into public.material_party_ledger(
      issue_order_id, issue_line_id, source_document_type, source_document_id,
      ledger_type, project_id, construction_site_id, recipient_type, recipient_id,
      recipient_name, item_id, item_name_snapshot, unit, quantity_delta, reason,
      metadata, created_by
    ) values (
      p_order_id, v_issue_line.id, 'material_issue_receipt', v_receipt_id::text,
      'receive_confirm', v_order.project_id, v_order.construction_site_id, v_order.recipient_type, v_order.recipient_id,
      v_order.recipient_name, v_issue_line.item_id, v_issue_line.item_name_snapshot, v_issue_line.unit, 0,
      nullif(trim(coalesce(p_note, '')), ''), jsonb_build_object('receivedQty', v_qty), v_actor
    )
    on conflict do nothing;
  end loop;

  return app_private.material_issue_refresh_status(p_order_id);
end;
$$;


