CREATE OR REPLACE FUNCTION "public"."create_asset_with_initial_stock"("p_asset" "jsonb") RETURNS "public"."assets"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_asset public.assets%rowtype;
  v_stock_id text;
  v_qty integer;
  v_warehouse_id text := nullif(p_asset->>'warehouse_id', '');
begin
  if not public.is_module_admin('TS') then
    raise exception 'insufficient privilege to create asset';
  end if;

  v_qty := greatest(
    1,
    coalesce(nullif(p_asset->>'quantity', '')::integer, 1)
  );
  if coalesce(nullif(p_asset->>'asset_type', ''), 'single') <> 'batch' then
    v_qty := 1;
  end if;

  insert into public.assets (
    id, code, name, category_id, brand, model, serial_number, status,
    asset_type, quantity, unit, parent_id, child_index, is_bundle,
    managed_by_user_id, managing_dept_id, construction_site_id,
    supplier_id, contract_number, invoice_number, asset_origin,
    is_fixed_asset, is_leased, leased_from, lease_end_date,
    warranty_condition, warranty_provider, warranty_contact,
    original_value, purchase_date, depreciation_years, warranty_months,
    residual_value, warehouse_id, location_note, assigned_to_user_id,
    assigned_to_name, assigned_date, disposal_date, disposal_value,
    disposal_note, image_url, note, created_at, updated_at
  )
  values (
    p_asset->>'id',
    p_asset->>'code',
    p_asset->>'name',
    nullif(p_asset->>'category_id', ''),
    nullif(p_asset->>'brand', ''),
    nullif(p_asset->>'model', ''),
    nullif(p_asset->>'serial_number', ''),
    coalesce(nullif(p_asset->>'status', ''), 'AVAILABLE')::public.asset_status,
    coalesce(nullif(p_asset->>'asset_type', ''), 'single'),
    v_qty,
    nullif(p_asset->>'unit', ''),
    nullif(p_asset->>'parent_id', ''),
    nullif(p_asset->>'child_index', '')::integer,
    coalesce(nullif(p_asset->>'is_bundle', '')::boolean, false),
    nullif(p_asset->>'managed_by_user_id', ''),
    nullif(p_asset->>'managing_dept_id', ''),
    nullif(p_asset->>'construction_site_id', ''),
    nullif(p_asset->>'supplier_id', ''),
    nullif(p_asset->>'contract_number', ''),
    nullif(p_asset->>'invoice_number', ''),
    coalesce(nullif(p_asset->>'asset_origin', ''), 'purchase'),
    coalesce(nullif(p_asset->>'is_fixed_asset', '')::boolean, true),
    coalesce(nullif(p_asset->>'is_leased', '')::boolean, false),
    nullif(p_asset->>'leased_from', ''),
    nullif(p_asset->>'lease_end_date', ''),
    nullif(p_asset->>'warranty_condition', ''),
    nullif(p_asset->>'warranty_provider', ''),
    nullif(p_asset->>'warranty_contact', ''),
    coalesce(nullif(p_asset->>'original_value', '')::numeric, 0),
    coalesce(nullif(p_asset->>'purchase_date', ''), now()::date::text),
    coalesce(nullif(p_asset->>'depreciation_years', '')::integer, 5),
    coalesce(nullif(p_asset->>'warranty_months', '')::integer, 0),
    coalesce(nullif(p_asset->>'residual_value', '')::numeric, 0),
    v_warehouse_id,
    nullif(p_asset->>'location_note', ''),
    nullif(p_asset->>'assigned_to_user_id', ''),
    nullif(p_asset->>'assigned_to_name', ''),
    nullif(p_asset->>'assigned_date', ''),
    nullif(p_asset->>'disposal_date', ''),
    nullif(p_asset->>'disposal_value', '')::numeric,
    nullif(p_asset->>'disposal_note', ''),
    nullif(p_asset->>'image_url', ''),
    nullif(p_asset->>'note', ''),
    coalesce(nullif(p_asset->>'created_at', '')::timestamp with time zone, now()),
    coalesce(nullif(p_asset->>'updated_at', '')::timestamp with time zone, now())
  )
  returning * into v_asset;

  if v_warehouse_id is not null then
    select id into v_stock_id
    from public.asset_location_stocks
    where asset_id = v_asset.id
      and warehouse_id is not distinct from v_warehouse_id
      and assigned_to_user_id is null
    limit 1
    for update;

    if v_stock_id is null then
      insert into public.asset_location_stocks (
        asset_id, warehouse_id, qty, note, updated_at
      )
      values (
        v_asset.id, v_warehouse_id, v_qty,
        nullif(p_asset->>'location_note', ''), now()
      );
    else
      update public.asset_location_stocks
      set qty = qty + v_qty,
          note = coalesce(nullif(p_asset->>'location_note', ''), note),
          updated_at = now()
      where id = v_stock_id;
    end if;
  end if;

  return v_asset;
end;
$$;


ALTER FUNCTION "public"."create_asset_with_initial_stock"("p_asset" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_material_issue_order"("p_project_id" "text", "p_construction_site_id" "text", "p_source_warehouse_id" "text", "p_recipient_type" "text", "p_recipient_id" "text", "p_recipient_name" "text", "p_responsible_user_id" "uuid", "p_subcontractor_contract_id" "text", "p_material_request_id" "text", "p_work_boq_item_id" "text", "p_needed_date" "date", "p_note" "text", "p_lines" "jsonb") RETURNS "public"."material_issue_orders"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_actor uuid := public.current_app_user_id();
  v_order public.material_issue_orders%rowtype;
  v_order_id uuid := gen_random_uuid();
  v_issue_no text;
  v_line jsonb;
  v_item public.items%rowtype;
  v_qty numeric;
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  if not (
    app_private.material_issue_can_manage_project(p_project_id, p_construction_site_id)
    or app_private.current_user_is_wms_keeper_for(p_source_warehouse_id)
  ) then
    raise exception 'Bạn không có quyền tạo phiếu xuất cấp cho dự án/công trường này.';
  end if;
  if coalesce(p_source_warehouse_id, '') = '' then raise exception 'Chưa chọn kho xuất.'; end if;
  if p_recipient_type not in ('employee', 'work_group', 'subcontractor', 'partner', 'manual') then
    raise exception 'Loại bên nhận không hợp lệ.';
  end if;
  if coalesce(trim(p_recipient_name), '') = '' then raise exception 'Chưa nhập tên bên nhận.'; end if;
  if jsonb_typeof(p_lines) <> 'array' or jsonb_array_length(p_lines) = 0 then
    raise exception 'Phiếu xuất cấp chưa có dòng vật tư.';
  end if;

  v_issue_no := 'MI-' || to_char(now(), 'YYYYMMDD') || '-' || upper(substr(replace(v_order_id::text, '-', ''), 1, 6));

  insert into public.material_issue_orders(
    id, issue_no, project_id, construction_site_id, source_warehouse_id,
    recipient_type, recipient_id, recipient_name, responsible_user_id,
    subcontractor_contract_id, material_request_id, work_boq_item_id,
    needed_date, status, note, created_by
  ) values (
    v_order_id, v_issue_no, nullif(p_project_id, ''), nullif(p_construction_site_id, ''), p_source_warehouse_id,
    p_recipient_type, nullif(p_recipient_id, ''), trim(p_recipient_name), p_responsible_user_id,
    nullif(p_subcontractor_contract_id, ''), nullif(p_material_request_id, ''), nullif(p_work_boq_item_id, ''),
    p_needed_date, 'draft', nullif(trim(coalesce(p_note, '')), ''), v_actor
  )
  returning * into v_order;

  for v_line in select value from jsonb_array_elements(p_lines)
  loop
    v_qty := coalesce(nullif(v_line ->> 'quantity', '')::numeric, 0);
    if coalesce(v_line ->> 'itemId', '') = '' or v_qty <= 0 then
      raise exception 'Dòng vật tư không hợp lệ.';
    end if;

    select * into v_item from public.items where id = v_line ->> 'itemId';
    if not found then raise exception 'Không tìm thấy vật tư %.', v_line ->> 'itemId'; end if;

    insert into public.material_issue_lines(
      issue_order_id, item_id, sku_snapshot, item_name_snapshot, unit,
      requested_qty, approved_qty, unit_price,
      material_budget_item_id, material_request_line_id, work_boq_item_id,
      subcontractor_contract_id, note
    ) values (
      v_order_id, v_item.id, v_item.sku, v_item.name, coalesce(nullif(v_line ->> 'unit', ''), v_item.unit),
      v_qty, v_qty, coalesce(nullif(v_line ->> 'unitPrice', '')::numeric, coalesce(v_item.price_in, 0)),
      nullif(v_line ->> 'materialBudgetItemId', ''),
      nullif(v_line ->> 'materialRequestLineId', ''),
      coalesce(nullif(v_line ->> 'workBoqItemId', ''), nullif(p_work_boq_item_id, '')),
      coalesce(nullif(v_line ->> 'subcontractorContractId', ''), nullif(p_subcontractor_contract_id, '')),
      nullif(trim(coalesce(v_line ->> 'note', '')), '')
    );
  end loop;

  return v_order;
end;
$$;


ALTER FUNCTION "public"."create_material_issue_order"("p_project_id" "text", "p_construction_site_id" "text", "p_source_warehouse_id" "text", "p_recipient_type" "text", "p_recipient_id" "text", "p_recipient_name" "text", "p_responsible_user_id" "uuid", "p_subcontractor_contract_id" "text", "p_material_request_id" "text", "p_work_boq_item_id" "text", "p_needed_date" "date", "p_note" "text", "p_lines" "jsonb") OWNER TO "postgres";


