CREATE OR REPLACE FUNCTION "public"."execute_ai_query"("query_text" "text") RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  result JSON;
  upper_query TEXT;
  clean_query TEXT;
BEGIN
  -- Strip trailing semicolons and whitespace
  clean_query := RTRIM(TRIM(query_text), ';');
  clean_query := TRIM(clean_query);

  -- Safety check: only allow SELECT and WITH (CTE)
  upper_query := UPPER(clean_query);
  IF NOT (upper_query LIKE 'SELECT%' OR upper_query LIKE 'WITH%') THEN
    RETURN json_build_object('error', 'Only SELECT queries are allowed');
  END IF;

  -- Block dangerous keywords using word-boundary regex
  IF upper_query ~ '\y(INSERT|UPDATE|DELETE|DROP|ALTER|CREATE|TRUNCATE|GRANT|REVOKE|EXEC|EXECUTE)\y' THEN
    RETURN json_build_object('error', 'Dangerous keywords detected');
  END IF;

  -- Block multiple statements (prevent SQL injection via semicolons)
  IF clean_query LIKE '%;%' THEN
    RETURN json_build_object('error', 'Multiple statements are not allowed');
  END IF;

  -- Execute and return as JSON
  EXECUTE 'SELECT json_agg(row_to_json(t)) FROM (' || clean_query || ') t' INTO result;

  -- Handle null result (no rows)
  IF result IS NULL THEN
    result := '[]'::json;
  END IF;

  RETURN result;
EXCEPTION
  WHEN OTHERS THEN
    RETURN json_build_object('error', SQLERRM);
END;
$$;


ALTER FUNCTION "public"."execute_ai_query"("query_text" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."execute_ai_readonly_query"("p_query" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $_$
declare
  v_sql text := trim(coalesce(p_query, ''));
  v_lower text;
  v_rows jsonb;
  v_row_count integer;
begin
  v_sql := regexp_replace(v_sql, ';\s*$', '');
  v_lower := lower(v_sql);

  if v_sql = '' or v_lower !~ '^\s*(select|with)\s' then
    raise exception 'AI query must be SELECT-only';
  end if;

  if v_sql like '%;%' then
    raise exception 'AI query must contain a single statement';
  end if;

  if v_sql ~ '(--|/\*)' then
    raise exception 'AI query comments are not allowed';
  end if;

  if v_lower ~ '(^|[^a-z_])(insert|update|delete|drop|alter|truncate|grant|revoke|create|replace|merge|call|copy|do|execute|notify|listen|vacuum|analyze|set|reset|refresh)([^a-z_]|$)' then
    raise exception 'AI query contains a blocked keyword';
  end if;

  if v_lower ~ '(^|[^a-z_])(auth|storage|vault|net|extensions|pg_catalog|information_schema)\s*\.' then
    raise exception 'AI query references a blocked schema';
  end if;

  perform set_config('statement_timeout', '5000', true);

  execute format(
    'select coalesce(jsonb_agg(to_jsonb(ai_limited)), ''[]''::jsonb)
       from (select * from (%s) ai_source limit 500) ai_limited',
    v_sql
  )
  into v_rows;

  v_row_count := coalesce(jsonb_array_length(v_rows), 0);
  return jsonb_build_object(
    'rows', v_rows,
    'rowCount', v_row_count,
    'limited', v_row_count >= 500
  );
end;
$_$;


ALTER FUNCTION "public"."execute_ai_readonly_query"("p_query" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."execute_readonly_query"("query_text" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  result jsonb;
BEGIN
  -- Only allow SELECT statements
  IF NOT (lower(trim(query_text)) LIKE 'select%' OR lower(trim(query_text)) LIKE 'with%') THEN
    RAISE EXCEPTION 'Only SELECT queries are allowed';
  END IF;

  -- Block dangerous keywords
  IF query_text ~* '\b(insert|update|delete|drop|alter|truncate|create|grant|revoke)\b' THEN
    RAISE EXCEPTION 'Write operations are not allowed';
  END IF;

  EXECUTE 'SELECT jsonb_agg(row_to_json(t)) FROM (' || query_text || ') t' INTO result;
  RETURN COALESCE(result, '[]'::jsonb);
END;
$$;


ALTER FUNCTION "public"."execute_readonly_query"("query_text" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fail_user_account_lifecycle"("p_actor_user_id" "uuid", "p_operation_id" "uuid", "p_error" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_operation app_private.user_account_operations%rowtype;
begin
  perform app_private.assert_legacy_system_admin(p_actor_user_id);

  select * into v_operation
  from app_private.user_account_operations
  where id = p_operation_id
  for update;

  if v_operation.id is null then
    raise exception 'Account lifecycle operation does not exist'
      using errcode = 'P0002';
  end if;

  if v_operation.status <> 'COMPLETED' then
    perform set_config('app.account_lifecycle_command', 'on', true);

    update app_private.user_account_operations
    set status = 'AUTH_RETRY',
        last_error = left(coalesce(p_error, 'Unknown Auth orchestration error'), 1000),
        updated_at = now()
    where id = p_operation_id
    returning * into v_operation;

    update public.users
    set account_operation_status = 'AUTH_RETRY',
        account_operation_action = v_operation.action,
        updated_at = now()
    where id = v_operation.target_user_id;

    insert into public.permission_audit_events (
      actor_user_id,
      target_user_id,
      event_type,
      before_grants,
      after_grants,
      metadata
    )
    values (
      p_actor_user_id,
      v_operation.target_user_id,
      'account_auth_retry_required',
      '[]'::jsonb,
      '[]'::jsonb,
      jsonb_build_object(
        'operationId', v_operation.id,
        'action', v_operation.action
      )
    );
  end if;

  return app_private.account_operation_response(v_operation);
end;
$$;


ALTER FUNCTION "public"."fail_user_account_lifecycle"("p_actor_user_id" "uuid", "p_operation_id" "uuid", "p_error" "text") OWNER TO "postgres";


