CREATE OR REPLACE FUNCTION "public"."get_inventory_ledger_report"("p_filters" "jsonb" DEFAULT '{}'::"jsonb", "p_limit" integer DEFAULT 500, "p_cursor" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_actor uuid := public.current_app_user_id();
  v_limit int := greatest(1, least(coalesce(p_limit, 500), 1000));
  v_warehouse_id text := nullif(coalesce(p_filters ->> 'warehouseId', p_filters ->> 'warehouse_id'), '');
  v_material_id text := nullif(coalesce(p_filters ->> 'materialId', p_filters ->> 'material_id'), '');
  v_project_id text := nullif(coalesce(p_filters ->> 'projectId', p_filters ->> 'project_id'), '');
  v_construction_site_id text := nullif(coalesce(p_filters ->> 'constructionSiteId', p_filters ->> 'construction_site_id'), '');
  v_transaction_type text := nullif(coalesce(p_filters ->> 'transactionType', p_filters ->> 'transaction_type'), '');
  v_date_from timestamptz := nullif(coalesce(p_filters ->> 'dateFrom', p_filters ->> 'date_from'), '')::timestamptz;
  v_date_to timestamptz := nullif(coalesce(p_filters ->> 'dateTo', p_filters ->> 'date_to'), '')::timestamptz;
  v_search text := lower(trim(coalesce(p_filters ->> 'search', '')));
  v_cursor_date text := nullif(split_part(coalesce(p_cursor, ''), '|', 1), '');
  v_cursor_id text := nullif(split_part(coalesce(p_cursor, ''), '|', 2), '');
  v_summary jsonb := '{}'::jsonb;
  v_stock_rows jsonb := '[]'::jsonb;
  v_warehouse_rows jsonb := '[]'::jsonb;
  v_entries jsonb := '[]'::jsonb;
  v_next_cursor text := null;
begin
  if v_actor is null then
    raise exception 'authentication required';
  end if;

  if v_warehouse_id = 'ALL' then v_warehouse_id := null; end if;
  if v_material_id = 'ALL' then v_material_id := null; end if;
  if v_transaction_type = 'all' then v_transaction_type := null; end if;
  if v_date_to is not null then
    v_date_to := date_trunc('day', v_date_to) + interval '1 day' - interval '1 millisecond';
  end if;

  with readable as (
    select e.*, i.sku, i.name as item_name, i.unit as item_unit, i.price_in, w.name as warehouse_name
    from public.inventory_ledger_entries e
    left join public.items i on i.id = e.material_id
    left join public.warehouses w on w.id = e.warehouse_id
    where app_private.can_read_inventory_scope(e.warehouse_id, e.created_by, e.approved_by)
      and (v_warehouse_id is null or e.warehouse_id = v_warehouse_id)
      and (v_material_id is null or e.material_id = v_material_id)
      and (v_project_id is null or e.project_id = v_project_id)
      and (v_construction_site_id is null or e.construction_site_id = v_construction_site_id)
      and (v_date_to is null or e.transaction_date <= v_date_to)
      and (
        v_search = ''
        or lower(
          coalesce(i.sku, '') || ' ' ||
          coalesce(i.name, '') || ' ' ||
          coalesce(e.document_code, '') || ' ' ||
          coalesce(e.source_code, '') || ' ' ||
          coalesce(e.description, '')
        ) like '%' || v_search || '%'
      )
  ),
  material_group as (
    select
      material_id,
      max(sku) as sku,
      max(item_name) as item_name,
      max(item_unit) as unit,
      max(price_in) as price_in,
      sum(case when v_date_from is not null and transaction_date < v_date_from then quantity_delta else 0 end) as opening,
      sum(case when (v_date_from is null or transaction_date >= v_date_from)
          and (v_transaction_type is null or transaction_type = v_transaction_type)
          and movement_direction = 'in' and transaction_type not in ('transfer_receipt', 'adjustment_in')
        then quantity_in else 0 end) as in_import,
      sum(case when (v_date_from is null or transaction_date >= v_date_from)
          and (v_transaction_type is null or transaction_type = v_transaction_type)
          and transaction_type = 'transfer_receipt'
        then quantity_in else 0 end) as in_transfer,
      sum(case when (v_date_from is null or transaction_date >= v_date_from)
          and (v_transaction_type is null or transaction_type = v_transaction_type)
          and transaction_type = 'adjustment_in'
        then quantity_in else 0 end) as in_adjustment,
      sum(case when (v_date_from is null or transaction_date >= v_date_from)
          and (v_transaction_type is null or transaction_type = v_transaction_type)
          and movement_direction = 'out' and transaction_type not in ('transfer_issue', 'loss_issue', 'adjustment_out')
        then quantity_out else 0 end) as out_export,
      sum(case when (v_date_from is null or transaction_date >= v_date_from)
          and (v_transaction_type is null or transaction_type = v_transaction_type)
          and transaction_type = 'transfer_issue'
        then quantity_out else 0 end) as out_transfer,
      sum(case when (v_date_from is null or transaction_date >= v_date_from)
          and (v_transaction_type is null or transaction_type = v_transaction_type)
          and transaction_type in ('loss_issue', 'adjustment_out')
        then quantity_out else 0 end) as out_liquidation
    from readable
    group by material_id
  ),
  stock as (
    select
      material_id as id,
      coalesce(max(sku), material_id) as sku,
      coalesce(max(item_name), material_id) as name,
      max(unit) as unit,
      coalesce(opening, 0) as opening,
      coalesce(in_import, 0) as in_import,
      coalesce(in_transfer, 0) as in_transfer,
      coalesce(in_adjustment, 0) as in_adjustment,
      coalesce(out_export, 0) as out_export,
      coalesce(out_transfer, 0) as out_transfer,
      coalesce(out_liquidation, 0) as out_liquidation,
      coalesce(in_import, 0) + coalesce(in_transfer, 0) + coalesce(in_adjustment, 0) as total_in,
      coalesce(out_export, 0) + coalesce(out_transfer, 0) + coalesce(out_liquidation, 0) as total_out,
      coalesce(opening, 0)
        + coalesce(in_import, 0) + coalesce(in_transfer, 0) + coalesce(in_adjustment, 0)
        - coalesce(out_export, 0) - coalesce(out_transfer, 0) - coalesce(out_liquidation, 0) as closing,
      (
        coalesce(opening, 0)
        + coalesce(in_import, 0) + coalesce(in_transfer, 0) + coalesce(in_adjustment, 0)
        - coalesce(out_export, 0) - coalesce(out_transfer, 0) - coalesce(out_liquidation, 0)
      ) * coalesce(max(price_in), 0) as value
    from material_group
    group by material_id, opening, in_import, in_transfer, in_adjustment, out_export, out_transfer, out_liquidation
  ),
  period_entries as (
    select *
    from readable
    where (v_date_from is null or transaction_date >= v_date_from)
      and (v_transaction_type is null or transaction_type = v_transaction_type)
  ),
  warehouse_group as (
    select
      warehouse_id,
      material_id,
      max(warehouse_name) as warehouse_name,
      max(sku) as sku,
      max(item_name) as material_name,
      max(item_unit) as unit,
      sum(quantity_in) as in_qty,
      sum(quantity_out) as out_qty,
      (array_agg(balance_after_qty order by transaction_date desc, id desc))[1] as balance_qty,
      max(transaction_date) as last_date
    from period_entries
    group by warehouse_id, material_id
  ),
  entry_page as (
    select *
    from period_entries
    where (
      v_cursor_date is null
      or transaction_date::text < v_cursor_date
      or (transaction_date::text = v_cursor_date and id::text < coalesce(v_cursor_id, ''))
    )
    order by transaction_date desc, id desc
    limit v_limit + 1
  ),
  entry_limited as (
    select *
    from entry_page
    order by transaction_date desc, id desc
    limit v_limit
  )
  select
    jsonb_build_object(
      'opening', coalesce(sum(opening), 0),
      'totalIn', coalesce(sum(total_in), 0),
      'totalOut', coalesce(sum(total_out), 0),
      'closing', coalesce(sum(closing), 0),
      'totalValue', coalesce(sum(value), 0)
    ),
    coalesce(jsonb_agg(to_jsonb(stock) order by stock.name), '[]'::jsonb)
  into v_summary, v_stock_rows
  from stock;

  with readable as (
    select e.*, i.sku, i.name as item_name, i.unit as item_unit, w.name as warehouse_name
    from public.inventory_ledger_entries e
    left join public.items i on i.id = e.material_id
    left join public.warehouses w on w.id = e.warehouse_id
    where app_private.can_read_inventory_scope(e.warehouse_id, e.created_by, e.approved_by)
      and (v_warehouse_id is null or e.warehouse_id = v_warehouse_id)
      and (v_material_id is null or e.material_id = v_material_id)
      and (v_project_id is null or e.project_id = v_project_id)
      and (v_construction_site_id is null or e.construction_site_id = v_construction_site_id)
      and (v_date_to is null or e.transaction_date <= v_date_to)
      and (v_date_from is null or e.transaction_date >= v_date_from)
      and (v_transaction_type is null or e.transaction_type = v_transaction_type)
      and (
        v_search = ''
        or lower(
          coalesce(i.sku, '') || ' ' ||
          coalesce(i.name, '') || ' ' ||
          coalesce(e.document_code, '') || ' ' ||
          coalesce(e.source_code, '') || ' ' ||
          coalesce(e.description, '')
        ) like '%' || v_search || '%'
      )
  ),
  warehouse_group as (
    select
      warehouse_id,
      material_id,
      max(warehouse_name) as warehouse_name,
      max(sku) as sku,
      max(item_name) as material_name,
      max(item_unit) as unit,
      sum(quantity_in) as in_qty,
      sum(quantity_out) as out_qty,
      (array_agg(balance_after_qty order by transaction_date desc, id desc))[1] as balance_qty,
      max(transaction_date) as last_date
    from readable
    group by warehouse_id, material_id
  )
  select coalesce(jsonb_agg(to_jsonb(warehouse_group) order by warehouse_name, material_name), '[]'::jsonb)
  into v_warehouse_rows
  from warehouse_group;

  with readable as (
    select e.*, i.sku, i.name as item_name, i.unit as item_unit, w.name as warehouse_name
    from public.inventory_ledger_entries e
    left join public.items i on i.id = e.material_id
    left join public.warehouses w on w.id = e.warehouse_id
    where app_private.can_read_inventory_scope(e.warehouse_id, e.created_by, e.approved_by)
      and (v_warehouse_id is null or e.warehouse_id = v_warehouse_id)
      and (v_material_id is null or e.material_id = v_material_id)
      and (v_project_id is null or e.project_id = v_project_id)
      and (v_construction_site_id is null or e.construction_site_id = v_construction_site_id)
      and (v_date_to is null or e.transaction_date <= v_date_to)
      and (v_date_from is null or e.transaction_date >= v_date_from)
      and (v_transaction_type is null or e.transaction_type = v_transaction_type)
      and (
        v_search = ''
        or lower(
          coalesce(i.sku, '') || ' ' ||
          coalesce(i.name, '') || ' ' ||
          coalesce(e.document_code, '') || ' ' ||
          coalesce(e.source_code, '') || ' ' ||
          coalesce(e.description, '')
        ) like '%' || v_search || '%'
      )
  ),
  entry_page as (
    select *
    from readable
    where (
      v_cursor_date is null
      or transaction_date::text < v_cursor_date
      or (transaction_date::text = v_cursor_date and id::text < coalesce(v_cursor_id, ''))
    )
    order by transaction_date desc, id desc
    limit v_limit + 1
  ),
  entry_limited as (
    select *
    from entry_page
    order by transaction_date desc, id desc
    limit v_limit
  )
  select
    coalesce(jsonb_agg(to_jsonb(entry_limited) order by transaction_date desc, id desc), '[]'::jsonb),
    case when (select count(*) from entry_page) > v_limit then (
      select e.transaction_date::text || '|' || e.id::text
      from entry_limited e
      order by e.transaction_date desc, e.id desc
      offset v_limit - 1
      limit 1
    ) else null end
  into v_entries, v_next_cursor
  from entry_limited;

  return jsonb_build_object(
    'filters', p_filters,
    'limit', v_limit,
    'cursor', p_cursor,
    'nextCursor', v_next_cursor,
    'summary', coalesce(v_summary, '{}'::jsonb),
    'stockRows', coalesce(v_stock_rows, '[]'::jsonb),
    'warehouseRows', coalesce(v_warehouse_rows, '[]'::jsonb),
    'entriesPage', coalesce(v_entries, '[]'::jsonb)
  );
end;
$$;


ALTER FUNCTION "public"."get_inventory_ledger_report"("p_filters" "jsonb", "p_limit" integer, "p_cursor" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_material_party_balance"("p_project_id" "text" DEFAULT NULL::"text", "p_construction_site_id" "text" DEFAULT NULL::"text", "p_recipient_type" "text" DEFAULT NULL::"text", "p_recipient_id" "text" DEFAULT NULL::"text") RETURNS TABLE("project_id" "text", "construction_site_id" "text", "recipient_type" "text", "recipient_id" "text", "recipient_name" "text", "item_id" "text", "item_name_snapshot" "text", "unit" "text", "balance_qty" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
  select
    l.project_id,
    l.construction_site_id,
    l.recipient_type,
    l.recipient_id,
    l.recipient_name,
    l.item_id,
    l.item_name_snapshot,
    l.unit,
    sum(l.quantity_delta) as balance_qty
  from public.material_party_ledger l
  where (p_project_id is null or l.project_id = p_project_id)
    and (p_construction_site_id is null or l.construction_site_id = p_construction_site_id)
    and (p_recipient_type is null or l.recipient_type = p_recipient_type)
    and (p_recipient_id is null or l.recipient_id = p_recipient_id)
    and app_private.material_issue_can_view(
      l.project_id, l.construction_site_id, null, null, null, l.recipient_type, l.recipient_id
    )
  group by l.project_id, l.construction_site_id, l.recipient_type, l.recipient_id,
    l.recipient_name, l.item_id, l.item_name_snapshot, l.unit
  having sum(l.quantity_delta) <> 0;
$$;


ALTER FUNCTION "public"."get_material_party_balance"("p_project_id" "text", "p_construction_site_id" "text", "p_recipient_type" "text", "p_recipient_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_material_request_workflow_board"("p_project_id" "text", "p_construction_site_id" "text" DEFAULT NULL::"text", "p_filters" "jsonb" DEFAULT '{}'::"jsonb", "p_limit" integer DEFAULT 150, "p_cursor" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_actor uuid := public.current_app_user_id();
  v_limit int := greatest(1, least(coalesce(p_limit, 150), 300));
  v_search text := lower(trim(coalesce(p_filters ->> 'search', '')));
  v_filter text := coalesce(nullif(p_filters ->> 'filter', ''), 'all');
  v_cursor_date text := nullif(split_part(coalesce(p_cursor, ''), '|', 1), '');
  v_cursor_id text := nullif(split_part(coalesce(p_cursor, ''), '|', 2), '');
  v_cards jsonb := '[]'::jsonb;
  v_next_cursor text := null;
begin
  if v_actor is null then
    raise exception 'authentication required';
  end if;
  if p_project_id is null or length(trim(p_project_id)) = 0 then
    raise exception 'project id is required';
  end if;

  with scoped as (
    select r.*
    from public.requests r
    left join public.workflow_subjects ws
      on ws.subject_type = 'material_request'
     and ws.subject_id = r.id
    left join public.users requester on requester.id = r.requester_id
    where coalesce(r.request_origin, 'wms') = 'project'
      and r.project_id = p_project_id
      and (p_construction_site_id is null or r.construction_site_id = p_construction_site_id)
      and (
        app_private.material_request_can_select(
          r.request_origin,
          r.project_id,
          r.requester_id,
          r.submitted_to_user_id,
          r.source_warehouse_id,
          r.site_warehouse_id
        )
        or (ws.id is not null and app_private.project_workflow_actor_can_select(ws.id))
      )
      and (
        v_cursor_date is null
        or r.created_date::text < v_cursor_date
        or (r.created_date::text = v_cursor_date and r.id < coalesce(v_cursor_id, ''))
      )
      and (
        v_search = ''
        or lower(
          coalesce(r.code, '') || ' ' ||
          coalesce(r.id, '') || ' ' ||
          coalesce(r.submitted_to_name, '') || ' ' ||
          coalesce(requester.name, '') || ' ' ||
          coalesce((
            select string_agg(coalesce(u.name, u.id::text), ' ')
            from public.workflow_step_assignments wsa
            join public.users u on u.id = wsa.assignee_user_id
            where wsa.workflow_subject_id = ws.id
              and wsa.status = 'PENDING'
          ), '')
        ) like '%' || v_search || '%'
      )
      and (
        v_filter = 'all'
        or (
          v_filter = 'mine'
          and (
            r.requester_id = v_actor
            or r.submitted_to_user_id = v_actor::text
            or exists (
              select 1
              from public.workflow_step_assignments wsa
              where wsa.workflow_subject_id = ws.id
                and wsa.assignee_user_id = v_actor
                and wsa.status = 'PENDING'
            )
          )
        )
        or (
          v_filter = 'overdue'
          and (
            r.workflow_step_due_at < now()
            or exists (
              select 1
              from public.workflow_step_assignments wsa
              where wsa.workflow_subject_id = ws.id
                and wsa.status = 'PENDING'
                and wsa.due_at < now()
            )
          )
        )
        or (
          v_filter = 'returned'
          and (ws.status = 'RETURNED' or r.workflow_step = 'returned_to_creator')
        )
        or (
          v_filter = 'watching'
          and exists (
            select 1
            from public.workflow_participants wp
            where wp.workflow_subject_id = ws.id
              and wp.user_id = v_actor
              and wp.role = 'WATCHER'
              and coalesce(wp.is_active, true)
          )
        )
      )
    order by r.created_date desc, r.id desc
    limit v_limit + 1
  ),
  page_rows as (
    select *
    from scoped
    order by created_date desc, id desc
    limit v_limit
  ),
  cards as (
    select jsonb_build_object(
      'id', r.id,
      'code', r.code,
      'status', r.status,
      'workflowStep', r.workflow_step,
      'workflowStepDueAt', r.workflow_step_due_at,
      'workflowStepStartedAt', r.workflow_step_started_at,
      'workflowStepSlaHours', r.workflow_step_sla_hours,
      'projectId', r.project_id,
      'constructionSiteId', r.construction_site_id,
      'requesterId', r.requester_id,
      'requesterName', requester.name,
      'submittedToUserId', r.submitted_to_user_id,
      'submittedToName', r.submitted_to_name,
      'createdDate', r.created_date,
      'expectedDate', r.expected_date,
      'itemCount', coalesce(jsonb_array_length(coalesce(r.items::jsonb, '[]'::jsonb)), 0),
      'itemPreview', coalesce((
        select jsonb_agg(item.value order by item.ordinality)
        from jsonb_array_elements(coalesce(r.items::jsonb, '[]'::jsonb)) with ordinality as item(value, ordinality)
        where item.ordinality <= 5
      ), '[]'::jsonb),
      'subject', case when ws.id is null then null else jsonb_build_object(
        'id', ws.id,
        'workflowInstanceId', ws.workflow_instance_id,
        'workflowTemplateId', ws.workflow_template_id,
        'templateVersionId', ws.template_version_id,
        'subjectType', ws.subject_type,
        'subjectId', ws.subject_id,
        'projectId', ws.project_id,
        'constructionSiteId', ws.construction_site_id,
        'status', ws.status,
        'currentNodeId', ws.current_node_id,
        'currentInstanceNodeId', ws.current_instance_node_id,
        'currentAssigneeUserId', ws.current_assignee_user_id,
        'currentAssigneeUserIds', coalesce(ws.current_assignee_user_ids, '{}'::uuid[]),
        'currentNodeLabel', coalesce(win.label, wn.label),
        'currentNodeType', coalesce(win.type::text, wn.type::text),
        'createdBy', ws.created_by,
        'updatedAt', ws.updated_at
      ) end,
      'currentRuntimeNode', case when win.id is null then null else jsonb_build_object(
        'id', win.id,
        'workflowInstanceId', win.workflow_instance_id,
        'templateVersionId', win.template_version_id,
        'templateNodeId', win.template_node_id,
        'label', win.label,
        'type', win.type::text,
        'config', coalesce(win.config, '{}'::jsonb),
        'positionX', win.position_x,
        'positionY', win.position_y,
        'createdAt', win.created_at
      ) end,
      'currentAssignees', coalesce(assignee_pool.assignees, '[]'::jsonb),
      'slaState', case
        when coalesce(min_pending.due_at, r.workflow_step_due_at) is null then 'none'
        when coalesce(min_pending.due_at, r.workflow_step_due_at) < now() then 'overdue'
        when min_pending.assigned_at is not null
          and now() >= min_pending.assigned_at + ((min_pending.due_at - min_pending.assigned_at) * 0.75) then 'urgent'
        when r.workflow_step_started_at is not null and r.workflow_step_due_at is not null
          and now() >= r.workflow_step_started_at + ((r.workflow_step_due_at - r.workflow_step_started_at) * 0.75) then 'urgent'
        else 'normal'
      end,
      'fulfillmentSummary', jsonb_build_object(
        'batchCount', coalesce(ff.batch_count, 0),
        'activeBatchCount', coalesce(ff.active_batch_count, 0),
        'committedQty', coalesce(ff.committed_qty, 0),
        'issuedQty', coalesce(ff.issued_qty, 0),
        'receivedQty', coalesce(ff.received_qty, 0),
        'remainingToReceive', greatest(coalesce(ff.committed_qty, 0) - coalesce(ff.received_qty, 0), 0)
      ),
      'eventPreview', coalesce(events.preview, '[]'::jsonb),
      'downstream', jsonb_build_object(
        'activeCount', coalesce(deps.active_count, 0),
        'totalCount', coalesce(deps.total_count, 0)
      )
    ) as card
    from page_rows r
    left join public.users requester on requester.id = r.requester_id
    left join public.workflow_subjects ws
      on ws.subject_type = 'material_request'
     and ws.subject_id = r.id
    left join public.workflow_instance_nodes win on win.id = ws.current_instance_node_id
    left join public.workflow_nodes wn on wn.id = ws.current_node_id
    left join lateral (
      select jsonb_agg(jsonb_build_object('id', au.id, 'name', au.name) order by au.name) as assignees
      from unnest(
        app_private.project_workflow_distinct_uuid_array(
          coalesce(ws.current_assignee_user_ids, '{}'::uuid[])
          || case when ws.current_assignee_user_id is null then '{}'::uuid[] else array[ws.current_assignee_user_id] end
        )
      ) assignee_id
      left join public.users au on au.id = assignee_id
    ) assignee_pool on true
    left join lateral (
      select min(wsa.assigned_at) as assigned_at, min(wsa.due_at) as due_at
      from public.workflow_step_assignments wsa
      where wsa.workflow_subject_id = ws.id
        and wsa.status = 'PENDING'
    ) min_pending on true
    left join lateral (
      select
        count(distinct b.id) as batch_count,
        count(distinct b.id) filter (where b.status not in ('draft', 'cancelled')) as active_batch_count,
        sum(l.committed_qty_snapshot) as committed_qty,
        sum(l.issued_qty) as issued_qty,
        sum(l.received_qty) as received_qty
      from public.material_request_fulfillment_batches b
      left join public.material_request_fulfillment_lines l on l.batch_id = b.id
      where b.material_request_id = r.id
    ) ff on true
    left join lateral (
      select jsonb_agg(jsonb_build_object(
        'id', e.id,
        'action', e.action,
        'actorUserId', e.actor_user_id,
        'targetUserId', e.target_user_id,
        'note', e.note,
        'createdAt', e.created_at
      ) order by e.created_at desc) as preview
      from (
        select *
        from public.material_request_events mre
        where mre.request_id = r.id
        order by mre.created_at desc, mre.id desc
        limit 3
      ) e
    ) events on true
    left join lateral (
      select
        count(*) as total_count,
        count(*) filter (where pdl.status = 'active') as active_count
      from public.project_document_links pdl
      where pdl.source_type = 'material_request'
        and pdl.source_id = r.id
        and pdl.relation_type = 'downstream'
    ) deps on true
  )
  select coalesce(jsonb_agg(card order by (card ->> 'createdDate') desc nulls last, card ->> 'id' desc), '[]'::jsonb)
  into v_cards
  from cards;

  if jsonb_array_length(v_cards) >= v_limit then
    select (card ->> 'createdDate') || '|' || (card ->> 'id')
    into v_next_cursor
    from jsonb_array_elements(v_cards) with ordinality as item(card, ordinality)
    order by item.ordinality desc
    limit 1;
  end if;

  return jsonb_build_object(
    'projectId', p_project_id,
    'constructionSiteId', p_construction_site_id,
    'filter', v_filter,
    'search', v_search,
    'limit', v_limit,
    'cursor', p_cursor,
    'nextCursor', v_next_cursor,
    'cards', v_cards
  );
end;
$$;


ALTER FUNCTION "public"."get_material_request_workflow_board"("p_project_id" "text", "p_construction_site_id" "text", "p_filters" "jsonb", "p_limit" integer, "p_cursor" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_next_employee_code"() RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  next_val INT;
BEGIN
  next_val := nextval('employee_code_seq');
  RETURN 'TT' || LPAD(next_val::TEXT, 3, '0');
END;
$$;


ALTER FUNCTION "public"."get_next_employee_code"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_permission_health_summary"() RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO ''
    AS $_$
declare
  v_broad_policies jsonb := '[]'::jsonb;
  v_anon_crud jsonb := '[]'::jsonb;
  v_sensitive_without_rls jsonb := '[]'::jsonb;
  v_non_namespaced_actions jsonb := '[]'::jsonb;
  v_legacy_admin_consumers jsonb := '[]'::jsonb;
  v_tables_with_legacy_columns jsonb := '[]'::jsonb;
  v_projects_without_scoped_grants jsonb := '[]'::jsonb;
  v_warehouses_without_scoped_grants jsonb := '[]'::jsonb;
  v_status text := 'ok';
begin
  if not app_private.can_manage_permissions() then
    raise exception 'Not allowed to view permission health'
      using errcode = '42501';
  end if;

  select coalesce(jsonb_agg(
    jsonb_build_object(
      'schema', p.schemaname,
      'table', p.tablename,
      'policy', p.policyname,
      'command', p.cmd,
      'qual', p.qual,
      'withCheck', p.with_check,
      'severity', 'high'
    )
    order by p.schemaname, p.tablename, p.policyname
  ), '[]'::jsonb)
  into v_broad_policies
  from pg_policies p
  where p.schemaname = 'public'
    and p.tablename <> all(array[
      'app_release_notices',
      'permission_applications',
      'permission_modules',
      'permission_actions'
    ])
    and (
      lower(trim(coalesce(p.qual, ''))) in ('true', '(true)')
      or lower(trim(coalesce(p.with_check, ''))) in ('true', '(true)')
    );

  select coalesce(jsonb_agg(
    jsonb_build_object(
      'schema', g.table_schema,
      'table', g.table_name,
      'privilege', g.privilege_type,
      'severity', 'critical'
    )
    order by g.table_schema, g.table_name, g.privilege_type
  ), '[]'::jsonb)
  into v_anon_crud
  from information_schema.role_table_grants g
  where g.table_schema = 'public'
    and g.grantee = 'anon'
    and g.privilege_type in ('INSERT', 'UPDATE', 'DELETE');

  select coalesce(jsonb_agg(
    jsonb_build_object(
      'schema', n.nspname,
      'table', c.relname,
      'severity', 'critical'
    )
    order by n.nspname, c.relname
  ), '[]'::jsonb)
  into v_sensitive_without_rls
  from pg_class c
  join pg_namespace n on n.oid = c.relnamespace
  where n.nspname = 'public'
    and c.relkind in ('r', 'p')
    and not c.relrowsecurity
    and c.relname <> all(array[
      'schema_migrations',
      'spatial_ref_sys'
    ])
    and (
      c.relname ~ '(user|permission|employee|payroll|attendance|transaction|request|asset|contract|payment|expense|workflow|warehouse)'
    );

  select coalesce(jsonb_agg(
    jsonb_build_object(
      'permissionCode', pa.permission_code,
      'moduleCode', pa.module_code,
      'severity', 'medium'
    )
    order by pa.permission_code
  ), '[]'::jsonb)
  into v_non_namespaced_actions
  from public.permission_actions pa
  where coalesce(pa.is_active, true)
    and (
      pa.permission_code = any(array['view','edit','delete','approve','verify','confirm','submit','manage'])
      or pa.permission_code !~ '^[a-z][a-z0-9_]*(\.[a-z0-9_]+)+$'
    );

  select coalesce(jsonb_agg(
    jsonb_build_object(
      'schema', n.nspname,
      'function', p.proname,
      'identityArguments', pg_get_function_identity_arguments(p.oid),
      'severity', 'medium'
    )
    order by n.nspname, p.proname, pg_get_function_identity_arguments(p.oid)
  ), '[]'::jsonb)
  into v_legacy_admin_consumers
  from pg_proc p
  join pg_namespace n on n.oid = p.pronamespace
  where n.nspname in ('public', 'app_private')
    and p.prokind in ('f', 'p')
    and p.proname <> 'is_module_admin'
    and pg_get_functiondef(p.oid) ilike '%is_module_admin%';

  select coalesce(jsonb_agg(
    jsonb_build_object(
      'schema', c.table_schema,
      'table', c.table_name,
      'columns', c.columns,
      'severity', 'info'
    )
    order by c.table_schema, c.table_name
  ), '[]'::jsonb)
  into v_tables_with_legacy_columns
  from (
    select
      table_schema,
      table_name,
      jsonb_agg(column_name order by column_name) as columns
    from information_schema.columns
    where table_schema = 'public'
      and column_name in ('allowed_modules','admin_modules','allowed_sub_modules','admin_sub_modules')
    group by table_schema, table_name
  ) c;

  if to_regclass('public.projects') is not null then
    execute $q$
      select coalesce(jsonb_agg(
        jsonb_build_object('projectId', p.id, 'severity', 'low')
        order by p.id
      ), '[]'::jsonb)
      from (
        select p.id
        from public.projects p
        where not exists (
          select 1
          from public.user_permission_grants g
          where g.scope_type = 'project'
            and g.scope_id = p.id::text
            and g.permission_code like 'project.%'
            and coalesce(g.is_active, false)
            and (g.expires_at is null or g.expires_at > now())
        )
        order by p.id
        limit 50
      ) p
    $q$
    into v_projects_without_scoped_grants;
  end if;

  if to_regclass('public.warehouses') is not null then
    execute $q$
      select coalesce(jsonb_agg(
        jsonb_build_object('warehouseId', w.id, 'severity', 'low')
        order by w.id
      ), '[]'::jsonb)
      from (
        select w.id
        from public.warehouses w
        where not exists (
          select 1
          from public.user_permission_grants g
          where g.scope_type = 'warehouse'
            and g.scope_id = w.id::text
            and coalesce(g.is_active, false)
            and (g.expires_at is null or g.expires_at > now())
        )
        order by w.id
        limit 50
      ) w
    $q$
    into v_warehouses_without_scoped_grants;
  end if;

  if jsonb_array_length(v_anon_crud) > 0 or jsonb_array_length(v_sensitive_without_rls) > 0 then
    v_status := 'critical';
  elsif jsonb_array_length(v_broad_policies) > 0
    or jsonb_array_length(v_non_namespaced_actions) > 0
    or jsonb_array_length(v_legacy_admin_consumers) > 0 then
    v_status := 'warning';
  end if;

  return jsonb_build_object(
    'generatedAt', now(),
    'status', v_status,
    'legacyProjectionEnabled', app_private.permission_hardening_flag('legacy_projection_enabled'),
    'legacyFallbackDisabled', app_private.permission_hardening_flag('legacy_fallback_disabled'),
    'checks', jsonb_build_object(
      'unmappedRoutes', '[]'::jsonb,
      'broadPolicies', v_broad_policies,
      'anonCrudGrants', v_anon_crud,
      'sensitiveTablesWithoutRls', v_sensitive_without_rls,
      'nonNamespacedPermissionActions', v_non_namespaced_actions,
      'legacyAdminFunctionConsumers', v_legacy_admin_consumers,
      'legacyProjectionColumns', v_tables_with_legacy_columns,
      'projectsWithoutScopedGrants', v_projects_without_scoped_grants,
      'warehousesWithoutScopedGrants', v_warehouses_without_scoped_grants,
      'departmentsWithoutScopedGrants', '[]'::jsonb
    )
  );
end;
$_$;


ALTER FUNCTION "public"."get_permission_health_summary"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_project_material_request_board"("p_project_id" "text", "p_construction_site_id" "text" DEFAULT NULL::"text", "p_filters" "jsonb" DEFAULT '{}'::"jsonb", "p_limit" integer DEFAULT 150, "p_cursor" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
begin
  return public.get_material_request_workflow_board(
    p_project_id,
    p_construction_site_id,
    p_filters,
    p_limit,
    p_cursor
  );
end;
$$;


ALTER FUNCTION "public"."get_project_material_request_board"("p_project_id" "text", "p_construction_site_id" "text", "p_filters" "jsonb", "p_limit" integer, "p_cursor" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_project_material_request_detail"("p_request_id" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_actor uuid := public.current_app_user_id();
  v_request public.requests%rowtype;
  v_subject public.workflow_subjects%rowtype;
  v_subject_json jsonb := null;
  v_runtime_context jsonb := null;
  v_assignments jsonb := '[]'::jsonb;
  v_batches jsonb := '[]'::jsonb;
  v_events jsonb := '[]'::jsonb;
begin
  if v_actor is null then
    raise exception 'authentication required';
  end if;

  select * into v_request
  from public.requests r
  where r.id = p_request_id;

  if not found then
    raise exception 'material request not found';
  end if;

  select * into v_subject
  from public.workflow_subjects ws
  where ws.subject_type = 'material_request'
    and ws.subject_id = v_request.id;

  if not (
    app_private.material_request_can_select(
      v_request.request_origin,
      v_request.project_id,
      v_request.requester_id,
      v_request.submitted_to_user_id,
      v_request.source_warehouse_id,
      v_request.site_warehouse_id
    )
    or (v_subject.id is not null and app_private.project_workflow_actor_can_select(v_subject.id))
  ) then
    raise exception 'user cannot view material request';
  end if;

  if v_subject.id is not null then
    select jsonb_strip_nulls(
      to_jsonb(v_subject)
      || jsonb_build_object(
        'current_node', to_jsonb(wn),
        'current_instance_node', to_jsonb(win),
        'workflow_instance', to_jsonb(wi),
        'participants', coalesce(participants.rows, '[]'::jsonb)
      )
    )
    into v_subject_json
    from public.workflow_subjects ws
    left join public.workflow_nodes wn on wn.id = ws.current_node_id
    left join public.workflow_instance_nodes win on win.id = ws.current_instance_node_id
    left join public.workflow_instances wi on wi.id = ws.workflow_instance_id
    left join lateral (
      select jsonb_agg(to_jsonb(wp) order by wp.created_at, wp.id) as rows
      from public.workflow_participants wp
      where wp.workflow_subject_id = ws.id
    ) participants on true
    where ws.id = v_subject.id;

    select coalesce(jsonb_agg(to_jsonb(wsa) order by wsa.assigned_at, wsa.id), '[]'::jsonb)
    into v_assignments
    from public.workflow_step_assignments wsa
    where wsa.workflow_subject_id = v_subject.id;

    select jsonb_build_object(
      'subjectId', v_subject.id,
      'workflowInstanceId', v_subject.workflow_instance_id,
      'nodes', coalesce(nodes.rows, '[]'::jsonb),
      'edges', coalesce(edges.rows, '[]'::jsonb)
    )
    into v_runtime_context
    from lateral (
      select jsonb_agg(to_jsonb(win) order by win.position_y, win.position_x, win.id) as rows
      from public.workflow_instance_nodes win
      where win.workflow_instance_id = v_subject.workflow_instance_id
    ) nodes
    cross join lateral (
      select jsonb_agg(to_jsonb(wie) order by wie.sort_order, wie.id) as rows
      from public.workflow_instance_edges wie
      where wie.workflow_instance_id = v_subject.workflow_instance_id
    ) edges;
  end if;

  select coalesce(jsonb_agg(
    to_jsonb(b) || jsonb_build_object('lines', coalesce(lines.rows, '[]'::jsonb))
    order by b.batch_date desc, b.id desc
  ), '[]'::jsonb)
  into v_batches
  from public.material_request_fulfillment_batches b
  left join lateral (
    select jsonb_agg(to_jsonb(l) order by l.created_at, l.id) as rows
    from public.material_request_fulfillment_lines l
    where l.batch_id = b.id
  ) lines on true
  where b.material_request_id = v_request.id;

  select coalesce(jsonb_agg(to_jsonb(e) order by e.created_at desc, e.id desc), '[]'::jsonb)
  into v_events
  from (
    select *
    from public.material_request_events mre
    where mre.request_id = v_request.id
    order by mre.created_at desc, mre.id desc
    limit 50
  ) e;

  return jsonb_build_object(
    'request', to_jsonb(v_request),
    'workflowSubject', v_subject_json,
    'runtimeContext', v_runtime_context,
    'assignments', v_assignments,
    'fulfillmentBatches', v_batches,
    'events', v_events
  );
end;
$$;


ALTER FUNCTION "public"."get_project_material_request_detail"("p_request_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_project_workflow_action_context"("p_subject_type" "text", "p_subject_id" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_actor uuid := public.current_app_user_id();
  v_subject public.workflow_subjects%rowtype;
  v_current_node jsonb := null;
  v_next_node jsonb := null;
  v_return_node jsonb := null;
  v_pending_assignee_ids uuid[] := '{}'::uuid[];
  v_is_pending_assignee boolean := false;
  v_is_workflow_admin boolean := false;
  v_is_watcher boolean := false;
  v_is_creator boolean := false;
  v_can_reassign boolean := false;
  v_can_rollback boolean := false;
  v_node_config jsonb := '{}'::jsonb;
  v_rollback jsonb := null;
begin
  if v_actor is null then
    raise exception 'authentication required';
  end if;

  select * into v_subject
  from public.workflow_subjects ws
  where ws.subject_type = p_subject_type
    and ws.subject_id = p_subject_id;

  if not found then
    raise exception 'workflow subject not found';
  end if;

  if not app_private.project_workflow_actor_can_select(v_subject.id) then
    raise exception 'user cannot view workflow action context';
  end if;

  select coalesce(array_agg(wsa.assignee_user_id order by wsa.assigned_at, wsa.assignee_user_id), '{}'::uuid[])
  into v_pending_assignee_ids
  from public.workflow_step_assignments wsa
  where wsa.workflow_subject_id = v_subject.id
    and wsa.workflow_instance_id = v_subject.workflow_instance_id
    and wsa.status = 'PENDING'
    and wsa.assignee_user_id is not null
    and (
      (v_subject.current_instance_node_id is not null and wsa.instance_node_id = v_subject.current_instance_node_id)
      or (v_subject.current_instance_node_id is null and wsa.node_id = v_subject.current_node_id)
    );

  v_is_pending_assignee := v_actor = any(coalesce(v_pending_assignee_ids, '{}'::uuid[]));

  select coalesce(exists (
    select 1
    from public.workflow_participants wp
    where wp.workflow_subject_id = v_subject.id
      and wp.user_id = v_actor
      and wp.role = 'ADMIN'
      and coalesce(wp.is_active, true)
  ), false)
  into v_is_workflow_admin;

  select coalesce(exists (
    select 1
    from public.workflow_participants wp
    where wp.workflow_subject_id = v_subject.id
      and wp.user_id = v_actor
      and wp.role = 'WATCHER'
      and coalesce(wp.is_active, true)
  ), false)
  into v_is_watcher;

  v_is_creator := v_subject.created_by = v_actor;

  select jsonb_build_object(
    'id', win.id,
    'templateNodeId', win.template_node_id,
    'label', win.label,
    'type', win.type::text,
    'config', coalesce(win.config, '{}'::jsonb)
  ),
  coalesce(win.config, '{}'::jsonb)
  into v_current_node, v_node_config
  from public.workflow_instance_nodes win
  where win.id = v_subject.current_instance_node_id;

  if v_current_node is null and v_subject.current_node_id is not null then
    select jsonb_build_object(
      'id', wn.id,
      'label', wn.label,
      'type', wn.type::text,
      'config', coalesce(wn.config, '{}'::jsonb)
    ),
    coalesce(wn.config, '{}'::jsonb)
    into v_current_node, v_node_config
    from public.workflow_nodes wn
    where wn.id = v_subject.current_node_id;
  end if;

  select jsonb_build_object(
    'id', target.id,
    'templateNodeId', target.template_node_id,
    'label', target.label,
    'type', target.type::text,
    'config', coalesce(target.config, '{}'::jsonb)
  )
  into v_next_node
  from public.workflow_instance_edges edge
  join public.workflow_instance_nodes target on target.id = edge.target_instance_node_id
  where edge.workflow_instance_id = v_subject.workflow_instance_id
    and edge.source_instance_node_id = v_subject.current_instance_node_id
  order by edge.sort_order, edge.created_at
  limit 1;

  select jsonb_build_object(
    'id', rtn.id,
    'templateNodeId', rtn.template_node_id,
    'label', rtn.label,
    'type', rtn.type::text,
    'config', coalesce(rtn.config, '{}'::jsonb)
  )
  into v_return_node
  from public.workflow_instance_nodes rtn
  where rtn.id = v_subject.return_to_instance_node_id;

  v_can_reassign := v_subject.status = 'RUNNING'
    and coalesce(v_node_config ->> 'allowReassign', 'true') <> 'false'
    and (v_is_pending_assignee or v_is_workflow_admin or public.is_admin() or public.is_module_admin('WF'));

  v_can_rollback := v_subject.status = 'COMPLETED'
    and (v_is_workflow_admin or public.is_admin() or public.is_module_admin('WF'));

  if v_can_rollback and p_subject_type = 'material_request' then
    v_rollback := public.get_project_workflow_rollback_dependencies(p_subject_type, p_subject_id);
  end if;

  return jsonb_build_object(
    'subjectType', p_subject_type,
    'subjectId', p_subject_id,
    'workflowSubjectId', v_subject.id,
    'status', v_subject.status,
    'currentNode', v_current_node,
    'nextNode', v_next_node,
    'returnTargetNode', v_return_node,
    'pendingAssigneeUserIds', coalesce(v_pending_assignee_ids, '{}'::uuid[]),
    'isPendingAssignee', v_is_pending_assignee,
    'isWorkflowAdmin', v_is_workflow_admin,
    'isWatcher', v_is_watcher,
    'isCreator', v_is_creator,
    'canApprove', v_subject.status = 'RUNNING' and v_is_pending_assignee,
    'canReturn', v_subject.status = 'RUNNING' and v_is_pending_assignee,
    'canReject', v_subject.status = 'RUNNING'
      and v_is_pending_assignee
      and coalesce(v_node_config ->> 'allowReject', 'true') <> 'false',
    'canResubmit', v_subject.status = 'RETURNED' and v_is_creator,
    'canReassign', v_can_reassign,
    'canRollback', v_can_rollback,
    'rollbackDependencies', v_rollback
  );
end;
$$;


ALTER FUNCTION "public"."get_project_workflow_action_context"("p_subject_type" "text", "p_subject_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_project_workflow_configuration"("p_subject_type" "text", "p_project_id" "text" DEFAULT NULL::"text", "p_construction_site_id" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_binding public.project_workflow_bindings%rowtype;
  v_scope text;
  v_validation jsonb;
begin
  if public.current_app_user_id() is null then
    raise exception 'authentication required';
  end if;
  if p_subject_type <> 'material_request' then
    raise exception 'unsupported project workflow subject type: %', p_subject_type;
  end if;

  select pwb.*
    into v_binding
  from public.project_workflow_bindings pwb
  join public.workflow_templates wt on wt.id = pwb.workflow_template_id
  where pwb.subject_type = p_subject_type
    and pwb.is_active
    and pwb.is_default
    and (
      (p_construction_site_id is not null and pwb.project_id is not distinct from p_project_id and pwb.construction_site_id = p_construction_site_id)
      or (p_project_id is not null and pwb.project_id = p_project_id and pwb.construction_site_id is null)
      or (pwb.project_id is null and pwb.construction_site_id is null)
    )
  order by
    case
      when p_construction_site_id is not null and pwb.construction_site_id = p_construction_site_id then 1
      when p_project_id is not null and pwb.project_id = p_project_id and pwb.construction_site_id is null then 2
      else 3
    end
  limit 1;

  if not found then
    return jsonb_build_object(
      'subjectType', p_subject_type,
      'projectId', p_project_id,
      'constructionSiteId', p_construction_site_id,
      'binding', null,
      'scope', null,
      'valid', false,
      'errors', jsonb_build_array('Chưa cấu hình workflow cho đề xuất vật tư.'),
      'canManage', app_private.project_workflow_binding_can_manage(p_project_id, p_construction_site_id)
    );
  end if;

  v_scope := case
    when v_binding.construction_site_id is not null then 'site'
    when v_binding.project_id is not null then 'project'
    else 'global'
  end;
  v_validation := app_private.project_workflow_validate_template(v_binding.workflow_template_id);

  return jsonb_build_object(
    'subjectType', p_subject_type,
    'projectId', p_project_id,
    'constructionSiteId', p_construction_site_id,
    'binding', to_jsonb(v_binding),
    'scope', v_scope,
    'valid', coalesce((v_validation ->> 'valid')::boolean, false),
    'errors', coalesce(v_validation -> 'errors', '[]'::jsonb),
    'validation', v_validation,
    'canManage', app_private.project_workflow_binding_can_manage(
      p_project_id, p_construction_site_id, v_binding.workflow_template_id
    )
  );
end;
$$;


ALTER FUNCTION "public"."get_project_workflow_configuration"("p_subject_type" "text", "p_project_id" "text", "p_construction_site_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_project_workflow_rollback_dependencies"("p_subject_type" "text", "p_subject_id" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_subject_id uuid;
  v_result jsonb;
begin
  if public.current_app_user_id() is null then raise exception 'authentication required'; end if;
  select ws.id into v_subject_id
  from public.workflow_subjects ws
  where ws.subject_type = p_subject_type and ws.subject_id = p_subject_id;
  if v_subject_id is null then raise exception 'workflow subject not found'; end if;
  if not app_private.project_workflow_actor_can_select(v_subject_id) then
    raise exception 'user cannot view workflow rollback dependencies';
  end if;

  if p_subject_type <> 'material_request' then
    return jsonb_build_object(
      'allowed', false,
      'activeCount', 1,
      'dependencies', jsonb_build_array(
        jsonb_build_object('type', 'unsupported_subject', 'status', 'active')
      )
    );
  end if;

  with candidates as (
    select
      pdl.target_type as type,
      pdl.target_id as id,
      pdl.status,
      'project_document_links'::text as source,
      10 as priority
    from public.project_document_links pdl
    where pdl.source_type = p_subject_type
      and pdl.source_id = p_subject_id
      and pdl.relation_type = 'downstream'

    union all

    select
      'fulfillment_batch'::text,
      b.id::text,
      case when app_private.material_request_batch_is_fully_reversed(b.id)
        then 'reversed' else 'active' end,
      'material_request_fulfillment_batches'::text,
      100
    from public.material_request_fulfillment_batches b
    where b.material_request_id = p_subject_id

    union all

    select
      'purchase_order'::text,
      po.id::text,
      case when lower(coalesce(po.status::text, '')) in ('cancelled', 'canceled', 'returned', 'reversed', 'void')
        then 'reversed' else 'active' end,
      'purchase_orders'::text,
      100
    from public.purchase_orders po
    where coalesce(po.material_request_id::text, '') = p_subject_id

    union all

    select distinct
      'purchase_order'::text,
      po.id::text,
      case when lower(coalesce(po.status::text, '')) in ('cancelled', 'canceled', 'returned', 'reversed', 'void')
        then 'reversed' else 'active' end,
      'purchase_order_request_lines'::text,
      100
    from public.purchase_order_request_lines porl
    join public.purchase_orders po on po.id = porl.purchase_order_id
    where porl.material_request_id = p_subject_id

    union all

    select
      'transaction'::text,
      t.id::text,
      app_private.material_request_transaction_dependency_status(t.id::text, p_subject_id),
      'transactions'::text,
      100
    from public.transactions t
    where coalesce(t.related_request_id, '') = p_subject_id
       or exists (
         select 1
         from jsonb_array_elements(coalesce(t.items, '[]'::jsonb)) item(value)
         where coalesce(
           item.value ->> 'materialRequestId',
           item.value ->> 'material_request_id'
         ) = p_subject_id
       )
  ),
  ranked as (
    select
      type, id, status, source,
      row_number() over (
        partition by type, id
        order by priority desc, case when status = 'active' then 0 else 1 end, source
      ) as row_number
    from candidates
  ),
  dependencies as (
    select type, id, status, source
    from ranked
    where row_number = 1
  )
  select jsonb_build_object(
    'allowed', count(*) filter (where status = 'active') = 0,
    'activeCount', count(*) filter (where status = 'active'),
    'dependencies', coalesce(
      jsonb_agg(
        jsonb_build_object('type', type, 'id', id, 'status', status, 'source', source)
        order by type, id
      ),
      '[]'::jsonb
    )
  )
  into v_result
  from dependencies;

  return coalesce(
    v_result,
    jsonb_build_object('allowed', true, 'activeCount', 0, 'dependencies', '[]'::jsonb)
  );
end;
$$;


ALTER FUNCTION "public"."get_project_workflow_rollback_dependencies"("p_subject_type" "text", "p_subject_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_project_workflow_rollback_dependencies_legacy"("p_subject_type" "text", "p_subject_id" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_items jsonb := '[]'::jsonb;
  v_active_count integer := 0;
begin
  if p_subject_type <> 'material_request' then
    return jsonb_build_object('allowed', false, 'activeCount', 1, 'dependencies', jsonb_build_array(
      jsonb_build_object('type', 'unsupported_subject', 'status', 'active')
    ));
  end if;

  if to_regclass('public.project_document_links') is not null then
    select
      coalesce(jsonb_agg(jsonb_build_object(
        'type', pdl.target_type,
        'id', pdl.target_id,
        'status', pdl.status,
        'relationType', pdl.relation_type,
        'source', 'project_document_links'
      )), '[]'::jsonb),
      count(*) filter (where pdl.status = 'active')
    into v_items, v_active_count
    from public.project_document_links pdl
    where pdl.source_type = p_subject_type
      and pdl.source_id = p_subject_id
      and pdl.relation_type = 'downstream';
  end if;

  if to_regclass('public.material_request_fulfillment_batches') is not null then
    with deps as (
      select
        'fulfillment_batch'::text as type,
        mrfb.id::text as id,
        case
          when lower(coalesce(mrfb.status::text, '')) in ('cancelled', 'canceled', 'returned', 'reversed', 'void')
            then 'reversed'
          else 'active'
        end as status
      from public.material_request_fulfillment_batches mrfb
      where mrfb.material_request_id = p_subject_id
    )
    select
      v_items || coalesce(jsonb_agg(jsonb_build_object('type', type, 'id', id, 'status', status, 'source', 'fulfillment_batches')), '[]'::jsonb),
      v_active_count + count(*) filter (where status = 'active')
    into v_items, v_active_count
    from deps;
  end if;

  if to_regclass('public.purchase_orders') is not null then
    with deps as (
      select distinct
        'purchase_order'::text as type,
        po.id::text as id,
        case
          when lower(coalesce(po.status::text, '')) in ('cancelled', 'canceled', 'reversed', 'void', 'closed')
            then 'reversed'
          else 'active'
        end as status
      from public.purchase_orders po
      where coalesce(po.material_request_id::text, '') = p_subject_id
    )
    select
      v_items || coalesce(jsonb_agg(jsonb_build_object('type', type, 'id', id, 'status', status, 'source', 'purchase_orders')), '[]'::jsonb),
      v_active_count + count(*) filter (where status = 'active')
    into v_items, v_active_count
    from deps;
  end if;

  if to_regclass('public.purchase_order_request_lines') is not null then
    with deps as (
      select distinct
        'purchase_order'::text as type,
        po.id::text as id,
        case
          when lower(coalesce(po.status::text, '')) in ('cancelled', 'canceled', 'reversed', 'void', 'closed')
            then 'reversed'
          else 'active'
        end as status
      from public.purchase_order_request_lines porl
      join public.purchase_orders po
        on po.id = porl.purchase_order_id
      where porl.material_request_id = p_subject_id
    )
    select
      v_items || coalesce(jsonb_agg(jsonb_build_object('type', type, 'id', id, 'status', status, 'source', 'purchase_order_request_lines')), '[]'::jsonb),
      v_active_count + count(*) filter (where status = 'active')
    into v_items, v_active_count
    from deps;
  end if;

  if to_regclass('public.transactions') is not null then
    with deps as (
      select
        'transaction'::text as type,
        t.id::text as id,
        case
          when lower(coalesce(t.status::text, '')) in ('cancelled', 'canceled', 'reversed', 'void')
            then 'reversed'
          else 'active'
        end as status
      from public.transactions t
      where coalesce(t.related_request_id, '') = p_subject_id
         or exists (
           select 1
           from jsonb_array_elements(coalesce(t.items, '[]'::jsonb)) as item(value)
           where coalesce(item.value ->> 'materialRequestId', item.value ->> 'material_request_id') = p_subject_id
         )
    )
    select
      v_items || coalesce(jsonb_agg(jsonb_build_object('type', type, 'id', id, 'status', status, 'source', 'transactions')), '[]'::jsonb),
      v_active_count + count(*) filter (where status = 'active')
    into v_items, v_active_count
    from deps;
  end if;

  return jsonb_build_object(
    'allowed', v_active_count = 0,
    'activeCount', v_active_count,
    'dependencies', coalesce(v_items, '[]'::jsonb)
  );
end;
$$;


ALTER FUNCTION "public"."get_project_workflow_rollback_dependencies_legacy"("p_subject_type" "text", "p_subject_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_project_workflow_timeline"("p_workflow_subject_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_subject public.workflow_subjects%rowtype;
  v_assignments jsonb := '[]'::jsonb;
  v_events jsonb := '[]'::jsonb;
begin
  if public.current_app_user_id() is null then
    raise exception 'authentication required';
  end if;

  select * into v_subject
  from public.workflow_subjects ws
  where ws.id = p_workflow_subject_id;

  if not found then
    raise exception 'workflow subject not found';
  end if;

  if not app_private.project_workflow_actor_can_select(v_subject.id) then
    raise exception 'user cannot view workflow timeline';
  end if;

  select coalesce(jsonb_agg(
    jsonb_build_object(
      'kind', 'assignment',
      'id', wsa.id,
      'workflowSubjectId', wsa.workflow_subject_id,
      'workflowInstanceId', wsa.workflow_instance_id,
      'nodeId', wsa.node_id,
      'instanceNodeId', wsa.instance_node_id,
      'assignmentRoundId', wsa.assignment_round_id,
      'nodeLabel', coalesce(win.label, wn.label),
      'nodeType', coalesce(win.type::text, wn.type::text),
      'assigneeUserId', wsa.assignee_user_id,
      'assigneeName', au.name,
      'assignedBy', wsa.assigned_by,
      'assignedByName', bu.name,
      'status', wsa.status,
      'assignedAt', wsa.assigned_at,
      'actedAt', wsa.acted_at,
      'actionComment', wsa.action_comment,
      'dueAt', wsa.due_at,
      'slaHours', wsa.sla_hours,
      'assignmentSource', wsa.assignment_source,
      'assignmentGroupType', wsa.assignment_group_type,
      'assignmentGroupId', wsa.assignment_group_id,
      'metadata', coalesce(wsa.metadata, '{}'::jsonb)
    )
    order by wsa.assigned_at, wsa.id
  ), '[]'::jsonb)
  into v_assignments
  from public.workflow_step_assignments wsa
  left join public.workflow_instance_nodes win on win.id = wsa.instance_node_id
  left join public.workflow_nodes wn on wn.id = wsa.node_id
  left join public.users au on au.id = wsa.assignee_user_id
  left join public.users bu on bu.id = wsa.assigned_by
  where wsa.workflow_subject_id = v_subject.id;

  if v_subject.subject_type = 'material_request' then
    select coalesce(jsonb_agg(
      jsonb_build_object(
        'kind', 'event',
        'id', mre.id,
        'requestId', mre.request_id,
        'action', mre.action,
        'fromStep', mre.from_step,
        'toStep', mre.to_step,
        'actorUserId', mre.actor_user_id,
        'actorName', actor.name,
        'targetUserId', mre.target_user_id,
        'targetName', target_user.name,
        'note', mre.note,
        'dueAt', mre.due_at,
        'slaHours', mre.sla_hours,
        'metadata', coalesce(mre.metadata, '{}'::jsonb),
        'createdAt', mre.created_at
      )
      order by mre.created_at, mre.id
    ), '[]'::jsonb)
    into v_events
    from public.material_request_events mre
    left join public.users actor on actor.id::text = mre.actor_user_id
    left join public.users target_user on target_user.id::text = mre.target_user_id
    where mre.request_id = v_subject.subject_id;
  end if;

  return jsonb_build_object(
    'workflowSubjectId', v_subject.id,
    'subjectType', v_subject.subject_type,
    'subjectId', v_subject.subject_id,
    'assignments', v_assignments,
    'events', v_events,
    'entries', (
      select coalesce(jsonb_agg(entry order by coalesce(entry ->> 'actedAt', entry ->> 'createdAt', entry ->> 'assignedAt')), '[]'::jsonb)
      from jsonb_array_elements(v_assignments || v_events) as t(entry)
    )
  );
end;
$$;


ALTER FUNCTION "public"."get_project_workflow_timeline"("p_workflow_subject_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_user_account_lifecycle_preview"("p_target_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_actor_user_id uuid := public.current_app_user_id();
  v_result jsonb;
begin
  perform app_private.assert_legacy_system_admin(v_actor_user_id);

  select jsonb_build_object(
    'targetUserId', user_row.id,
    'accountStatus', user_row.account_status,
    'operationStatus', user_row.account_operation_status,
    'operationAction', user_row.account_operation_action,
    'hasAuthIdentity', user_row.auth_id is not null,
    'directGrants', (
      select count(*)
      from public.user_permission_grants grant_row
      where grant_row.user_id = user_row.id
        and grant_row.is_active
    ),
    'businessRoleAssignments', (
      select count(*)
      from public.principal_role_assignments assignment_row
      where assignment_row.principal_type = 'user'
        and assignment_row.principal_id = user_row.id
        and assignment_row.status in ('ACTIVE')
    ),
    'legacyModules', cardinality(coalesce(user_row.allowed_modules, '{}'::text[]))
      + cardinality(coalesce(user_row.admin_modules, '{}'::text[])),
    'projectStaffAssignments', (
      select count(*)
      from public.project_staff staff_row
      where staff_row.user_id = user_row.id::text
        and staff_row.end_date is null
    ),
    'responsibilitySlots', (
      select count(*)
      from public.app_responsibility_slots slot_row
      where slot_row.assignee_user_id = user_row.id
        and slot_row.status = 'active'
    ),
    'runtimeAssignments', (
      select count(*)
      from public.app_assignments assignment_row
      where assignment_row.principal_id = user_row.id
        and assignment_row.status = 'active'
    )
  )
  into v_result
  from public.users user_row
  where user_row.id = p_target_user_id;

  if v_result is null then
    raise exception 'Target user does not exist'
      using errcode = 'P0002';
  end if;

  return v_result;
end;
$$;


ALTER FUNCTION "public"."get_user_account_lifecycle_preview"("p_target_user_id" "uuid") OWNER TO "postgres";


