CREATE OR REPLACE FUNCTION "public"."match_ai_memories"("query_embedding" "public"."vector", "match_count" integer DEFAULT 10, "match_threshold" double precision DEFAULT 0.3, "filter_user_id" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "content" "text", "category" "text", "topics" "text"[], "importance" integer, "similarity" double precision)
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    m.id,
    m.content,
    m.category,
    m.topics,
    m.importance,
    1 - (m.embedding <=> query_embedding) AS similarity
  FROM ai_memory m
  WHERE m.embedding IS NOT NULL
    AND 1 - (m.embedding <=> query_embedding) > match_threshold
    AND (filter_user_id IS NULL OR m.user_id = filter_user_id OR m.user_id = 'system')
  ORDER BY m.importance DESC, similarity DESC
  LIMIT match_count;
END;
$$;


ALTER FUNCTION "public"."match_ai_memories"("query_embedding" "public"."vector", "match_count" integer, "match_threshold" double precision, "filter_user_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."match_query_cache"("query_embedding" "public"."vector", "match_count" integer DEFAULT 3, "match_threshold" double precision DEFAULT 0.85) RETURNS TABLE("id" "uuid", "question" "text", "sql_query" "text", "answer" "text", "hit_count" integer, "score" double precision, "similarity" double precision)
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    c.id,
    c.question,
    c.sql_query,
    c.answer,
    c.hit_count,
    c.score,
    1 - (c.embedding <=> query_embedding) AS similarity
  FROM ai_query_cache c
  WHERE c.embedding IS NOT NULL
    AND c.score > 0
    AND 1 - (c.embedding <=> query_embedding) > match_threshold
  ORDER BY similarity DESC
  LIMIT match_count;
END;
$$;


ALTER FUNCTION "public"."match_query_cache"("query_embedding" "public"."vector", "match_count" integer, "match_threshold" double precision) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."match_rag_chunks"("query_embedding" "public"."vector", "match_count" integer DEFAULT 5, "match_threshold" double precision DEFAULT 0.3) RETURNS TABLE("id" "uuid", "document_id" "uuid", "content" "text", "metadata" "jsonb", "similarity" double precision)
    LANGUAGE "sql" STABLE
    AS $$
  SELECT
    rc.id, rc.document_id, rc.content, rc.metadata,
    1 - (rc.embedding <=> query_embedding) as similarity
  FROM rag_chunks rc
  JOIN rag_documents rd ON rc.document_id = rd.id
  WHERE rd.status = 'ready'
    AND 1 - (rc.embedding <=> query_embedding) > match_threshold
  ORDER BY rc.embedding <=> query_embedding
  LIMIT match_count;
$$;


ALTER FUNCTION "public"."match_rag_chunks"("query_embedding" "public"."vector", "match_count" integer, "match_threshold" double precision) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."next_asset_code"() RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_next integer;
  v_code text;
begin
  perform pg_advisory_xact_lock(hashtext('public.next_asset_code'));

  select coalesce(max(substring(code from '^TS-([0-9]+)$')::integer), 0) + 1
    into v_next
  from public.assets
  where code ~ '^TS-[0-9]+$';

  loop
    v_code := 'TS-' || lpad(v_next::text, 3, '0');
    exit when not exists (select 1 from public.assets where code = v_code);
    v_next := v_next + 1;
  end loop;

  return v_code;
end;
$_$;


ALTER FUNCTION "public"."next_asset_code"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."next_asset_transfer_code"() RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_year integer := extract(year from now())::integer;
  v_existing integer;
  v_next integer;
begin
  select coalesce(max(substring(code from ('^DC-' || v_year || '-([0-9]+)$'))::integer), 0)
    into v_existing
  from public.asset_transfers
  where code ~ ('^DC-' || v_year || '-[0-9]+$');

  insert into public.app_code_counters(scope, year, value)
  values ('DC', v_year, v_existing + 1)
  on conflict (scope, year) do update
    set value = greatest(public.app_code_counters.value + 1, excluded.value),
        updated_at = now()
  returning value into v_next;

  return 'DC-' || v_year || '-' || lpad(v_next::text, 3, '0');
end;
$_$;


ALTER FUNCTION "public"."next_asset_transfer_code"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."next_material_request_code_v1"("p_year" integer DEFAULT NULL::integer) RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_year integer := coalesce(p_year, extract(year from now())::integer);
  v_next bigint;
  v_code text;
begin
  if v_year < 2000 or v_year > 2999 then
    raise exception 'Invalid material request year %.', v_year
      using errcode = '22023';
  end if;

  loop
    insert into app_private.material_request_code_counters(year, value, updated_at)
    values (v_year, 1, now())
    on conflict (year) do update
      set value = app_private.material_request_code_counters.value + 1,
          updated_at = now()
    returning value into v_next;

    v_code := 'MR-' || v_year::text || '-' || lpad(v_next::text, 4, '0');

    insert into app_private.material_request_code_registry(code)
    values (v_code)
    on conflict (code) do nothing;

    if found and not exists (
      select 1
      from public.requests r
      where r.code = v_code
    ) then
      return v_code;
    end if;
  end loop;
end;
$$;


ALTER FUNCTION "public"."next_material_request_code_v1"("p_year" integer) OWNER TO "postgres";


