CREATE TABLE IF NOT EXISTS "public"."site_cash_settlement_batches" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "code" "text" NOT NULL,
    "project_id" "text",
    "construction_site_id" "text" NOT NULL,
    "period_month" "date" NOT NULL,
    "cash_fund_id" "uuid",
    "opening_balance" numeric(18,2) DEFAULT 0 NOT NULL,
    "topup_amount" numeric(18,2) DEFAULT 0 NOT NULL,
    "accepted_spend_amount" numeric(18,2) DEFAULT 0 NOT NULL,
    "rejected_spend_amount" numeric(18,2) DEFAULT 0 NOT NULL,
    "closing_balance" numeric(18,2) DEFAULT 0 NOT NULL,
    "status" "text" DEFAULT 'draft'::"text" NOT NULL,
    "qr_token" "text",
    "created_by" "uuid",
    "approved_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "approved_at" timestamp with time zone,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "note" "text",
    "approved_site_cash_spend" numeric(18,2) DEFAULT 0 NOT NULL,
    "approved_staff_paid_amount" numeric(18,2) DEFAULT 0 NOT NULL,
    "staff_reimbursed_amount" numeric(18,2) DEFAULT 0 NOT NULL,
    "staff_outstanding_amount" numeric(18,2) DEFAULT 0 NOT NULL,
    "project_transaction_id" "text",
    "cash_voucher_id" "uuid",
    "metadata" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    CONSTRAINT "site_cash_settlement_batches_accepted_spend_amount_check" CHECK (("accepted_spend_amount" >= (0)::numeric)),
    CONSTRAINT "site_cash_settlement_batches_approved_site_cash_spend_check" CHECK (("approved_site_cash_spend" >= (0)::numeric)),
    CONSTRAINT "site_cash_settlement_batches_approved_staff_paid_amount_check" CHECK (("approved_staff_paid_amount" >= (0)::numeric)),
    CONSTRAINT "site_cash_settlement_batches_check" CHECK ((("project_id" IS NOT NULL) OR ("construction_site_id" IS NOT NULL))),
    CONSTRAINT "site_cash_settlement_batches_opening_balance_check" CHECK (("opening_balance" >= (0)::numeric)),
    CONSTRAINT "site_cash_settlement_batches_rejected_spend_amount_check" CHECK (("rejected_spend_amount" >= (0)::numeric)),
    CONSTRAINT "site_cash_settlement_batches_staff_outstanding_amount_check" CHECK (("staff_outstanding_amount" >= (0)::numeric)),
    CONSTRAINT "site_cash_settlement_batches_staff_reimbursed_amount_check" CHECK (("staff_reimbursed_amount" >= (0)::numeric)),
    CONSTRAINT "site_cash_settlement_batches_status_check" CHECK (("status" = ANY (ARRAY['draft'::"text", 'submitted'::"text", 'reviewing'::"text", 'approved'::"text", 'closed'::"text", 'cancelled'::"text", 'reversed'::"text"]))),
    CONSTRAINT "site_cash_settlement_batches_topup_amount_check" CHECK (("topup_amount" >= (0)::numeric))
);


ALTER TABLE "public"."site_cash_settlement_batches" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."post_site_cash_settlement_batch"("p_batch_id" "uuid", "p_actor_id" "uuid" DEFAULT NULL::"uuid") RETURNS "public"."site_cash_settlement_batches"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
declare
  v_batch public.site_cash_settlement_batches%rowtype;
  v_totals record;
  v_finance_id text := '';
  v_tx_id text;
  v_voucher_id uuid;
  v_cashflow_amount numeric(18,2);
  v_actor_id uuid;
  v_document public.supplier_payable_documents%rowtype;
begin
  select * into v_batch
  from public.site_cash_settlement_batches
  where id = p_batch_id
  for update;

  if not found then
    raise exception 'Không tìm thấy bộ hoàn ứng %. ', p_batch_id;
  end if;

  if not app_private.ap_scope_can_mutate(v_batch.project_id, v_batch.construction_site_id) then
    raise exception 'Bạn không có quyền duyệt bộ hoàn ứng này.';
  end if;

  if v_batch.status in ('approved', 'closed') then
    return v_batch;
  end if;

  if v_batch.status in ('cancelled', 'reversed') then
    raise exception 'Không thể post bộ hoàn ứng đã huỷ/đảo.';
  end if;

  v_actor_id := coalesce(p_actor_id, v_batch.created_by);

  if not exists (
    select 1
    from public.site_cash_settlement_lines
    where settlement_batch_id = p_batch_id
  ) then
    raise exception 'Bộ hoàn ứng chưa có dòng chứng từ.';
  end if;

  if exists (
    select 1
    from public.site_cash_settlement_lines
    where settlement_batch_id = p_batch_id
      and status = 'pending'
  ) then
    raise exception 'Bộ hoàn ứng còn dòng chứng từ chưa review.';
  end if;

  if exists (
    select 1
    from public.site_cash_settlement_lines line
    join public.site_cash_settlement_lines other_line
      on other_line.source_type = line.source_type
     and other_line.source_id = line.source_id
     and other_line.settlement_batch_id <> line.settlement_batch_id
    join public.site_cash_settlement_batches other_batch on other_batch.id = other_line.settlement_batch_id
    where line.settlement_batch_id = p_batch_id
      and line.source_type = 'site_direct_purchase'
      and other_batch.status not in ('cancelled', 'reversed')
  ) then
    raise exception 'Có phiếu mua nóng đã nằm trong bộ hoàn ứng khác.';
  end if;

  if exists (
    select 1
    from public.site_cash_settlement_lines line
    join public.site_direct_purchases purchase on purchase.id::text = line.source_id
    where line.settlement_batch_id = p_batch_id
      and line.source_type = 'site_direct_purchase'
      and line.status in ('accepted', 'adjusted')
      and purchase.payment_source not in ('site_cash', 'staff_paid')
  ) then
    raise exception 'Bộ hoàn ứng chỉ nhận phiếu mua nóng nguồn quỹ công trường hoặc cá nhân ứng trước.';
  end if;

  if exists (
    select 1
    from public.site_cash_settlement_lines line
    join public.site_direct_purchases purchase on purchase.id::text = line.source_id
    where line.settlement_batch_id = p_batch_id
      and line.source_type = 'site_direct_purchase'
      and line.status in ('accepted', 'adjusted')
      and exists (
        select 1
        from public.site_direct_purchase_lines purchase_line
        left join public.transactions tx on tx.id = purchase.wms_transaction_id
        where purchase_line.direct_purchase_id = purchase.id
          and purchase_line.line_type = 'stock_item'
          and purchase_line.status <> 'rejected'
          and coalesce(tx.status::text, '') not in ('completed', 'COMPLETED', 'Hoàn tất')
      )
  ) then
    raise exception 'Phiếu mua nóng có vật tư tồn kho phải hoàn tất WMS trước khi hoàn ứng.';
  end if;

  if exists (
    select 1
    from public.site_cash_settlement_lines line
    where line.settlement_batch_id = p_batch_id
      and line.status in ('accepted', 'adjusted')
      and line.payment_source = 'staff_paid'
      and line.staff_reimbursed_amount > line.approved_amount
  ) then
    raise exception 'Số hoàn cá nhân không được vượt số đã duyệt.';
  end if;

  select * into v_totals
  from app_private.recompute_site_cash_settlement_totals(p_batch_id);

  if v_totals.closing_balance < 0 then
    raise exception 'Quỹ công trường âm sau hoàn ứng (%).', v_totals.closing_balance;
  end if;

  select id into v_finance_id
  from public.project_finances
  where (v_batch.project_id is not null and project_id = v_batch.project_id)
     or (v_batch.construction_site_id is not null and construction_site_id = v_batch.construction_site_id)
  limit 1;

  v_cashflow_amount := (v_totals.approved_site_cash_spend + v_totals.staff_reimbursed_amount)::numeric(18,2);
  v_tx_id := 'site-cash-settlement-' || p_batch_id::text;

  for v_document in
    select doc.*
    from (
      select distinct line.source_id::uuid as direct_purchase_id
      from public.site_cash_settlement_lines line
      where line.settlement_batch_id = p_batch_id
        and line.source_type = 'site_direct_purchase'
        and line.status in ('accepted', 'adjusted')
    ) source_purchase
    cross join lateral public.sync_supplier_payable_from_site_direct_purchase(source_purchase.direct_purchase_id) doc
  loop
    null;
  end loop;

  update public.site_cash_settlement_lines line
  set payable_document_id = payable.id
  from public.supplier_payable_documents payable
  where line.settlement_batch_id = p_batch_id
    and line.source_type = 'site_direct_purchase'
    and payable.source_type = 'site_direct_purchase'
    and payable.source_id = line.source_id;

  with settlement_credits as (
    select
      line.payable_document_id,
      sum(line.approved_amount)::numeric(18,2) as requested_credit_amount
    from public.site_cash_settlement_lines line
    where line.settlement_batch_id = p_batch_id
      and line.status in ('accepted', 'adjusted')
      and line.payable_document_id is not null
    group by line.payable_document_id
  ),
  credit_deltas as (
    select
      payable.id,
      least(
        greatest(balance.outstanding_amount, 0),
        settlement_credits.requested_credit_amount
      )::numeric(18,2) as credit_delta
    from public.supplier_payable_documents payable
    join public.supplier_payable_document_balances balance on balance.id = payable.id
    join settlement_credits on settlement_credits.payable_document_id = payable.id
  )
  update public.supplier_payable_documents payable
  set
    credit_amount = (payable.credit_amount + credit_deltas.credit_delta)::numeric(18,2),
    metadata = payable.metadata
      || jsonb_build_object(
        'siteCashSettlementCredits',
        coalesce(payable.metadata->'siteCashSettlementCredits', '{}'::jsonb)
          || jsonb_build_object(p_batch_id::text, credit_deltas.credit_delta)
      ),
    updated_at = now()
  from credit_deltas
  where payable.id = credit_deltas.id
    and credit_deltas.credit_delta > 0;

  update public.supplier_payable_documents payable
  set
    status = case
      when balance.outstanding_amount <= 0 then 'paid'
      when balance.paid_amount > 0 or payable.credit_amount > 0 then 'partial'
      when payable.recognized_amount > 0 then 'open'
      else 'draft'
    end,
    updated_at = now()
  from public.supplier_payable_document_balances balance
  where balance.id = payable.id
    and payable.id in (
      select payable_document_id
      from public.site_cash_settlement_lines
      where settlement_batch_id = p_batch_id
        and payable_document_id is not null
    );

  if v_cashflow_amount > 0 then
    insert into public.project_transactions (
      id, "projectFinanceId", "constructionSiteId", project_id, project_finance_id, construction_site_id,
      type, category, amount, description, date, source, "sourceRef", source_ref,
      attachments, "createdBy", "createdAt"
    )
    values (
      v_tx_id,
      coalesce(v_finance_id, ''),
      coalesce(v_batch.construction_site_id, ''),
      v_batch.project_id,
      nullif(v_finance_id, ''),
      v_batch.construction_site_id,
      'expense',
      'materials',
      v_cashflow_amount,
      'Hoàn ứng/quỹ công trường ' || v_batch.code,
      current_date::text,
      'workflow',
      'site_cash_settlement_batch:' || p_batch_id::text,
      'site_cash_settlement_batch:' || p_batch_id::text,
      '[]'::jsonb,
      v_actor_id::text,
      now()
    )
    on conflict (source_ref) do update
    set
      amount = excluded.amount,
      description = excluded.description,
      date = excluded.date,
      "createdBy" = excluded."createdBy";
  else
    v_tx_id := null;
  end if;

  if v_batch.cash_fund_id is not null and v_cashflow_amount > 0 then
    if v_actor_id is null then
      raise exception 'Thiếu người duyệt để tạo phiếu chi quỹ.';
    end if;

    insert into public.cash_vouchers (
      code, type, fund_id, date, amount, contact_name, contact_type, contact_id,
      reason, status, approved_by, approved_at, note, created_by
    )
    values (
      'PC-' || v_batch.code,
      'payment',
      v_batch.cash_fund_id,
      now(),
      v_cashflow_amount,
      'Công trường',
      'other',
      v_batch.construction_site_id,
      'Hoàn ứng/quỹ công trường ' || v_batch.code,
      'approved',
      v_actor_id,
      now(),
      v_batch.note,
      v_actor_id
    )
    on conflict (code) do update
    set
      amount = excluded.amount,
      approved_by = excluded.approved_by,
      approved_at = excluded.approved_at,
      note = excluded.note
    returning id into v_voucher_id;
  end if;

  update public.site_direct_purchases purchase
  set site_cash_settlement_id = p_batch_id, updated_at = now()
  where exists (
    select 1
    from public.site_cash_settlement_lines line
    where line.settlement_batch_id = p_batch_id
      and line.source_type = 'site_direct_purchase'
      and line.source_id = purchase.id::text
      and line.status in ('accepted', 'adjusted')
  );

  update public.site_cash_settlement_batches
  set
    accepted_spend_amount = v_totals.accepted_spend_amount,
    rejected_spend_amount = v_totals.rejected_spend_amount,
    approved_site_cash_spend = v_totals.approved_site_cash_spend,
    approved_staff_paid_amount = v_totals.approved_staff_paid_amount,
    staff_reimbursed_amount = v_totals.staff_reimbursed_amount,
    staff_outstanding_amount = v_totals.staff_outstanding_amount,
    closing_balance = v_totals.closing_balance,
    project_transaction_id = v_tx_id,
    cash_voucher_id = coalesce(v_voucher_id, cash_voucher_id),
    status = 'approved',
    approved_by = coalesce(v_actor_id, approved_by),
    approved_at = coalesce(approved_at, now()),
    updated_at = now()
  where id = p_batch_id
  returning * into v_batch;

  return v_batch;
end;
$$;


ALTER FUNCTION "public"."post_site_cash_settlement_batch"("p_batch_id" "uuid", "p_actor_id" "uuid") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."supplier_delivery_statements" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "code" "text" NOT NULL,
    "project_id" "text",
    "construction_site_id" "text",
    "supplier_contract_id" "text" NOT NULL,
    "supplier_contract_code" "text",
    "supplier_id" "text",
    "supplier_name_snapshot" "text" NOT NULL,
    "period_month" "date" NOT NULL,
    "statement_date" "date" DEFAULT CURRENT_DATE NOT NULL,
    "status" "text" DEFAULT 'draft'::"text" NOT NULL,
    "gross_amount" numeric(18,2) DEFAULT 0 NOT NULL,
    "vat_amount" numeric(18,2) DEFAULT 0 NOT NULL,
    "total_amount" numeric(18,2) DEFAULT 0 NOT NULL,
    "payable_document_id" "uuid",
    "qr_token" "text",
    "attachments" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "metadata" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "created_by" "uuid",
    "posted_by" "uuid",
    "posted_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "note" "text",
    CONSTRAINT "supplier_delivery_statements_check" CHECK ((("project_id" IS NOT NULL) OR ("construction_site_id" IS NOT NULL))),
    CONSTRAINT "supplier_delivery_statements_gross_amount_check" CHECK (("gross_amount" >= (0)::numeric)),
    CONSTRAINT "supplier_delivery_statements_status_check" CHECK (("status" = ANY (ARRAY['draft'::"text", 'posted'::"text", 'cancelled'::"text", 'reversed'::"text"]))),
    CONSTRAINT "supplier_delivery_statements_total_amount_check" CHECK (("total_amount" >= (0)::numeric)),
    CONSTRAINT "supplier_delivery_statements_vat_amount_check" CHECK (("vat_amount" >= (0)::numeric))
);


ALTER TABLE "public"."supplier_delivery_statements" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."post_supplier_delivery_statement"("p_statement_id" "uuid", "p_actor_id" "uuid" DEFAULT NULL::"uuid") RETURNS "public"."supplier_delivery_statements"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
declare
  v_statement public.supplier_delivery_statements%rowtype;
  v_contract public.supplier_contracts%rowtype;
  v_document public.supplier_payable_documents%rowtype;
  v_gross numeric(18,2);
  v_vat numeric(18,2);
  v_total numeric(18,2);
  v_blocked_item text;
begin
  select * into v_statement
  from public.supplier_delivery_statements
  where id = p_statement_id
  for update;

  if not found then
    raise exception 'Không tìm thấy bảng đối soát HĐ NCC %. ', p_statement_id;
  end if;

  if not app_private.ap_scope_can_mutate(v_statement.project_id, v_statement.construction_site_id) then
    raise exception 'Bạn không có quyền post bảng đối soát này.';
  end if;

  if v_statement.status = 'posted' then
    return v_statement;
  end if;

  if v_statement.status in ('cancelled', 'reversed') then
    raise exception 'Không thể post bảng đối soát đã huỷ/đảo.';
  end if;

  select * into v_contract
  from public.supplier_contracts
  where id = v_statement.supplier_contract_id;

  if not found then
    raise exception 'Không tìm thấy HĐ NCC %. ', v_statement.supplier_contract_id;
  end if;

  if v_contract.status = 'cancelled' then
    raise exception 'Không thể ghi nhận phải trả từ HĐ NCC đã huỷ.';
  end if;

  if not exists (
    select 1
    from public.supplier_delivery_statement_lines
    where statement_id = p_statement_id
  ) then
    raise exception 'Bảng đối soát chưa có dòng giao nhận được duyệt.';
  end if;

  if exists (
    select 1
    from public.supplier_delivery_statement_lines sl
    join public.supplier_direct_delivery_lines dl on dl.id = sl.delivery_line_id
    where sl.statement_id = p_statement_id
      and dl.status not in ('accepted', 'adjusted')
  ) then
    raise exception 'Bảng đối soát chỉ được gồm dòng giao nhận accepted/adjusted.';
  end if;

  select dl.item_name_snapshot into v_blocked_item
  from public.supplier_delivery_statement_lines sl
  join public.supplier_direct_delivery_lines dl on dl.id = sl.delivery_line_id
  where sl.statement_id = p_statement_id
    and coalesce(dl.wms_flow_mode, 'none') = 'direct_in_out'
    and coalesce(dl.wms_status, 'not_required') <> 'exported'
  limit 1;

  if v_blocked_item is not null then
    raise exception 'Dòng nhập-xuất thẳng % phải hoàn tất WMS import và WMS xuất dùng trước khi post AP.', v_blocked_item;
  end if;

  if exists (
    select 1
    from public.supplier_delivery_statement_lines sl
    join public.supplier_delivery_statement_lines other_sl on other_sl.delivery_line_id = sl.delivery_line_id
    join public.supplier_delivery_statements other_s on other_s.id = other_sl.statement_id
    where sl.statement_id = p_statement_id
      and other_sl.statement_id <> p_statement_id
      and other_s.status in ('draft', 'posted')
  ) then
    raise exception 'Có dòng giao nhận đã nằm trong bảng đối soát khác.';
  end if;

  select
    coalesce(sum(accepted_amount), 0)::numeric(18,2),
    coalesce(sum(vat_amount), 0)::numeric(18,2),
    coalesce(sum(total_amount), 0)::numeric(18,2)
  into v_gross, v_vat, v_total
  from public.supplier_delivery_statement_lines
  where statement_id = p_statement_id;

  if v_total <= 0 then
    raise exception 'Bảng đối soát chưa có giá trị được duyệt.';
  end if;

  update public.supplier_delivery_statements
  set
    gross_amount = v_gross,
    vat_amount = v_vat,
    total_amount = v_total,
    status = 'posted',
    posted_by = coalesce(p_actor_id, posted_by),
    posted_at = coalesce(posted_at, now()),
    supplier_contract_code = coalesce(supplier_contract_code, v_contract.code),
    supplier_id = coalesce(supplier_id, v_contract.supplier_id),
    supplier_name_snapshot = coalesce(nullif(supplier_name_snapshot, ''), v_contract.supplier_name, 'Nhà cung cấp'),
    updated_at = now()
  where id = p_statement_id
  returning * into v_statement;

  update public.supplier_direct_delivery_lines dl
  set statement_id = p_statement_id, updated_at = now()
  from public.supplier_delivery_statement_lines sl
  where sl.statement_id = p_statement_id
    and sl.delivery_line_id = dl.id;

  update public.supplier_direct_delivery_notes note
  set status = 'statemented', updated_at = now()
  where exists (
    select 1
    from public.supplier_delivery_statement_lines sl
    where sl.statement_id = p_statement_id
      and sl.delivery_note_id = note.id
  )
  and not exists (
    select 1
    from public.supplier_direct_delivery_lines dl
    where dl.delivery_note_id = note.id
      and dl.status in ('accepted', 'adjusted')
      and dl.statement_id is null
  );

  v_document := public.sync_supplier_payable_from_delivery_statement(p_statement_id);

  update public.supplier_delivery_statements
  set payable_document_id = v_document.id, updated_at = now()
  where id = p_statement_id
  returning * into v_statement;

  return v_statement;
end;
$$;


ALTER FUNCTION "public"."post_supplier_delivery_statement"("p_statement_id" "uuid", "p_actor_id" "uuid") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."supplier_payment_batches" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "code" "text" NOT NULL,
    "project_id" "text",
    "construction_site_id" "text",
    "supplier_id" "text",
    "supplier_name_snapshot" "text" NOT NULL,
    "period_month" "date",
    "payment_date" "date" NOT NULL,
    "payment_method" "text" DEFAULT 'bank_transfer'::"text" NOT NULL,
    "cash_fund_id" "uuid",
    "cash_voucher_id" "uuid",
    "project_transaction_id" "text",
    "bank_account_snapshot" "text",
    "document_ref" "text",
    "total_recognized_snapshot" numeric(18,2) DEFAULT 0 NOT NULL,
    "payment_amount" numeric(18,2) DEFAULT 0 NOT NULL,
    "currency" "text" DEFAULT 'VND'::"text" NOT NULL,
    "allocation_mode" "text" DEFAULT 'fifo'::"text" NOT NULL,
    "status" "text" DEFAULT 'draft'::"text" NOT NULL,
    "qr_token" "text",
    "attachments" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "metadata" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "created_by" "uuid",
    "approved_by" "uuid",
    "paid_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "approved_at" timestamp with time zone,
    "paid_at" timestamp with time zone,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "note" "text",
    CONSTRAINT "supplier_payment_batches_allocation_mode_check" CHECK (("allocation_mode" = ANY (ARRAY['fifo'::"text", 'manual'::"text", 'proportional'::"text"]))),
    CONSTRAINT "supplier_payment_batches_check" CHECK ((("project_id" IS NOT NULL) OR ("construction_site_id" IS NOT NULL))),
    CONSTRAINT "supplier_payment_batches_payment_amount_check" CHECK (("payment_amount" >= (0)::numeric)),
    CONSTRAINT "supplier_payment_batches_payment_method_check" CHECK (("payment_method" = ANY (ARRAY['bank_transfer'::"text", 'cash'::"text", 'site_cash'::"text", 'offset'::"text", 'other'::"text"]))),
    CONSTRAINT "supplier_payment_batches_status_check" CHECK (("status" = ANY (ARRAY['draft'::"text", 'submitted'::"text", 'approved'::"text", 'paid'::"text", 'cancelled'::"text", 'reversed'::"text"]))),
    CONSTRAINT "supplier_payment_batches_total_recognized_snapshot_check" CHECK (("total_recognized_snapshot" >= (0)::numeric))
);


ALTER TABLE "public"."supplier_payment_batches" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."post_supplier_payment_batch"("p_batch_id" "uuid", "p_actor_id" "uuid" DEFAULT NULL::"uuid") RETURNS "public"."supplier_payment_batches"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
declare
  v_batch public.supplier_payment_batches%rowtype;
  v_allocated numeric(18,2);
  v_finance_id text := '';
  v_tx_id text;
  v_allocation record;
begin
  select * into v_batch
  from public.supplier_payment_batches
  where id = p_batch_id
  for update;

  if not found then
    raise exception 'Không tìm thấy đợt thanh toán %. ', p_batch_id;
  end if;

  if not app_private.ap_scope_can_mutate(v_batch.project_id, v_batch.construction_site_id) then
    raise exception 'Bạn không có quyền post đợt thanh toán này.';
  end if;

  if v_batch.status = 'paid' then
    return v_batch;
  end if;

  if v_batch.status in ('cancelled', 'reversed') then
    raise exception 'Không thể post đợt thanh toán đã huỷ/đảo.';
  end if;

  select coalesce(sum(allocated_amount), 0)::numeric(18,2)
  into v_allocated
  from public.supplier_payment_allocations
  where payment_batch_id = p_batch_id;

  if v_allocated <> v_batch.payment_amount then
    raise exception 'Tổng phân bổ (%) phải bằng số tiền thanh toán (%).', v_allocated, v_batch.payment_amount;
  end if;

  for v_allocation in
    select
      a.*,
      d.document_no,
      d.recognized_amount,
      d.credit_amount,
      coalesce((
        select sum(a2.allocated_amount + a2.discount_amount + a2.withholding_amount)
        from public.supplier_payment_allocations a2
        join public.supplier_payment_batches b2 on b2.id = a2.payment_batch_id
        where a2.payable_document_id = a.payable_document_id
          and b2.status = 'paid'
          and b2.id <> p_batch_id
      ), 0) as paid_before
    from public.supplier_payment_allocations a
    join public.supplier_payable_documents d on d.id = a.payable_document_id
    where a.payment_batch_id = p_batch_id
    for update of d
  loop
    if v_allocation.paid_before + v_allocation.allocated_amount + v_allocation.discount_amount + v_allocation.withholding_amount
      > v_allocation.recognized_amount - v_allocation.credit_amount
    then
      raise exception 'Số phân bổ vượt công nợ của chứng từ %.', v_allocation.document_no;
    end if;
  end loop;

  select id into v_finance_id
  from public.project_finances
  where (v_batch.project_id is not null and project_id = v_batch.project_id)
     or (v_batch.construction_site_id is not null and construction_site_id = v_batch.construction_site_id)
  limit 1;

  v_tx_id := 'supplier-payment-' || p_batch_id::text;

  insert into public.project_transactions (
    id, "projectFinanceId", "constructionSiteId", project_id, project_finance_id, construction_site_id,
    type, category, amount, description, date, source, "sourceRef", source_ref,
    attachments, "createdBy", "createdAt"
  )
  values (
    v_tx_id,
    coalesce(v_finance_id, ''),
    coalesce(v_batch.construction_site_id, ''),
    v_batch.project_id,
    nullif(v_finance_id, ''),
    v_batch.construction_site_id,
    'expense',
    'materials',
    v_batch.payment_amount,
    'Thanh toán NCC ' || v_batch.supplier_name_snapshot || ' - ' || v_batch.code,
    v_batch.payment_date::text,
    'workflow',
    'supplier_payment_batch:' || p_batch_id::text,
    'supplier_payment_batch:' || p_batch_id::text,
    coalesce(v_batch.attachments, '[]'::jsonb),
    p_actor_id::text,
    now()
  )
  on conflict (source_ref) do update
  set
    amount = excluded.amount,
    description = excluded.description,
    date = excluded.date,
    attachments = excluded.attachments;

  update public.supplier_payment_batches
  set
    status = 'paid',
    paid_by = coalesce(p_actor_id, paid_by),
    paid_at = coalesce(paid_at, now()),
    project_transaction_id = v_tx_id,
    updated_at = now()
  where id = p_batch_id
  returning * into v_batch;

  update public.supplier_payable_documents d
  set
    status = case
      when b.outstanding_amount <= 0 then 'paid'
      when b.paid_amount > 0 then 'partial'
      else d.status
    end,
    updated_at = now()
  from public.supplier_payable_document_balances b
  where b.id = d.id
    and d.id in (
      select payable_document_id
      from public.supplier_payment_allocations
      where payment_batch_id = p_batch_id
    );

  return v_batch;
end;
$$;


ALTER FUNCTION "public"."post_supplier_payment_batch"("p_batch_id" "uuid", "p_actor_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."prepare_user_account_lifecycle"("p_actor_user_id" "uuid", "p_target_user_id" "uuid", "p_action" "text", "p_reason" "text", "p_idempotency_key" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_action text := upper(btrim(coalesce(p_action, '')));
  v_reason text := btrim(coalesce(p_reason, ''));
  v_operation app_private.user_account_operations%rowtype;
  v_target public.users%rowtype;
  v_before_grants jsonb := '[]'::jsonb;
  v_revocation_summary jsonb := '{}'::jsonb;
begin
  if v_action not in ('DISABLE', 'REACTIVATE') then
    raise exception 'Unsupported account lifecycle action'
      using errcode = '22023';
  end if;
  if char_length(v_reason) < 5 then
    raise exception 'Account lifecycle reason must contain at least 5 characters'
      using errcode = '22023';
  end if;

  -- Serialize lifecycle authorization so two concurrent admin disables cannot
  -- both pass the last-active-admin check against stale snapshots.
  perform pg_advisory_xact_lock(
    hashtextextended('user_account_lifecycle_active_admin', 0)
  );
  perform app_private.assert_legacy_system_admin(p_actor_user_id);

  select * into v_target
  from public.users
  where id = p_target_user_id
  for update;

  if v_target.id is null then
    raise exception 'Target user does not exist'
      using errcode = 'P0002';
  end if;

  select * into v_operation
  from app_private.user_account_operations
  where idempotency_key = p_idempotency_key
  for update;

  if v_operation.id is not null then
    if v_operation.target_user_id <> p_target_user_id
      or v_operation.action <> v_action
      or v_operation.requested_by <> p_actor_user_id
      or v_operation.reason <> v_reason
    then
      raise exception 'Idempotency key is already used for another command'
        using errcode = '23505';
    end if;
    return app_private.account_operation_response(v_operation);
  end if;

  -- A fresh browser command may safely resume only the same unfinished action.
  select * into v_operation
  from app_private.user_account_operations
  where target_user_id = p_target_user_id
    and status <> 'COMPLETED'
  order by created_at
  limit 1
  for update;

  if v_operation.id is not null then
    if v_operation.action <> v_action then
      raise exception 'Target account has an unfinished lifecycle operation'
        using errcode = '55000';
    end if;
    return app_private.account_operation_response(v_operation);
  end if;

  if v_action = 'DISABLE' then
    if p_actor_user_id = p_target_user_id then
      raise exception 'Cannot disable the current account'
        using errcode = '42501';
    end if;
    if v_target.is_active and v_target.role = 'ADMIN' and not exists (
      select 1
      from public.users other_admin
      where other_admin.id <> p_target_user_id
        and other_admin.role = 'ADMIN'
        and other_admin.is_active
        and other_admin.account_status = 'ACTIVE'
    ) then
      raise exception 'Cannot disable the last active System Admin'
        using errcode = '42501';
    end if;
  else
    if v_target.is_active or v_target.account_status = 'ACTIVE' then
      raise exception 'Target account is already active'
        using errcode = '22023';
    end if;
  end if;

  select coalesce(
    jsonb_agg(to_jsonb(g) order by g.permission_code, g.scope_type, g.scope_id),
    '[]'::jsonb
  )
  into v_before_grants
  from public.user_permission_grants g
  where g.user_id = p_target_user_id
    and g.is_active;

  insert into app_private.user_account_operations (
    idempotency_key,
    target_user_id,
    requested_by,
    action,
    status,
    reason,
    auth_id,
    before_state
  )
  values (
    p_idempotency_key,
    p_target_user_id,
    p_actor_user_id,
    v_action,
    'PREPARED',
    v_reason,
    v_target.auth_id,
    jsonb_build_object(
      'role', v_target.role,
      'assignedWarehouseId', v_target.assigned_warehouse_id,
      'allowedModules', v_target.allowed_modules,
      'adminModules', v_target.admin_modules,
      'allowedSubModules', v_target.allowed_sub_modules,
      'adminSubModules', v_target.admin_sub_modules,
      'permissionGrants', v_before_grants
    )
  )
  returning * into v_operation;

  perform set_config('app.account_lifecycle_command', 'on', true);

  if v_action = 'DISABLE' then
    update public.users
    set account_status = 'DISABLED',
        is_active = false,
        disabled_at = case when v_target.is_active then now() else disabled_at end,
        disabled_by = case when v_target.is_active then p_actor_user_id else disabled_by end,
        disabled_reason = case when v_target.is_active then v_reason else disabled_reason end,
        role = 'EMPLOYEE',
        assigned_warehouse_id = null,
        allowed_modules = '{}'::text[],
        admin_modules = '{}'::text[],
        allowed_sub_modules = '{}'::jsonb,
        admin_sub_modules = '{}'::jsonb,
        account_operation_status = 'PENDING',
        account_operation_action = 'DISABLE',
        updated_at = now()
    where id = p_target_user_id;
  else
    update public.users
    set account_operation_status = 'PENDING',
        account_operation_action = 'REACTIVATE',
        updated_at = now()
    where id = p_target_user_id;
  end if;

  v_revocation_summary := app_private.revoke_user_access_sources(
    p_target_user_id,
    p_actor_user_id,
    v_operation.id,
    case
      when v_action = 'DISABLE' then 'account_disabled: ' || v_reason
      else 'reactivation_zero_rights_guard: ' || v_reason
    end
  );

  insert into public.permission_audit_events (
    actor_user_id,
    target_user_id,
    event_type,
    before_grants,
    after_grants,
    metadata
  )
  values (
    p_actor_user_id,
    p_target_user_id,
    case
      when v_action = 'DISABLE' then 'account_disabled_db_applied'
      else 'account_reactivation_prepared_zero_rights'
    end,
    v_before_grants,
    '[]'::jsonb,
    jsonb_build_object(
      'operationId', v_operation.id,
      'reason', v_reason,
      'revocationSummary', v_revocation_summary
    )
  );

  update app_private.user_account_operations
  set status = 'DB_APPLIED',
      before_state = before_state || jsonb_build_object(
        'revocationSummary', v_revocation_summary
      ),
      updated_at = now()
  where id = v_operation.id
  returning * into v_operation;

  return app_private.account_operation_response(v_operation);
end;
$$;


ALTER FUNCTION "public"."prepare_user_account_lifecycle"("p_actor_user_id" "uuid", "p_target_user_id" "uuid", "p_action" "text", "p_reason" "text", "p_idempotency_key" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."preview_authorization_change"("p_target_user_id" "uuid", "p_proposed_permission_codes" "text"[], "p_scope_type" "text" DEFAULT 'global'::"text", "p_scope_id" "text" DEFAULT '*'::"text", "p_change_mode" "text" DEFAULT 'ADD'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO ''
    AS $$
declare
  v_actor_user_id uuid := public.current_app_user_id();
begin
  if not app_private.has_any_permission(
    v_actor_user_id,
    array['system.authorization.manage_roles','system.authorization.manage_grants'],
    'global', '*'
  ) then
    raise exception 'Not allowed to preview authorization changes' using errcode = '42501';
  end if;
  return app_private.evaluate_authorization_change(
    v_actor_user_id,
    p_target_user_id,
    p_proposed_permission_codes,
    coalesce(nullif(p_scope_type, ''), 'global'),
    coalesce(nullif(p_scope_id, ''), '*'),
    p_change_mode
  );
end;
$$;


