CREATE OR REPLACE FUNCTION "public"."process_project_workflow_sla_reminders"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_row record;
  v_kind text;
  v_inserted_id uuid;
  v_count integer := 0;
begin
  for v_row in
    select
      wsa.id as assignment_id,
      wsa.workflow_subject_id,
      wsa.assignee_user_id,
      wsa.assigned_at,
      wsa.due_at,
      win.label as node_label,
      ws.subject_id,
      ws.project_id,
      ws.construction_site_id,
      r.code as request_code
    from public.workflow_step_assignments wsa
    join public.workflow_subjects ws on ws.id = wsa.workflow_subject_id
    join public.workflow_instance_nodes win on win.id = wsa.instance_node_id
    join public.requests r on r.id = ws.subject_id
    where wsa.status = 'PENDING'
      and ws.status = 'RUNNING'
      and wsa.due_at is not null
      and wsa.assignee_user_id is not null
      and now() >= wsa.assigned_at + ((wsa.due_at - wsa.assigned_at) * 0.75)
  loop
    v_kind := case when now() > v_row.due_at then 'OVERDUE' else 'DUE_SOON' end;
    v_inserted_id := null;
    insert into public.workflow_sla_notifications(
      workflow_step_assignment_id, workflow_subject_id, user_id, notification_kind
    )
    values (v_row.assignment_id, v_row.workflow_subject_id, v_row.assignee_user_id, v_kind)
    on conflict (workflow_step_assignment_id, notification_kind) do nothing
    returning id into v_inserted_id;

    if v_inserted_id is not null then
      insert into public.notifications(
        user_id, type, category, title, message, icon, link, severity,
        source_type, source_id, construction_site_id, metadata
      )
      values (
        v_row.assignee_user_id::text,
        case when v_kind = 'OVERDUE' then 'error' else 'warning' end,
        'material',
        case when v_kind = 'OVERDUE' then 'Phiếu vật tư đã quá SLA' else 'Phiếu vật tư sắp đến hạn SLA' end,
        coalesce(v_row.request_code, v_row.subject_id) || ' - bước ' || v_row.node_label,
        null,
        '/da?projectId=' || coalesce(v_row.project_id, '') || '&siteId=' || coalesce(v_row.construction_site_id, '') || '&tab=material&materialTab=request',
        case when v_kind = 'OVERDUE' then 'critical' else 'warning' end,
        'workflow_sla',
        v_row.assignment_id::text || ':' || v_kind,
        v_row.construction_site_id,
        jsonb_build_object(
          'workflowSubjectId', v_row.workflow_subject_id,
          'assignmentId', v_row.assignment_id,
          'requestId', v_row.subject_id,
          'notificationKind', v_kind,
          'dueAt', v_row.due_at
        )
      );
      v_count := v_count + 1;
    end if;
  end loop;
  return v_count;
end;
$$;


ALTER FUNCTION "public"."process_project_workflow_sla_reminders"() OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."request_instances" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "category_id" "uuid" NOT NULL,
    "code" "text" NOT NULL,
    "title" "text" NOT NULL,
    "description" "text" DEFAULT ''::"text",
    "priority" "text" DEFAULT 'medium'::"text",
    "form_data" "jsonb" DEFAULT '{}'::"jsonb",
    "created_by" "uuid" NOT NULL,
    "assigned_to" "uuid",
    "status" "text" DEFAULT 'PENDING'::"text",
    "due_date" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"(),
    "approver_id" "uuid",
    "approvers" "jsonb" DEFAULT '[]'::"jsonb",
    CONSTRAINT "request_instances_priority_check" CHECK (("priority" = ANY (ARRAY['low'::"text", 'medium'::"text", 'high'::"text", 'urgent'::"text"]))),
    CONSTRAINT "request_instances_status_check" CHECK (("status" = ANY (ARRAY['DRAFT'::"text", 'PENDING'::"text", 'APPROVED'::"text", 'IN_PROGRESS'::"text", 'DONE'::"text", 'REJECTED'::"text", 'CANCELLED'::"text"])))
);


ALTER TABLE "public"."request_instances" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."process_request_step"("p_request_id" "uuid", "p_user_id" "uuid", "p_action" "text", "p_comment" "text" DEFAULT ''::"text") RETURNS "public"."request_instances"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_req public.request_instances%rowtype;
  v_current_user uuid := public.current_app_user_id();
  v_step jsonb;
  v_step_ord bigint;
  v_approvers jsonb;
  v_all_approved boolean;
  v_status text;
  v_step_order integer;
begin
  if v_current_user is null then
    raise exception 'authentication required';
  end if;
  if p_user_id is distinct from v_current_user and not public.is_module_admin('RQ') then
    raise exception 'cannot act as another user';
  end if;

  select * into v_req
  from public.request_instances
  where id = p_request_id
  for update;
  if not found then
    raise exception 'request not found: %', p_request_id;
  end if;
  if v_req.status not in ('PENDING', 'IN_PROGRESS') then
    raise exception 'request is not waiting for approval';
  end if;

  select elem, ord
    into v_step, v_step_ord
  from jsonb_array_elements(coalesce(v_req.approvers, '[]'::jsonb)) with ordinality as e(elem, ord)
  where elem->>'status' = 'waiting'
  order by coalesce((elem->>'order')::integer, ord::integer)
  limit 1;

  if v_step is null then
    raise exception 'no waiting approver';
  end if;
  if v_step->>'userId' <> p_user_id::text and not public.is_module_admin('RQ') then
    raise exception 'user is not the current approver';
  end if;

  v_step_order := coalesce((v_step->>'order')::integer, v_step_ord::integer);

  if upper(p_action) = 'APPROVED' then
    select jsonb_agg(
      case when ord = v_step_ord then
        elem || jsonb_build_object(
          'status', 'approved',
          'comment', coalesce(nullif(p_comment, ''), 'Đã duyệt'),
          'actedAt', now()::text
        )
      else elem end
      order by ord
    )
      into v_approvers
    from jsonb_array_elements(coalesce(v_req.approvers, '[]'::jsonb)) with ordinality as e(elem, ord);

    v_all_approved := not exists (
      select 1 from jsonb_array_elements(v_approvers) e(elem)
      where elem->>'status' = 'waiting'
    );
    v_status := case when v_all_approved then 'APPROVED' else 'PENDING' end;

    update public.request_instances
    set approvers = v_approvers,
        status = v_status,
        updated_at = now()
    where id = p_request_id
    returning * into v_req;

    insert into public.request_logs(request_id, action, acted_by, comment)
    values (
      p_request_id,
      'APPROVED',
      p_user_id,
      coalesce(nullif(p_comment, ''), 'Duyệt bước ' || v_step_order::text)
    );
  elsif upper(p_action) = 'REJECTED' then
    select jsonb_agg(
      case when ord = v_step_ord then
        elem || jsonb_build_object(
          'status', 'rejected',
          'comment', coalesce(nullif(p_comment, ''), 'Từ chối'),
          'actedAt', now()::text
        )
      else elem end
      order by ord
    )
      into v_approvers
    from jsonb_array_elements(coalesce(v_req.approvers, '[]'::jsonb)) with ordinality as e(elem, ord);

    update public.request_instances
    set approvers = v_approvers,
        status = 'REJECTED',
        updated_at = now()
    where id = p_request_id
    returning * into v_req;

    insert into public.request_logs(request_id, action, acted_by, comment)
    values (
      p_request_id,
      'REJECTED',
      p_user_id,
      coalesce(nullif(p_comment, ''), 'Từ chối ở bước ' || v_step_order::text)
    );
  else
    raise exception 'unsupported request action: %', p_action;
  end if;

  return v_req;
end;
$$;


ALTER FUNCTION "public"."process_request_step"("p_request_id" "uuid", "p_user_id" "uuid", "p_action" "text", "p_comment" "text") OWNER TO "postgres";


