CREATE OR REPLACE FUNCTION "public"."record_material_issue_settlement"("p_order_id" "uuid", "p_settlement_type" "text", "p_lines" "jsonb", "p_reason" "text", "p_attachments" "jsonb" DEFAULT '[]'::"jsonb") RETURNS "public"."material_issue_orders"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_actor uuid := public.current_app_user_id();
  v_order public.material_issue_orders%rowtype;
  v_line jsonb;
  v_issue_line public.material_issue_lines%rowtype;
  v_qty numeric;
  v_available numeric;
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  if p_settlement_type not in ('consume', 'loss') then raise exception 'Loại quyết toán không hợp lệ.'; end if;
  if coalesce(trim(p_reason), '') = '' then raise exception 'Bắt buộc nhập lý do quyết toán.'; end if;
  select * into v_order from public.material_issue_orders where id = p_order_id for update;
  if not found then raise exception 'Không tìm thấy phiếu xuất cấp.'; end if;
  if v_order.status not in ('issued', 'partially_received', 'received', 'settling', 'partially_returned') then
    raise exception 'Phiếu chưa sẵn sàng quyết toán.';
  end if;
  if not app_private.material_issue_can_process(v_order.source_warehouse_id, v_order.created_by, v_order.responsible_user_id, v_order.recipient_type, v_order.recipient_id) then
    raise exception 'Bạn không có quyền quyết toán phiếu này.';
  end if;

  for v_line in select value from jsonb_array_elements(p_lines)
  loop
    v_qty := coalesce(nullif(v_line ->> 'quantity', '')::numeric, 0);
    if v_qty <= 0 then raise exception 'Số lượng quyết toán phải lớn hơn 0.'; end if;
    select * into v_issue_line from public.material_issue_lines where id = (v_line ->> 'issueLineId')::uuid and issue_order_id = p_order_id for update;
    if not found then raise exception 'Không tìm thấy dòng phiếu xuất cấp.'; end if;
    v_available := greatest(v_issue_line.issued_qty - v_issue_line.returned_qty - v_issue_line.consumed_qty - v_issue_line.lost_qty, 0);
    if v_qty > v_available then raise exception 'Số lượng quyết toán vượt số lượng còn lại.';
    end if;

    if p_settlement_type = 'consume' then
      update public.material_issue_lines set consumed_qty = consumed_qty + v_qty where id = v_issue_line.id;
    else
      update public.material_issue_lines set lost_qty = lost_qty + v_qty where id = v_issue_line.id;
    end if;

    insert into public.material_party_ledger(
      issue_order_id, issue_line_id, source_document_type, source_document_id,
      ledger_type, project_id, construction_site_id, recipient_type, recipient_id,
      recipient_name, item_id, item_name_snapshot, unit, quantity_delta, reason,
      metadata, created_by
    ) values (
      p_order_id, v_issue_line.id, 'material_issue_settlement', gen_random_uuid()::text,
      p_settlement_type, v_order.project_id, v_order.construction_site_id, v_order.recipient_type, v_order.recipient_id,
      v_order.recipient_name, v_issue_line.item_id, v_issue_line.item_name_snapshot, v_issue_line.unit, -v_qty,
      trim(p_reason), jsonb_build_object('attachments', coalesce(p_attachments, '[]'::jsonb)), v_actor
    );
  end loop;

  update public.material_issue_orders set status = 'settling' where id = p_order_id and status not in ('closed', 'cancelled');
  return app_private.material_issue_refresh_status(p_order_id);
end;
$$;


ALTER FUNCTION "public"."record_material_issue_settlement"("p_order_id" "uuid", "p_settlement_type" "text", "p_lines" "jsonb", "p_reason" "text", "p_attachments" "jsonb") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."supplier_direct_delivery_notes" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "code" "text" NOT NULL,
    "project_id" "text",
    "construction_site_id" "text",
    "supplier_contract_id" "text" NOT NULL,
    "supplier_contract_code" "text",
    "supplier_id" "text",
    "supplier_name_snapshot" "text" NOT NULL,
    "delivery_ticket_no" "text" NOT NULL,
    "delivery_date" "date" DEFAULT CURRENT_DATE NOT NULL,
    "vehicle_no" "text",
    "status" "text" DEFAULT 'draft'::"text" NOT NULL,
    "gross_amount" numeric(18,2) DEFAULT 0 NOT NULL,
    "vat_amount" numeric(18,2) DEFAULT 0 NOT NULL,
    "total_amount" numeric(18,2) DEFAULT 0 NOT NULL,
    "attachments" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "qr_token" "text",
    "created_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "note" "text",
    CONSTRAINT "supplier_direct_delivery_notes_check" CHECK ((("project_id" IS NOT NULL) OR ("construction_site_id" IS NOT NULL))),
    CONSTRAINT "supplier_direct_delivery_notes_gross_amount_check" CHECK (("gross_amount" >= (0)::numeric)),
    CONSTRAINT "supplier_direct_delivery_notes_status_check" CHECK (("status" = ANY (ARRAY['draft'::"text", 'submitted'::"text", 'site_confirmed'::"text", 'finance_review'::"text", 'accepted'::"text", 'statemented'::"text", 'rejected'::"text", 'cancelled'::"text"]))),
    CONSTRAINT "supplier_direct_delivery_notes_total_amount_check" CHECK (("total_amount" >= (0)::numeric)),
    CONSTRAINT "supplier_direct_delivery_notes_vat_amount_check" CHECK (("vat_amount" >= (0)::numeric))
);


ALTER TABLE "public"."supplier_direct_delivery_notes" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_supplier_direct_delivery_note"("p_note_id" "uuid", "p_actor_id" "uuid" DEFAULT NULL::"uuid") RETURNS "public"."supplier_direct_delivery_notes"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
declare
  v_note public.supplier_direct_delivery_notes%rowtype;
  v_rows integer;
begin
  select * into v_note
  from public.supplier_direct_delivery_notes
  where id = p_note_id
  for update;

  if not found then
    raise exception 'Không tìm thấy phiếu giao HĐ NCC %. ', p_note_id;
  end if;

  if not app_private.material_flow_has_action_or_legacy(v_note.project_id, v_note.construction_site_id, 'project.material_supplier_delivery.record') then
    raise exception 'Bạn không có quyền ghi phiếu giao HĐ NCC.';
  end if;

  if v_note.status in ('statemented', 'cancelled', 'rejected') then
    raise exception 'Không thể ghi phiếu giao HĐ NCC ở trạng thái hiện tại.';
  end if;

  update public.supplier_direct_delivery_lines
  set status = 'accepted',
      accepted_quantity = quantity,
      accepted_amount = 0,
      unit_price = 0,
      vat_rate = 0,
      line_amount = 0,
      vat_amount = 0,
      total_amount = 0,
      rejection_reason = null,
      updated_at = now()
  where delivery_note_id = p_note_id
    and status <> 'rejected';

  get diagnostics v_rows = row_count;
  if v_rows = 0 then
    raise exception 'Chưa có dòng đã ghi trong phiếu giao HĐ NCC.';
  end if;

  update public.supplier_direct_delivery_notes
  set status = 'accepted',
      gross_amount = 0,
      vat_amount = 0,
      total_amount = 0,
      updated_at = now()
  where id = p_note_id
  returning * into v_note;

  return v_note;
end;
$$;


ALTER FUNCTION "public"."record_supplier_direct_delivery_note"("p_note_id" "uuid", "p_actor_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reject_project_workflow"("p_subject_type" "text", "p_subject_id" "text", "p_comment" "text" DEFAULT ''::"text") RETURNS "public"."workflow_subjects"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_actor uuid := public.current_app_user_id();
  v_subject public.workflow_subjects%rowtype;
  v_request public.requests%rowtype;
  v_node public.workflow_instance_nodes%rowtype;
  v_dependency jsonb;
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  if nullif(coalesce(p_comment, ''), '') is null then raise exception 'reject reason is required'; end if;
  select * into v_subject from public.workflow_subjects ws
  where ws.subject_type = p_subject_type and ws.subject_id = p_subject_id for update;
  if not found then raise exception 'workflow subject not found'; end if;
  select * into v_request from public.requests r where r.id = p_subject_id for update;
  if not found then raise exception 'material request not found: %', p_subject_id; end if;
  if v_subject.status <> 'RUNNING' then raise exception 'workflow subject can only be rejected while running'; end if;
  if not app_private.project_workflow_actor_can_act(v_subject.id, v_actor) then
    raise exception 'user is not allowed to reject this workflow';
  end if;

  select * into v_node from public.workflow_instance_nodes win where win.id = v_subject.current_instance_node_id;
  if not found or coalesce((v_node.config ->> 'allowReject')::boolean, true) = false then
    raise exception 'runtime workflow step does not allow reject';
  end if;
  v_dependency := public.get_project_workflow_rollback_dependencies(p_subject_type, p_subject_id);
  if not coalesce((v_dependency ->> 'allowed')::boolean, false) then
    raise exception 'reject is locked by active downstream dependencies: %', v_dependency;
  end if;

  update public.workflow_step_assignments
  set status = case when assignee_user_id = v_actor then 'REJECTED' else 'SKIPPED' end,
      acted_at = now(), action_comment = p_comment,
      metadata = coalesce(metadata, '{}'::jsonb) || jsonb_build_object('rejectedByUserId', v_actor)
  where workflow_subject_id = v_subject.id
    and workflow_instance_id = v_subject.workflow_instance_id
    and instance_node_id = v_node.id
    and status = 'PENDING';

  insert into public.workflow_instance_logs(instance_id, node_id, action, acted_by, comment)
  values (v_subject.workflow_instance_id, v_node.template_node_id,
    'REJECTED'::public.workflow_instance_action, v_actor, p_comment);

  update public.workflow_instances
  set status = 'REJECTED'::public.workflow_instance_status, updated_at = now()
  where id = v_subject.workflow_instance_id;
  update public.workflow_subjects
  set current_assignee_user_id = null, current_assignee_user_ids = '{}'::uuid[],
      last_action_instance_node_id = v_node.id, status = 'REJECTED', updated_at = now()
  where id = v_subject.id
  returning * into v_subject;
  update public.requests
  set status = 'REJECTED'::public.request_status,
      submitted_to_user_id = null, submitted_to_name = null, submitted_to_permission = null,
      submission_note = p_comment, last_action_by = v_actor, last_action_at = now(),
      workflow_step = 'rejected', workflow_step_started_at = now(),
      workflow_step_due_at = null, workflow_step_sla_hours = null,
      workflow_step_actor_user_id = v_actor::text
  where id = p_subject_id;

  insert into public.material_request_events(
    request_id, project_id, from_step, to_step, action, actor_user_id, note, metadata
  )
  values (
    p_subject_id, v_request.project_id, coalesce(v_request.workflow_step, 'material_department_review'),
    'rejected', 'REJECTED', v_actor::text, p_comment,
    jsonb_build_object(
      'workflowInstanceId', v_subject.workflow_instance_id,
      'workflowSubjectId', v_subject.id,
      'instanceNodeId', v_node.id,
      'rollbackDependencies', v_dependency
    )
  );
  return v_subject;
end;
$$;


ALTER FUNCTION "public"."reject_project_workflow"("p_subject_type" "text", "p_subject_id" "text", "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reject_purchase_order_supplemental_approval"("p_approval_id" "uuid", "p_actor_id" "text" DEFAULT NULL::"text", "p_note" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_approval public.purchase_order_supplemental_approvals%rowtype;
  v_po public.purchase_orders%rowtype;
  v_user_id uuid := public.current_app_user_id();
  v_actor_id text := coalesce(nullif(p_actor_id, ''), v_user_id::text);
  v_previous_guard text;
begin
  select *
    into v_approval
  from public.purchase_order_supplemental_approvals
  where id = p_approval_id
  for update;

  if not found then
    raise exception 'Không tìm thấy yêu cầu duyệt bổ sung PO.';
  end if;

  select *
    into v_po
  from public.purchase_orders
  where id = v_approval.purchase_order_id
  for update;

  if not found then
    raise exception 'Không tìm thấy PO của yêu cầu duyệt bổ sung.';
  end if;

  if not app_private.purchase_order_supplemental_can_approve(v_po.id::text) then
    raise exception 'Bạn cần quyền duyệt PO để từ chối duyệt bổ sung.'
      using errcode = '42501';
  end if;

  v_previous_guard := current_setting('app.material_transition_context', true);
  perform set_config('app.material_transition_context', 'on', true);

  update public.purchase_order_supplemental_approvals
  set status = 'rejected',
      rejected_by = v_actor_id,
      rejected_at = now(),
      approved_by = null,
      approved_at = null,
      decision_note = nullif(p_note, ''),
      last_action_by = v_actor_id,
      last_action_at = now()
  where id = p_approval_id;

  update public.purchase_orders
  set supplemental_approval_status = case
        when exists (
          select 1
          from public.purchase_order_supplemental_approvals pending
          where pending.purchase_order_id = v_po.id
            and pending.id <> p_approval_id
            and pending.status = 'pending'
        ) then 'pending'
        else 'rejected'
      end,
      last_action_by = v_actor_id,
      last_action_at = now()
  where id = v_po.id;

  update public.purchase_order_delivery_batches
  set status = 'supplemental_pending',
      supplemental_approval_id = p_approval_id
  where id = v_approval.delivery_batch_id;

  perform set_config('app.material_transition_context', coalesce(v_previous_guard, ''), true);
exception
  when others then
    perform set_config('app.material_transition_context', coalesce(v_previous_guard, ''), true);
    raise;
end;
$$;


ALTER FUNCTION "public"."reject_purchase_order_supplemental_approval"("p_approval_id" "uuid", "p_actor_id" "text", "p_note" "text") OWNER TO "postgres";


