CREATE OR REPLACE FUNCTION "public"."replace_project_staff_permissions"("p_staff_id" "uuid", "p_permission_type_ids" "uuid"[], "p_granted_by" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
    BEGIN
      DELETE FROM public.project_staff_permissions
      WHERE staff_id = p_staff_id;

      IF COALESCE(array_length(p_permission_type_ids, 1), 0) > 0 THEN
        INSERT INTO public.project_staff_permissions (
          staff_id,
          permission_type_id,
          is_active,
          granted_by
        )
        SELECT
          p_staff_id,
          permission_type_id,
          TRUE,
          p_granted_by
        FROM unnest(p_permission_type_ids) AS permission_type_id;
      END IF;
    END;
    $$;


