CREATE OR REPLACE FUNCTION "public"."resubmit_project_workflow"("p_subject_type" "text", "p_subject_id" "text", "p_assignee_user_id" "uuid" DEFAULT NULL::"uuid", "p_comment" "text" DEFAULT ''::"text") RETURNS "public"."workflow_subjects"
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
  select public.resubmit_project_workflow_v2(
    p_subject_type, p_subject_id,
    case when p_assignee_user_id is null then null else array[p_assignee_user_id] end,
    p_comment
  );
$$;


ALTER FUNCTION "public"."resubmit_project_workflow"("p_subject_type" "text", "p_subject_id" "text", "p_assignee_user_id" "uuid", "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resubmit_project_workflow_v2"("p_subject_type" "text", "p_subject_id" "text", "p_assignee_user_ids" "uuid"[] DEFAULT NULL::"uuid"[], "p_comment" "text" DEFAULT ''::"text") RETURNS "public"."workflow_subjects"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_actor uuid := public.current_app_user_id();
  v_subject public.workflow_subjects%rowtype;
  v_request public.requests%rowtype;
  v_target_node public.workflow_instance_nodes%rowtype;
  v_target_assignee_ids uuid[];
  v_first_assignee uuid;
  v_assignee_name text;
  v_sla_hours integer;
  v_due_at timestamptz;
  v_to_step text;
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  select * into v_subject from public.workflow_subjects ws
  where ws.subject_type = p_subject_type and ws.subject_id = p_subject_id for update;
  if not found then raise exception 'workflow subject not found'; end if;
  select * into v_request from public.requests r where r.id = p_subject_id for update;
  if not found then raise exception 'material request not found: %', p_subject_id; end if;
  if v_subject.status <> 'RETURNED' then raise exception 'workflow subject is not returned'; end if;
  if v_request.requester_id::uuid <> v_actor then
    raise exception 'only requester can resubmit this material request';
  end if;

  select * into v_target_node
  from public.workflow_instance_nodes win
  where win.id = coalesce(v_subject.return_to_instance_node_id, v_subject.current_instance_node_id)
    and win.workflow_instance_id = v_subject.workflow_instance_id;
  if not found or v_target_node.type = 'END'::public.workflow_node_type then
    raise exception 'return runtime workflow node not found';
  end if;

  v_target_assignee_ids := app_private.project_workflow_distinct_uuid_array(
    coalesce(p_assignee_user_ids, v_subject.return_to_assignee_user_ids)
  );
  if not app_private.project_workflow_runtime_assignees_are_eligible(
    p_subject_type, p_subject_id, v_target_node.id, v_target_assignee_ids
  ) then
    raise exception 'resubmit assignee pool is not eligible for this runtime workflow step';
  end if;

  update public.workflow_step_assignments
  set status = 'APPROVED', acted_at = now(),
      action_comment = nullif(coalesce(p_comment, ''), ''),
      metadata = coalesce(metadata, '{}'::jsonb) || jsonb_build_object('resubmittedByCreator', true)
  where workflow_subject_id = v_subject.id
    and workflow_instance_id = v_subject.workflow_instance_id
    and assignee_user_id = v_request.requester_id::uuid
    and status = 'PENDING'
    and assignment_source = 'return_to_creator';

  perform app_private.project_workflow_insert_assignment_pool(
    v_subject.id, v_subject.workflow_instance_id, v_target_node.template_node_id, v_target_node.id,
    v_target_assignee_ids, v_actor, p_comment,
    jsonb_build_object('resubmitted', true, 'approvalPolicy', 'ANY_ONE'), 'resubmit'
  );

  insert into public.workflow_instance_logs(instance_id, node_id, action, acted_by, comment)
  values (v_subject.workflow_instance_id, v_target_node.template_node_id,
    'REOPENED'::public.workflow_instance_action, v_actor, coalesce(p_comment, ''));

  v_first_assignee := v_target_assignee_ids[1];
  v_assignee_name := app_private.project_workflow_first_assignee_name(v_target_assignee_ids);
  v_sla_hours := app_private.project_workflow_runtime_sla_hours(v_target_node.id);
  v_due_at := app_private.project_workflow_runtime_sla_due_at(v_target_node.id);
  v_to_step := app_private.project_workflow_runtime_to_coarse_step(v_subject.workflow_instance_id, v_target_node.id);

  update public.workflow_instances
  set current_node_id = v_target_node.template_node_id,
      current_instance_node_id = v_target_node.id,
      status = 'RUNNING'::public.workflow_instance_status,
      step_assignees = coalesce(step_assignees, '{}'::jsonb)
        || app_private.project_workflow_step_assignees_json(v_target_node.template_node_id, v_target_assignee_ids),
      updated_at = now()
  where id = v_subject.workflow_instance_id;

  update public.workflow_subjects
  set current_assignee_user_id = v_first_assignee,
      current_assignee_user_ids = v_target_assignee_ids,
      current_node_id = v_target_node.template_node_id,
      current_instance_node_id = v_target_node.id,
      status = 'RUNNING',
      return_to_node_id = null, return_to_instance_node_id = null,
      return_to_assignee_user_id = null, return_to_assignee_user_ids = '{}'::uuid[],
      returned_by_user_id = null, returned_at = null, updated_at = now()
  where id = v_subject.id
  returning * into v_subject;

  update public.requests
  set status = 'PENDING'::public.request_status,
      submitted_to_user_id = v_first_assignee::text, submitted_to_name = v_assignee_name,
      submitted_to_permission = app_private.project_workflow_runtime_primary_permission(v_target_node.id),
      submission_note = nullif(coalesce(p_comment, ''), ''), ever_submitted = true,
      last_action_by = v_actor, last_action_at = now(),
      workflow_step = v_to_step, workflow_step_started_at = now(),
      workflow_step_due_at = v_due_at, workflow_step_sla_hours = v_sla_hours,
      workflow_step_actor_user_id = v_actor::text
  where id = p_subject_id;

  insert into public.material_request_events(
    request_id, project_id, from_step, to_step, action, actor_user_id,
    target_user_id, target_permission, note, sla_hours, due_at, metadata
  )
  values (
    p_subject_id, v_request.project_id, coalesce(v_request.workflow_step, 'returned_to_creator'),
    v_to_step, 'RESUBMITTED', v_actor::text, v_first_assignee::text,
    app_private.project_workflow_runtime_primary_permission(v_target_node.id),
    nullif(coalesce(p_comment, ''), ''), v_sla_hours, v_due_at,
    jsonb_build_object(
      'workflowInstanceId', v_subject.workflow_instance_id,
      'workflowSubjectId', v_subject.id,
      'toInstanceNodeId', v_target_node.id,
      'assigneeUserIds', v_target_assignee_ids
    )
  );
  return v_subject;
end;
$$;


ALTER FUNCTION "public"."resubmit_project_workflow_v2"("p_subject_type" "text", "p_subject_id" "text", "p_assignee_user_ids" "uuid"[], "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."return_project_workflow"("p_subject_type" "text", "p_subject_id" "text", "p_comment" "text" DEFAULT ''::"text") RETURNS "public"."workflow_subjects"
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
  select public.return_project_workflow_v2(p_subject_type, p_subject_id, p_comment);
$$;


ALTER FUNCTION "public"."return_project_workflow"("p_subject_type" "text", "p_subject_id" "text", "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."return_project_workflow_v2"("p_subject_type" "text", "p_subject_id" "text", "p_comment" "text" DEFAULT ''::"text") RETURNS "public"."workflow_subjects"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_actor uuid := public.current_app_user_id();
  v_subject public.workflow_subjects%rowtype;
  v_request public.requests%rowtype;
  v_requester_id uuid;
  v_requester_name text;
  v_return_assignee_ids uuid[];
  v_round_id uuid := gen_random_uuid();
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  if nullif(coalesce(p_comment, ''), '') is null then raise exception 'return reason is required'; end if;

  select * into v_subject from public.workflow_subjects ws
  where ws.subject_type = p_subject_type and ws.subject_id = p_subject_id for update;
  if not found then raise exception 'workflow subject not found'; end if;
  select * into v_request from public.requests r where r.id = p_subject_id for update;
  if not found then raise exception 'material request not found: %', p_subject_id; end if;
  if v_subject.status <> 'RUNNING' then raise exception 'workflow subject is not running'; end if;
  if not app_private.project_workflow_actor_can_act(v_subject.id, v_actor) then
    raise exception 'user is not assigned to current workflow step';
  end if;

  v_requester_id := v_request.requester_id::uuid;
  v_return_assignee_ids := app_private.project_workflow_pending_assignee_ids(v_subject.id, v_subject.current_node_id);

  update public.workflow_step_assignments
  set status = case when assignee_user_id = v_actor then 'RETURNED' else 'SKIPPED' end,
      acted_at = now(), action_comment = p_comment, return_to_node_id = v_subject.current_node_id,
      metadata = coalesce(metadata, '{}'::jsonb) || jsonb_build_object(
        'returnedToCreator', true, 'returnedByUserId', v_actor,
        'returnToInstanceNodeId', v_subject.current_instance_node_id,
        'returnToAssigneeUserIds', v_return_assignee_ids
      )
  where workflow_subject_id = v_subject.id
    and workflow_instance_id = v_subject.workflow_instance_id
    and instance_node_id = v_subject.current_instance_node_id
    and status = 'PENDING';

  insert into public.workflow_step_assignments(
    workflow_subject_id, workflow_instance_id, node_id, instance_node_id,
    assignee_user_id, assigned_by, status, assigned_at, action_comment,
    assignment_source, assignment_round_id, metadata
  )
  values (
    v_subject.id, v_subject.workflow_instance_id, v_subject.current_node_id,
    v_subject.current_instance_node_id, v_requester_id, v_actor, 'PENDING', now(),
    p_comment, 'return_to_creator', v_round_id,
    jsonb_build_object(
      'returnedToCreator', true, 'returnToInstanceNodeId', v_subject.current_instance_node_id,
      'returnToAssigneeUserIds', v_return_assignee_ids, 'assignmentRoundId', v_round_id
    )
  );

  perform app_private.project_workflow_register_participant(
    v_subject.id, v_subject.workflow_instance_id, v_requester_id, 'CREATOR',
    'return_to_creator', p_subject_id, v_subject.current_node_id,
    v_subject.current_instance_node_id, v_actor
  );

  insert into public.workflow_instance_logs(instance_id, node_id, action, acted_by, comment)
  values (v_subject.workflow_instance_id, v_subject.current_node_id,
    'REVISION_REQUESTED'::public.workflow_instance_action, v_actor, p_comment);

  select u.name into v_requester_name from public.users u where u.id = v_requester_id;

  update public.workflow_subjects
  set current_assignee_user_id = v_requester_id,
      current_assignee_user_ids = array[v_requester_id],
      status = 'RETURNED',
      return_to_node_id = v_subject.current_node_id,
      return_to_instance_node_id = v_subject.current_instance_node_id,
      return_to_assignee_user_id = v_return_assignee_ids[1],
      return_to_assignee_user_ids = v_return_assignee_ids,
      returned_by_user_id = v_actor, returned_at = now(), updated_at = now()
  where id = v_subject.id
  returning * into v_subject;

  update public.requests
  set status = 'DRAFT'::public.request_status,
      submitted_to_user_id = v_requester_id::text, submitted_to_name = v_requester_name,
      submitted_to_permission = 'edit', submission_note = p_comment,
      last_action_by = v_actor, last_action_at = now(),
      workflow_step = 'returned_to_creator', workflow_step_started_at = now(),
      workflow_step_due_at = null, workflow_step_sla_hours = null,
      workflow_step_actor_user_id = v_actor::text
  where id = p_subject_id;

  insert into public.material_request_events(
    request_id, project_id, from_step, to_step, action, actor_user_id,
    target_user_id, target_permission, note, metadata
  )
  values (
    p_subject_id, v_request.project_id, coalesce(v_request.workflow_step, 'material_department_review'),
    'returned_to_creator', 'RETURNED', v_actor::text, v_requester_id::text, 'edit',
    p_comment, jsonb_build_object(
      'workflowInstanceId', v_subject.workflow_instance_id,
      'workflowSubjectId', v_subject.id,
      'returnToInstanceNodeId', v_subject.return_to_instance_node_id,
      'returnToAssigneeUserIds', v_return_assignee_ids
    )
  );
  return v_subject;
end;
$$;


ALTER FUNCTION "public"."return_project_workflow_v2"("p_subject_type" "text", "p_subject_id" "text", "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reverse_site_cash_settlement_batch"("p_batch_id" "uuid", "p_actor_id" "uuid" DEFAULT NULL::"uuid") RETURNS "public"."site_cash_settlement_batches"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
declare
  v_batch public.site_cash_settlement_batches%rowtype;
  v_reversal_ref text;
  v_actor_id uuid;
begin
  select * into v_batch
  from public.site_cash_settlement_batches
  where id = p_batch_id
  for update;

  if not found then
    raise exception 'Không tìm thấy bộ hoàn ứng %. ', p_batch_id;
  end if;

  if not app_private.ap_scope_can_mutate(v_batch.project_id, v_batch.construction_site_id) then
    raise exception 'Bạn không có quyền đảo bộ hoàn ứng này.';
  end if;

  if v_batch.status not in ('approved', 'closed') then
    raise exception 'Chỉ đảo được bộ hoàn ứng đã duyệt/đóng.';
  end if;

  v_actor_id := coalesce(p_actor_id, v_batch.approved_by, v_batch.created_by);

  v_reversal_ref := 'site_cash_settlement_batch:' || p_batch_id::text || ':reversal';

  if coalesce(v_batch.approved_site_cash_spend, 0) + coalesce(v_batch.staff_reimbursed_amount, 0) > 0 then
    insert into public.project_transactions (
      id, "projectFinanceId", "constructionSiteId", project_id, project_finance_id, construction_site_id,
      type, category, amount, description, date, source, "sourceRef", source_ref,
      attachments, "createdBy", "createdAt"
    )
    values (
      'site-cash-settlement-reversal-' || p_batch_id::text,
      coalesce((
        select id from public.project_finances
        where (v_batch.project_id is not null and project_id = v_batch.project_id)
           or (v_batch.construction_site_id is not null and construction_site_id = v_batch.construction_site_id)
        limit 1
      ), ''),
      coalesce(v_batch.construction_site_id, ''),
      v_batch.project_id,
      (
        select id from public.project_finances
        where (v_batch.project_id is not null and project_id = v_batch.project_id)
           or (v_batch.construction_site_id is not null and construction_site_id = v_batch.construction_site_id)
        limit 1
      ),
      v_batch.construction_site_id,
      'expense',
      'materials',
      -(coalesce(v_batch.approved_site_cash_spend, 0) + coalesce(v_batch.staff_reimbursed_amount, 0)),
      'Đảo hoàn ứng/quỹ công trường ' || v_batch.code,
      current_date::text,
      'workflow',
      v_reversal_ref,
      v_reversal_ref,
      '[]'::jsonb,
      v_actor_id::text,
      now()
    )
    on conflict (source_ref) do nothing;
  end if;

  update public.site_direct_purchases purchase
  set site_cash_settlement_id = null, updated_at = now()
  where site_cash_settlement_id = p_batch_id;

  with credit_deltas as (
    select
      payable.id,
      coalesce((payable.metadata->'siteCashSettlementCredits'->>p_batch_id::text)::numeric, 0)::numeric(18,2) as credit_delta
    from public.supplier_payable_documents payable
    where payable.id in (
      select payable_document_id
      from public.site_cash_settlement_lines
      where settlement_batch_id = p_batch_id
        and payable_document_id is not null
    )
  )
  update public.supplier_payable_documents payable
  set
    credit_amount = greatest(0, payable.credit_amount - credit_deltas.credit_delta)::numeric(18,2),
    metadata = (payable.metadata #- (array['siteCashSettlementCredits', p_batch_id::text]::text[]))
      || jsonb_build_object('lastSiteCashSettlementReversal', p_batch_id, 'lastSiteCashSettlementReversedAt', now()),
    updated_at = now()
  from credit_deltas
  where payable.id = credit_deltas.id
    and credit_deltas.credit_delta > 0;

  update public.supplier_payable_documents payable
  set
    status = case
      when balance.outstanding_amount <= 0 then 'paid'
      when balance.paid_amount > 0 or payable.credit_amount > 0 then 'partial'
      when payable.recognized_amount > 0 then 'open'
      else 'draft'
    end,
    updated_at = now()
  from public.supplier_payable_document_balances balance
  where balance.id = payable.id
    and payable.id in (
      select payable_document_id
      from public.site_cash_settlement_lines
      where settlement_batch_id = p_batch_id
        and payable_document_id is not null
    );

  update public.cash_vouchers
  set status = 'cancelled', note = coalesce(note, '') || ' | Đảo bộ hoàn ứng ' || v_batch.code
  where id = v_batch.cash_voucher_id;

  update public.site_cash_settlement_batches
  set
    status = 'reversed',
    metadata = metadata || jsonb_build_object('reversedBy', v_actor_id, 'reversedAt', now()),
    updated_at = now()
  where id = p_batch_id
  returning * into v_batch;

  return v_batch;
end;
$$;


ALTER FUNCTION "public"."reverse_site_cash_settlement_batch"("p_batch_id" "uuid", "p_actor_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reverse_supplier_delivery_statement"("p_statement_id" "uuid", "p_actor_id" "uuid" DEFAULT NULL::"uuid") RETURNS "public"."supplier_delivery_statements"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
declare
  v_statement public.supplier_delivery_statements%rowtype;
begin
  select * into v_statement
  from public.supplier_delivery_statements
  where id = p_statement_id
  for update;

  if not found then
    raise exception 'Không tìm thấy bảng đối soát HĐ NCC %. ', p_statement_id;
  end if;

  if not app_private.ap_scope_can_mutate(v_statement.project_id, v_statement.construction_site_id) then
    raise exception 'Bạn không có quyền đảo bảng đối soát này.';
  end if;

  if v_statement.status <> 'posted' then
    raise exception 'Chỉ đảo được bảng đối soát đã post.';
  end if;

  if exists (
    select 1
    from public.supplier_payment_allocations a
    join public.supplier_payment_batches b on b.id = a.payment_batch_id
    where a.payable_document_id = v_statement.payable_document_id
      and b.status = 'paid'
  ) then
    raise exception 'Bảng đối soát đã có thanh toán paid. Hãy đảo thanh toán trước.';
  end if;

  update public.supplier_payable_documents
  set status = 'reversed', updated_at = now()
  where id = v_statement.payable_document_id;

  update public.supplier_direct_delivery_lines dl
  set statement_id = null, updated_at = now()
  where dl.statement_id = p_statement_id;

  update public.supplier_direct_delivery_notes note
  set status = 'accepted', updated_at = now()
  where exists (
    select 1
    from public.supplier_delivery_statement_lines sl
    where sl.statement_id = p_statement_id
      and sl.delivery_note_id = note.id
  )
  and status = 'statemented';

  update public.supplier_delivery_statements
  set
    status = 'reversed',
    metadata = metadata || jsonb_build_object('reversedBy', p_actor_id, 'reversedAt', now()),
    updated_at = now()
  where id = p_statement_id
  returning * into v_statement;

  return v_statement;
end;
$$;


ALTER FUNCTION "public"."reverse_supplier_delivery_statement"("p_statement_id" "uuid", "p_actor_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reverse_supplier_payment_batch"("p_batch_id" "uuid", "p_actor_id" "uuid" DEFAULT NULL::"uuid") RETURNS "public"."supplier_payment_batches"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
declare
  v_batch public.supplier_payment_batches%rowtype;
  v_reversal_ref text;
begin
  select * into v_batch
  from public.supplier_payment_batches
  where id = p_batch_id
  for update;

  if not found then
    raise exception 'Không tìm thấy đợt thanh toán %. ', p_batch_id;
  end if;

  if not app_private.ap_scope_can_mutate(v_batch.project_id, v_batch.construction_site_id) then
    raise exception 'Bạn không có quyền đảo đợt thanh toán này.';
  end if;

  if v_batch.status <> 'paid' then
    raise exception 'Chỉ đảo được đợt thanh toán đã paid.';
  end if;

  v_reversal_ref := 'supplier_payment_batch:' || p_batch_id::text || ':reversal';

  insert into public.project_transactions (
    id, "projectFinanceId", "constructionSiteId", project_id, project_finance_id, construction_site_id,
    type, category, amount, description, date, source, "sourceRef", source_ref,
    attachments, "createdBy", "createdAt"
  )
  values (
    'supplier-payment-reversal-' || p_batch_id::text,
    coalesce((
      select id from public.project_finances
      where (v_batch.project_id is not null and project_id = v_batch.project_id)
         or (v_batch.construction_site_id is not null and construction_site_id = v_batch.construction_site_id)
      limit 1
    ), ''),
    coalesce(v_batch.construction_site_id, ''),
    v_batch.project_id,
    (
      select id from public.project_finances
      where (v_batch.project_id is not null and project_id = v_batch.project_id)
         or (v_batch.construction_site_id is not null and construction_site_id = v_batch.construction_site_id)
      limit 1
    ),
    v_batch.construction_site_id,
    'expense',
    'materials',
    -v_batch.payment_amount,
    'Đảo thanh toán NCC ' || v_batch.supplier_name_snapshot || ' - ' || v_batch.code,
    current_date::text,
    'workflow',
    v_reversal_ref,
    v_reversal_ref,
    '[]'::jsonb,
    p_actor_id::text,
    now()
  )
  on conflict (source_ref) do nothing;

  update public.supplier_payment_batches
  set
    status = 'reversed',
    updated_at = now(),
    metadata = metadata || jsonb_build_object('reversedBy', p_actor_id, 'reversedAt', now())
  where id = p_batch_id
  returning * into v_batch;

  update public.supplier_payable_documents d
  set
    status = case
      when b.outstanding_amount <= 0 then 'paid'
      when b.paid_amount > 0 then 'partial'
      when d.recognized_amount > 0 then 'open'
      else 'draft'
    end,
    updated_at = now()
  from public.supplier_payable_document_balances b
  where b.id = d.id
    and d.id in (
      select payable_document_id
      from public.supplier_payment_allocations
      where payment_batch_id = p_batch_id
    );

  return v_batch;
end;
$$;


ALTER FUNCTION "public"."reverse_supplier_payment_batch"("p_batch_id" "uuid", "p_actor_id" "uuid") OWNER TO "postgres";


