CREATE OR REPLACE FUNCTION "public"."start_project_workflow"("p_subject_type" "text", "p_subject_id" "text", "p_template_id" "uuid" DEFAULT NULL::"uuid", "p_first_assignee_user_id" "uuid" DEFAULT NULL::"uuid", "p_comment" "text" DEFAULT ''::"text") RETURNS "public"."workflow_subjects"
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
  select public.start_project_workflow_v2(
    p_subject_type, p_subject_id, p_template_id,
    case when p_first_assignee_user_id is null then '{}'::uuid[] else array[p_first_assignee_user_id] end,
    p_comment
  );
$$;


ALTER FUNCTION "public"."start_project_workflow"("p_subject_type" "text", "p_subject_id" "text", "p_template_id" "uuid", "p_first_assignee_user_id" "uuid", "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."start_project_workflow_v2"("p_subject_type" "text", "p_subject_id" "text", "p_template_id" "uuid" DEFAULT NULL::"uuid", "p_first_assignee_user_ids" "uuid"[] DEFAULT '{}'::"uuid"[], "p_comment" "text" DEFAULT ''::"text") RETURNS "public"."workflow_subjects"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_request public.requests%rowtype;
  v_config jsonb;
  v_effective_template_id uuid;
  v_subject public.workflow_subjects%rowtype;
  v_pending public.workflow_step_assignments%rowtype;
begin
  if public.current_app_user_id() is null then raise exception 'authentication required'; end if;
  select * into v_request from public.requests r where r.id = p_subject_id;
  if not found then raise exception 'material request not found: %', p_subject_id; end if;

  v_config := public.get_project_workflow_configuration(
    p_subject_type, v_request.project_id, v_request.construction_site_id
  );
  if not coalesce((v_config ->> 'valid')::boolean, false) then
    raise exception 'material request workflow is not configured or invalid: %', v_config -> 'errors';
  end if;
  v_effective_template_id := (v_config -> 'binding' ->> 'workflow_template_id')::uuid;
  if p_template_id is not null and p_template_id <> v_effective_template_id then
    raise exception 'selected workflow template is not the effective project binding';
  end if;

  v_subject := public.start_project_workflow_v2_legacy(
    p_subject_type, p_subject_id, v_effective_template_id,
    p_first_assignee_user_ids, p_comment
  );

  select * into v_pending
  from public.workflow_step_assignments wsa
  where wsa.workflow_subject_id = v_subject.id
    and wsa.instance_node_id = v_subject.current_instance_node_id
    and wsa.status = 'PENDING'
  order by wsa.assigned_at desc
  limit 1;

  update public.requests
  set submitted_to_permission = app_private.project_workflow_runtime_primary_permission(v_subject.current_instance_node_id),
      workflow_step_due_at = v_pending.due_at,
      workflow_step_sla_hours = v_pending.sla_hours
  where id = p_subject_id;

  return v_subject;
end;
$$;


ALTER FUNCTION "public"."start_project_workflow_v2"("p_subject_type" "text", "p_subject_id" "text", "p_template_id" "uuid", "p_first_assignee_user_ids" "uuid"[], "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."start_project_workflow_v2_legacy"("p_subject_type" "text", "p_subject_id" "text", "p_template_id" "uuid" DEFAULT NULL::"uuid", "p_first_assignee_user_ids" "uuid"[] DEFAULT '{}'::"uuid"[], "p_comment" "text" DEFAULT ''::"text") RETURNS "public"."workflow_subjects"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_actor uuid := public.current_app_user_id();
  v_request public.requests%rowtype;
  v_template_id uuid;
  v_template public.workflow_templates%rowtype;
  v_template_version_id uuid;
  v_start_node_id uuid;
  v_first_node_id uuid;
  v_first_instance_node_id uuid;
  v_instance public.workflow_instances%rowtype;
  v_subject public.workflow_subjects%rowtype;
  v_assignee_ids uuid[] := app_private.project_workflow_distinct_uuid_array(p_first_assignee_user_ids);
  v_first_assignee uuid;
  v_assignee_name text;
  v_sla_hours integer;
  v_due_at timestamptz;
  v_manager text;
  v_watcher text;
  v_next_code text;
begin
  if v_actor is null then
    raise exception 'authentication required';
  end if;
  if p_subject_type <> 'material_request' then
    raise exception 'unsupported project workflow subject type: %', p_subject_type;
  end if;

  select *
    into v_request
  from public.requests
  where id = p_subject_id
  for update;

  if not found then
    raise exception 'material request not found: %', p_subject_id;
  end if;

  if not (
    public.is_admin()
    or public.is_module_admin('WF')
    or v_request.requester_id::uuid = v_actor
    or app_private.project_workflow_binding_can_manage(v_request.project_id, v_request.construction_site_id)
  ) then
    raise exception 'user cannot start workflow for this material request';
  end if;

  v_template_id := coalesce(
    p_template_id,
    v_request.workflow_template_id,
    app_private.project_workflow_resolve_template(p_subject_type, v_request.project_id, v_request.construction_site_id)
  );

  if v_template_id is null then
    raise exception 'project workflow binding/template not found';
  end if;

  select *
    into v_template
  from public.workflow_templates
  where id = v_template_id
    and coalesce(is_active, true);

  if not found then
    raise exception 'workflow template is not active: %', v_template_id;
  end if;

  if exists (
    select 1
    from public.workflow_subjects ws
    where ws.subject_type = p_subject_type
      and ws.subject_id = p_subject_id
      and ws.status in ('RUNNING', 'RETURNED')
  ) then
    raise exception 'workflow is already running for this material request';
  end if;

  v_start_node_id := app_private.project_workflow_start_node(v_template_id);
  v_first_node_id := app_private.project_workflow_first_task_node(v_template_id);
  if v_start_node_id is null or v_first_node_id is null then
    raise exception 'workflow template must have START and first task nodes';
  end if;

  if not app_private.project_workflow_assignees_are_eligible(p_subject_type, p_subject_id, v_first_node_id, v_assignee_ids) then
    raise exception 'first assignee pool is not eligible for this workflow step';
  end if;

  v_first_assignee := v_assignee_ids[1];
  v_assignee_name := app_private.project_workflow_first_assignee_name(v_assignee_ids);
  v_sla_hours := app_private.project_workflow_node_sla_hours(v_first_node_id);
  v_due_at := app_private.project_workflow_node_sla_due_at(v_first_node_id);
  v_template_version_id := app_private.project_workflow_ensure_template_version(v_template_id, v_actor);

  v_next_code := public.next_workflow_code();

  insert into public.workflow_instances(
    template_id,
    code,
    title,
    created_by,
    current_node_id,
    status,
    form_data,
    watchers,
    step_assignees,
    template_version_id
  )
  values (
    v_template_id,
    v_next_code,
    coalesce(v_request.code, 'MR') || ' - Đề xuất vật tư',
    v_actor,
    v_first_node_id,
    'RUNNING'::public.workflow_instance_status,
    jsonb_build_object('subjectType', p_subject_type, 'subjectId', p_subject_id),
    coalesce(v_template.default_watchers, '{}'::text[]),
    app_private.project_workflow_step_assignees_json(v_first_node_id, v_assignee_ids),
    v_template_version_id
  )
  returning * into v_instance;

  perform app_private.project_workflow_snapshot_instance(v_instance.id, v_template_version_id, v_template_id);
  v_first_instance_node_id := app_private.project_workflow_instance_node_for_template(v_instance.id, v_first_node_id);

  update public.workflow_instances
  set current_instance_node_id = v_first_instance_node_id,
      updated_at = now()
  where id = v_instance.id
  returning * into v_instance;

  insert into public.workflow_instance_logs(instance_id, node_id, action, acted_by, comment)
  values (v_instance.id, v_start_node_id, 'SUBMITTED'::public.workflow_instance_action, v_actor, coalesce(p_comment, ''));

  insert into public.workflow_subjects(
    workflow_instance_id,
    subject_type,
    subject_id,
    project_id,
    construction_site_id,
    current_assignee_user_id,
    current_assignee_user_ids,
    current_node_id,
    current_instance_node_id,
    template_version_id,
    status,
    created_by
  )
  values (
    v_instance.id,
    p_subject_type,
    p_subject_id,
    v_request.project_id,
    v_request.construction_site_id,
    v_first_assignee,
    v_assignee_ids,
    v_first_node_id,
    v_first_instance_node_id,
    v_template_version_id,
    'RUNNING',
    v_actor
  )
  on conflict (subject_type, subject_id) do update
  set workflow_instance_id = excluded.workflow_instance_id,
      project_id = excluded.project_id,
      construction_site_id = excluded.construction_site_id,
      current_assignee_user_id = excluded.current_assignee_user_id,
      current_assignee_user_ids = excluded.current_assignee_user_ids,
      current_node_id = excluded.current_node_id,
      current_instance_node_id = excluded.current_instance_node_id,
      template_version_id = excluded.template_version_id,
      status = excluded.status,
      updated_at = now()
  returning * into v_subject;

  perform app_private.project_workflow_register_participant(v_subject.id, v_instance.id, v_actor, 'CREATOR', 'requester', p_subject_id, null, null, v_actor);

  foreach v_manager in array coalesce(v_template.managers, '{}'::text[]) loop
    if nullif(v_manager, '') is not null then
      perform app_private.project_workflow_register_participant(v_subject.id, v_instance.id, v_manager::uuid, 'ADMIN', 'template_manager', v_template_id::text, null, null, v_actor);
    end if;
  end loop;

  foreach v_watcher in array coalesce(v_template.default_watchers, '{}'::text[]) loop
    if nullif(v_watcher, '') is not null then
      perform app_private.project_workflow_register_participant(v_subject.id, v_instance.id, v_watcher::uuid, 'WATCHER', 'template_watcher', v_template_id::text, null, null, v_actor);
    end if;
  end loop;

  perform app_private.project_workflow_insert_assignment_pool(
    v_subject.id,
    v_instance.id,
    v_first_node_id,
    v_first_instance_node_id,
    v_assignee_ids,
    v_actor,
    p_comment,
    jsonb_build_object('submitted', true, 'approvalPolicy', 'ANY_ONE'),
    'start'
  );

  update public.requests
  set status = 'PENDING'::public.request_status,
      submitted_to_user_id = v_first_assignee::text,
      submitted_to_name = v_assignee_name,
      submitted_to_permission = app_private.project_workflow_node_primary_permission(v_first_node_id),
      submission_note = nullif(coalesce(p_comment, ''), ''),
      ever_submitted = true,
      last_action_by = v_actor,
      last_action_at = now(),
      workflow_step = 'site_manager_review',
      workflow_step_started_at = now(),
      workflow_step_due_at = v_due_at,
      workflow_step_sla_hours = v_sla_hours,
      workflow_step_actor_user_id = v_actor::text,
      workflow_instance_id = v_instance.id,
      workflow_subject_id = v_subject.id,
      workflow_template_id = v_template_id
  where id = p_subject_id;

  insert into public.material_request_events(
    request_id,
    project_id,
    from_step,
    to_step,
    action,
    actor_user_id,
    target_user_id,
    target_permission,
    note,
    sla_hours,
    due_at,
    metadata
  )
  values (
    p_subject_id,
    v_request.project_id,
    coalesce(v_request.workflow_step, 'draft'),
    'site_manager_review',
    'SUBMITTED',
    v_actor::text,
    v_first_assignee::text,
    app_private.project_workflow_node_primary_permission(v_first_node_id),
    nullif(coalesce(p_comment, ''), ''),
    v_sla_hours,
    v_due_at,
    jsonb_build_object(
      'workflowInstanceId', v_instance.id,
      'workflowSubjectId', v_subject.id,
      'templateVersionId', v_template_version_id,
      'toNodeId', v_first_node_id,
      'assigneeUserIds', v_assignee_ids
    )
  );

  return v_subject;
end;
$$;


ALTER FUNCTION "public"."start_project_workflow_v2_legacy"("p_subject_type" "text", "p_subject_id" "text", "p_template_id" "uuid", "p_first_assignee_user_ids" "uuid"[], "p_comment" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."submit_material_issue_order"("p_order_id" "uuid", "p_override_reason" "text" DEFAULT NULL::"text") RETURNS "public"."material_issue_orders"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_actor uuid := public.current_app_user_id();
  v_order public.material_issue_orders%rowtype;
  v_transaction_id text := 'tx-material-issue-' || replace(gen_random_uuid()::text, '-', '');
  v_items jsonb := '[]'::jsonb;
  v_line record;
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  select * into v_order from public.material_issue_orders where id = p_order_id for update;
  if not found then raise exception 'Không tìm thấy phiếu xuất cấp.'; end if;
  if v_order.status not in ('draft', 'submitted') then raise exception 'Chỉ gửi duyệt phiếu ở trạng thái nháp.'; end if;
  if not (
    public.is_admin()
    or public.is_module_admin('WMS')
    or v_order.created_by = v_actor
    or app_private.material_issue_can_manage_project(v_order.project_id, v_order.construction_site_id)
  ) then
    raise exception 'Bạn không có quyền gửi phiếu xuất cấp này.';
  end if;

  for v_line in
    select * from public.material_issue_lines where issue_order_id = p_order_id order by created_at
  loop
    if v_line.approved_qty <= 0 then raise exception 'Phiếu có dòng số lượng không hợp lệ.'; end if;
    v_items := v_items || jsonb_build_array(jsonb_build_object(
      'itemId', v_line.item_id,
      'quantity', v_line.approved_qty,
      'price', v_line.unit_price,
      'materialIssueOrderId', v_order.id,
      'materialIssueLineId', v_line.id,
      'recipientType', v_order.recipient_type,
      'recipientNameSnapshot', v_order.recipient_name
    ));
  end loop;

  if jsonb_array_length(v_items) = 0 then raise exception 'Phiếu xuất cấp chưa có dòng vật tư.'; end if;

  insert into public.transactions(
    id, type, date, items, source_warehouse_id, target_warehouse_id,
    requester_id, approver_id, status, note, related_request_id, pending_items
  ) values (
    v_transaction_id, 'EXPORT', now(), v_items, v_order.source_warehouse_id, null,
    v_actor, null, 'PENDING',
    'Xuất cấp thi công ' || v_order.issue_no || ' cho ' || v_order.recipient_name,
    v_order.material_request_id, '[]'::jsonb
  );

  update public.material_issue_orders
  set status = 'wms_pending',
      transaction_id = v_transaction_id,
      submitted_by = v_actor,
      submitted_at = now(),
      override_reason = nullif(trim(coalesce(p_override_reason, '')), '')
  where id = p_order_id
  returning * into v_order;

  if to_regclass('public.project_document_links') is not null then
    if v_order.material_request_id is not null then
      insert into public.project_document_links(source_type, source_id, target_type, target_id, project_id, relation_type, status, metadata)
      values ('material_request', v_order.material_request_id, 'material_issue_order', v_order.id::text, v_order.project_id, 'downstream', 'active', jsonb_build_object('issueNo', v_order.issue_no, 'transactionId', v_transaction_id))
      on conflict (source_type, source_id, target_type, target_id, relation_type)
      do update set status = excluded.status, metadata = excluded.metadata, updated_at = now();
    end if;

    insert into public.project_document_links(source_type, source_id, target_type, target_id, project_id, relation_type, status, metadata)
    values ('material_issue_order', v_order.id::text, 'transaction', v_transaction_id, v_order.project_id, 'downstream', 'active', jsonb_build_object('kind', 'external_issue'))
    on conflict (source_type, source_id, target_type, target_id, relation_type)
    do update set status = excluded.status, metadata = excluded.metadata, updated_at = now();

    if v_order.subcontractor_contract_id is not null then
      insert into public.project_document_links(source_type, source_id, target_type, target_id, project_id, relation_type, status, metadata)
      values ('subcontractor_contract', v_order.subcontractor_contract_id, 'material_issue_order', v_order.id::text, v_order.project_id, 'downstream', 'active', jsonb_build_object('issueNo', v_order.issue_no))
      on conflict (source_type, source_id, target_type, target_id, relation_type)
      do update set status = excluded.status, metadata = excluded.metadata, updated_at = now();
    end if;
  end if;

  return v_order;
end;
$$;


ALTER FUNCTION "public"."submit_material_issue_order"("p_order_id" "uuid", "p_override_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_auth_user_profile"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_requested_username text := coalesce(
    nullif(split_part(coalesce(new.email, ''), '@', 1), ''),
    new.id::text
  );
  v_safe_username text := v_requested_username;
  v_name text := coalesce(
    nullif(new.raw_user_meta_data ->> 'name', ''),
    v_requested_username
  );
  v_phone text := nullif(new.raw_user_meta_data ->> 'phone', '');
  v_avatar text := coalesce(
    nullif(new.raw_user_meta_data ->> 'avatar', ''),
    'https://i.pravatar.cc/150?u=' || coalesce(new.email, new.id::text)
  );
  v_existing_profile_id uuid;
begin
  select u.id
    into v_existing_profile_id
  from public.users u
  where u.auth_id = new.id
     or (
       new.email is not null
       and lower(u.email) = lower(new.email)
     )
  order by
    case
      when u.auth_id = new.id then 0
      when new.email is not null and lower(u.email) = lower(new.email) then 1
      else 2
    end,
    u.created_at nulls last,
    u.id
  limit 1
  for update;

  if v_existing_profile_id is not null then
    update public.users
    set auth_id = case
          when public.users.auth_id is null or public.users.auth_id = new.id
            then new.id
          else public.users.auth_id
        end,
        name = coalesce(nullif(v_name, ''), public.users.name),
        email = coalesce(new.email, public.users.email),
        phone = coalesce(v_phone, public.users.phone),
        avatar = coalesce(v_avatar, public.users.avatar),
        updated_at = now()
    where id = v_existing_profile_id;

    return new;
  end if;

  if exists (
    select 1
    from public.users
    where lower(username) = lower(v_safe_username)
      and email is distinct from new.email
  ) then
    v_safe_username := v_safe_username || '-' || left(new.id::text, 8);
  end if;

  insert into public.users (
    id,
    auth_id,
    name,
    email,
    username,
    phone,
    role,
    avatar,
    assigned_warehouse_id,
    allowed_modules,
    admin_modules,
    allowed_sub_modules,
    admin_sub_modules,
    is_active,
    account_status
  )
  values (
    new.id,
    new.id,
    v_name,
    new.email,
    v_safe_username,
    v_phone,
    'EMPLOYEE'::public.user_role,
    v_avatar,
    null,
    '{}'::text[],
    '{}'::text[],
    '{}'::jsonb,
    '{}'::jsonb,
    true,
    'ACTIVE'
  )
  on conflict (id) do update
  set auth_id = coalesce(public.users.auth_id, excluded.auth_id),
      name = excluded.name,
      email = excluded.email,
      phone = excluded.phone,
      avatar = excluded.avatar,
      updated_at = now();

  return new;
end;
$$;


ALTER FUNCTION "public"."sync_auth_user_profile"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_employee_status_from_metadata"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  status_code text;
begin
  if new.employment_status_id is null then
    return new;
  end if;

  select code into status_code
  from public.hrm_catalog_items
  where id = new.employment_status_id
    and catalog_key = 'employment_status';

  if status_code = 'NV' then
    new.status := 'Đã nghỉ việc';
  elsif status_code in ('DL', 'CV') then
    new.status := 'Đang làm việc';
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."sync_employee_status_from_metadata"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_fulfillment_receipt_for_transaction"("p_transaction_id" "text", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'app_private'
    AS $$
declare
  v_tx public.transactions%rowtype;
  v_user public.users%rowtype;
  v_batch public.material_request_fulfillment_batches%rowtype;
  v_actor_user_id uuid;
  v_can_sync boolean := false;
  v_line record;
  v_received_qty numeric;
  v_reason text;
  v_has_variance boolean := false;
  v_po_id text;
  v_po public.purchase_orders%rowtype;
  v_next_items jsonb;
  v_is_delivered boolean;
  v_already_recorded boolean;
begin
  select * into v_tx
  from public.transactions
  where id = p_transaction_id
  for update;
  if not found then
    raise exception 'transaction not found: %', p_transaction_id;
  end if;

  select * into v_user
  from public.users
  where id = public.current_app_user_id();
  if v_user.id is null then
    raise exception 'authentication required';
  end if;

  v_actor_user_id := coalesce(p_actor_user_id, v_user.id);

  v_can_sync :=
    public.is_admin()
    or public.is_module_admin('WMS')
    or (
      v_user.role = 'WAREHOUSE_KEEPER'
      and (
        v_user.assigned_warehouse_id is null
        or (
          v_tx.type in ('IMPORT'::public.transaction_type, 'TRANSFER'::public.transaction_type)
          and v_user.assigned_warehouse_id is not distinct from v_tx.target_warehouse_id
        )
      )
    );

  if not v_can_sync then
    raise exception 'insufficient privilege to sync fulfillment receipt';
  end if;

  if v_tx.status <> 'COMPLETED'::public.transaction_status then
    raise exception 'Chỉ đồng bộ nhận hàng cho phiếu kho đã hoàn tất.';
  end if;

  select * into v_batch
  from public.material_request_fulfillment_batches
  where transaction_id = p_transaction_id
  for update;
  if not found then
    return jsonb_build_object('synced', false, 'reason', 'batch_not_found');
  end if;

  if v_batch.status not in ('issued', 'received') then
    return jsonb_build_object('synced', false, 'reason', 'batch_not_receivable', 'batchStatus', v_batch.status);
  end if;

  for v_line in
    select *
    from public.material_request_fulfillment_lines
    where batch_id = v_batch.id
    order by created_at asc
    for update
  loop
    select
      coalesce(sum(coalesce(nullif(item.value->>'quantity', '')::numeric, 0)), 0),
      max(nullif(item.value->>'varianceReason', ''))
    into v_received_qty, v_reason
    from jsonb_array_elements(coalesce(v_tx.items, '[]'::jsonb)) item(value)
    where coalesce(item.value->>'fulfillmentBatchId', '') = v_batch.id::text
      and item.value->>'requestLineId' = v_line.request_line_id;

    if coalesce(v_received_qty, 0) = 0 then
      select
        coalesce(sum(coalesce(nullif(item.value->>'quantity', '')::numeric, 0)), 0),
        max(nullif(item.value->>'varianceReason', ''))
      into v_received_qty, v_reason
      from jsonb_array_elements(coalesce(v_tx.items, '[]'::jsonb)) item(value)
      where coalesce(item.value->>'fulfillmentBatchId', '') = v_batch.id::text
        and item.value->>'itemId' = v_line.item_id;
    end if;

    if coalesce(v_received_qty, 0) <> coalesce(v_line.issued_qty, 0) then
      v_has_variance := true;
    end if;

    update public.material_request_fulfillment_lines
    set
      received_qty = coalesce(v_received_qty, 0),
      variance_reason = coalesce(
        nullif(v_reason, ''),
        variance_reason,
        case
          when coalesce(v_received_qty, 0) <> coalesce(v_line.issued_qty, 0)
            then 'Thủ kho công trường xác nhận số lượng thực nhận lệch phiếu kho.'
          else null
        end
      )
    where id = v_line.id;
  end loop;

  if v_batch.status = 'issued' then
    update public.material_request_fulfillment_batches
    set
      status = 'received',
      received_by = v_actor_user_id,
      received_at = now(),
      reason = coalesce(
        reason,
        case when v_has_variance then 'Thủ kho công trường xác nhận nhận lệch theo thực tế.' else null end
      )
    where id = v_batch.id
    returning * into v_batch;
  end if;

  for v_po_id in
    select distinct po_id
    from public.material_request_fulfillment_lines
    where batch_id = v_batch.id
      and po_id is not null
  loop
    select * into v_po
    from public.purchase_orders
    where id = v_po_id
    for update;
    if not found then
      continue;
    end if;

    select exists (
      select 1
      from jsonb_array_elements_text(coalesce(v_po.received_transaction_ids, '[]'::jsonb)) existing(id)
      where existing.id = v_tx.id
    )
    into v_already_recorded;
    if v_already_recorded then
      continue;
    end if;

    with receipt_by_line as (
      select po_line_id, sum(coalesce(received_qty, 0)) as received_qty
      from public.material_request_fulfillment_lines
      where batch_id = v_batch.id
        and po_id = v_po_id
        and po_line_id is not null
      group by po_line_id
    ),
    item_rows as (
      select
        item.value as item,
        item.ordinality,
        coalesce(item.value->>'lineId', item.value->>'line_id', item.value->>'itemId', item.value->>'item_id') as line_key,
        coalesce(nullif(item.value->>'qty', '')::numeric, 0) as ordered_qty,
        coalesce(nullif(item.value->>'receivedQty', '')::numeric, 0) as current_received_qty
      from jsonb_array_elements(coalesce(v_po.items, '[]'::jsonb)) with ordinality item(value, ordinality)
    ),
    next_rows as (
      select
        case
          when coalesce(r.received_qty, 0) > 0 then
            jsonb_set(
              ir.item,
              '{receivedQty}',
              to_jsonb(least(ir.ordered_qty, ir.current_received_qty + coalesce(r.received_qty, 0))),
              true
            )
          else ir.item
        end as item,
        ir.ordinality
      from item_rows ir
      left join receipt_by_line r on r.po_line_id = ir.line_key
    )
    select coalesce(jsonb_agg(item order by ordinality), '[]'::jsonb)
    into v_next_items
    from next_rows;

    select coalesce(bool_and(
      coalesce(nullif(item.value->>'qty', '')::numeric, 0) <= coalesce(nullif(item.value->>'receivedQty', '')::numeric, 0)
    ), false)
    into v_is_delivered
    from jsonb_array_elements(coalesce(v_next_items, '[]'::jsonb)) item(value);

    update public.purchase_orders
    set
      items = v_next_items,
      status = case when v_is_delivered then 'delivered' else 'partial' end,
      actual_delivery_date = case when v_is_delivered then current_date::text else actual_delivery_date end,
      received_transaction_ids = coalesce(received_transaction_ids, '[]'::jsonb) || jsonb_build_array(v_tx.id)
    where id = v_po_id;
  end loop;

  perform app_private.sync_po_delivery_schedule_status_v1(
    v_batch.po_delivery_batch_id,
    v_batch.po_delivery_group_id
  );

  perform app_private.sync_material_request_receipt_status_v1(
    v_batch.material_request_id,
    v_actor_user_id,
    'Đồng bộ sau khi phiếu kho hoàn tất'
  );

  return jsonb_build_object(
    'synced', true,
    'batchId', v_batch.id,
    'batchStatus', v_batch.status,
    'hasVariance', v_has_variance
  );
end;
$$;


ALTER FUNCTION "public"."sync_fulfillment_receipt_for_transaction"("p_transaction_id" "text", "p_actor_user_id" "uuid") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."site_small_tool_records" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "code" "text" NOT NULL,
    "project_id" "text",
    "construction_site_id" "text" NOT NULL,
    "source_type" "text" DEFAULT 'site_direct_purchase'::"text" NOT NULL,
    "source_id" "text" NOT NULL,
    "source_line_id" "uuid" NOT NULL,
    "source_code" "text",
    "supplier_id" "text",
    "supplier_name_snapshot" "text",
    "item_name_snapshot" "text" NOT NULL,
    "category" "text",
    "unit_snapshot" "text",
    "quantity" numeric(18,6) DEFAULT 0 NOT NULL,
    "unit_cost" numeric(18,2) DEFAULT 0 NOT NULL,
    "total_amount" numeric(18,2) DEFAULT 0 NOT NULL,
    "purchase_date" "date",
    "holder_type" "text" DEFAULT 'site'::"text" NOT NULL,
    "holder_id" "text",
    "holder_name_snapshot" "text",
    "location_note" "text",
    "status" "text" DEFAULT 'stored'::"text" NOT NULL,
    "attachments" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "qr_token" "text",
    "created_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "note" "text",
    CONSTRAINT "site_small_tool_records_check" CHECK ((("project_id" IS NOT NULL) OR ("construction_site_id" IS NOT NULL))),
    CONSTRAINT "site_small_tool_records_holder_type_check" CHECK (("holder_type" = ANY (ARRAY['site'::"text", 'employee'::"text", 'team'::"text", 'manual'::"text"]))),
    CONSTRAINT "site_small_tool_records_quantity_check" CHECK (("quantity" >= (0)::numeric)),
    CONSTRAINT "site_small_tool_records_source_type_check" CHECK (("source_type" = 'site_direct_purchase'::"text")),
    CONSTRAINT "site_small_tool_records_status_check" CHECK (("status" = ANY (ARRAY['stored'::"text", 'in_use'::"text", 'damaged'::"text", 'lost'::"text", 'disposed'::"text"]))),
    CONSTRAINT "site_small_tool_records_total_amount_check" CHECK (("total_amount" >= (0)::numeric)),
    CONSTRAINT "site_small_tool_records_unit_cost_check" CHECK (("unit_cost" >= (0)::numeric))
);


ALTER TABLE "public"."site_small_tool_records" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_site_small_tools_from_site_direct_purchase"("p_direct_purchase_id" "uuid") RETURNS SETOF "public"."site_small_tool_records"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
declare
  v_purchase public.site_direct_purchases%rowtype;
begin
  select * into v_purchase
  from public.site_direct_purchases
  where id = p_direct_purchase_id;

  if not found then
    raise exception 'Không tìm thấy phiếu mua nóng %. ', p_direct_purchase_id;
  end if;

  if not app_private.ap_scope_can_mutate(v_purchase.project_id, v_purchase.construction_site_id) then
    raise exception 'Bạn không có quyền đồng bộ sổ CCDC nhỏ cho phiếu mua nóng này.';
  end if;

  delete from public.site_small_tool_records record
  using public.site_direct_purchase_lines line
  where record.source_type = 'site_direct_purchase'
    and record.source_line_id = line.id
    and line.direct_purchase_id = v_purchase.id
    and (
      line.line_type <> 'small_tool'
      or line.status not in ('accepted', 'adjusted')
    );

  return query
  insert into public.site_small_tool_records as target (
    code,
    project_id,
    construction_site_id,
    source_type,
    source_id,
    source_line_id,
    source_code,
    supplier_id,
    supplier_name_snapshot,
    item_name_snapshot,
    category,
    unit_snapshot,
    quantity,
    unit_cost,
    total_amount,
    purchase_date,
    holder_type,
    holder_id,
    holder_name_snapshot,
    location_note,
    status,
    attachments,
    qr_token,
    created_by,
    note
  )
  select
    'CCDC-' || v_purchase.code || '-' || lpad(line.line_no::text, 2, '0'),
    v_purchase.project_id,
    v_purchase.construction_site_id,
    'site_direct_purchase',
    v_purchase.id::text,
    line.id,
    v_purchase.code,
    v_purchase.supplier_id,
    v_purchase.supplier_name_snapshot,
    line.item_name_snapshot,
    nullif(line.small_tool_category, ''),
    line.unit_snapshot,
    coalesce(nullif(line.accepted_quantity, 0), line.quantity, 0)::numeric(18,6),
    case
      when coalesce(nullif(line.accepted_quantity, 0), line.quantity, 0) > 0 then
        round(
          coalesce(nullif(line.accepted_amount, 0), line.line_amount + line.vat_amount, 0)
          / coalesce(nullif(line.accepted_quantity, 0), line.quantity, 1),
          2
        )
      else coalesce(line.unit_price, 0)
    end::numeric(18,2),
    coalesce(nullif(line.accepted_amount, 0), line.line_amount + line.vat_amount, 0)::numeric(18,2),
    coalesce(v_purchase.purchase_date, current_date),
    coalesce(nullif(line.small_tool_holder_type, ''), 'site'),
    case
      when coalesce(nullif(line.small_tool_holder_type, ''), 'site') = 'site' then v_purchase.construction_site_id
      else nullif(line.small_tool_holder_id, '')
    end,
    coalesce(nullif(line.small_tool_holder_name_snapshot, ''), 'Công trường'),
    nullif(line.small_tool_location_note, ''),
    case
      when coalesce(nullif(line.small_tool_holder_type, ''), 'site') = 'site' then 'stored'
      else 'in_use'
    end,
    coalesce(v_purchase.attachments, '[]'::jsonb),
    'qr_ccdc_' || replace(line.id::text, '-', ''),
    v_purchase.created_by,
    line.note
  from public.site_direct_purchase_lines line
  where line.direct_purchase_id = v_purchase.id
    and line.line_type = 'small_tool'
    and line.status in ('accepted', 'adjusted')
  on conflict (source_type, source_line_id) do update
  set
    project_id = excluded.project_id,
    construction_site_id = excluded.construction_site_id,
    source_id = excluded.source_id,
    source_code = excluded.source_code,
    supplier_id = excluded.supplier_id,
    supplier_name_snapshot = excluded.supplier_name_snapshot,
    item_name_snapshot = excluded.item_name_snapshot,
    category = excluded.category,
    unit_snapshot = excluded.unit_snapshot,
    quantity = excluded.quantity,
    unit_cost = excluded.unit_cost,
    total_amount = excluded.total_amount,
    purchase_date = excluded.purchase_date,
    holder_type = coalesce(target.holder_type, excluded.holder_type),
    holder_id = coalesce(target.holder_id, excluded.holder_id),
    holder_name_snapshot = coalesce(target.holder_name_snapshot, excluded.holder_name_snapshot),
    location_note = coalesce(target.location_note, excluded.location_note),
    status = target.status,
    attachments = excluded.attachments,
    note = excluded.note,
    updated_at = now()
  returning *;
end;
$$;


ALTER FUNCTION "public"."sync_site_small_tools_from_site_direct_purchase"("p_direct_purchase_id" "uuid") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."supplier_payable_documents" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "code" "text" NOT NULL,
    "source_type" "text" NOT NULL,
    "source_id" "text" NOT NULL,
    "project_id" "text",
    "construction_site_id" "text",
    "supplier_id" "text",
    "supplier_name_snapshot" "text" NOT NULL,
    "document_no" "text" NOT NULL,
    "document_date" "date" NOT NULL,
    "due_date" "date",
    "currency" "text" DEFAULT 'VND'::"text" NOT NULL,
    "committed_amount" numeric(18,2) DEFAULT 0 NOT NULL,
    "recognized_amount" numeric(18,2) DEFAULT 0 NOT NULL,
    "credit_amount" numeric(18,2) DEFAULT 0 NOT NULL,
    "status" "text" DEFAULT 'open'::"text" NOT NULL,
    "qr_token" "text",
    "invoice_number" "text",
    "invoice_date" "date",
    "metadata" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "created_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "supplier_contract_id" "text",
    "supplier_contract_code" "text",
    CONSTRAINT "supplier_payable_documents_check" CHECK ((("project_id" IS NOT NULL) OR ("construction_site_id" IS NOT NULL))),
    CONSTRAINT "supplier_payable_documents_committed_amount_check" CHECK (("committed_amount" >= (0)::numeric)),
    CONSTRAINT "supplier_payable_documents_credit_amount_check" CHECK (("credit_amount" >= (0)::numeric)),
    CONSTRAINT "supplier_payable_documents_recognized_amount_check" CHECK (("recognized_amount" >= (0)::numeric)),
    CONSTRAINT "supplier_payable_documents_source_type_check" CHECK (("source_type" = ANY (ARRAY['purchase_order'::"text", 'site_direct_purchase'::"text", 'supplier_delivery_statement'::"text", 'supplier_return_credit'::"text", 'opening_balance'::"text", 'manual_adjustment'::"text"]))),
    CONSTRAINT "supplier_payable_documents_status_check" CHECK (("status" = ANY (ARRAY['draft'::"text", 'open'::"text", 'partial'::"text", 'paid'::"text", 'cancelled'::"text", 'reversed'::"text"])))
);


ALTER TABLE "public"."supplier_payable_documents" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_supplier_payable_from_delivery_statement"("p_statement_id" "uuid") RETURNS "public"."supplier_payable_documents"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
declare
  v_statement public.supplier_delivery_statements%rowtype;
  v_document public.supplier_payable_documents%rowtype;
begin
  select * into v_statement
  from public.supplier_delivery_statements
  where id = p_statement_id;

  if not found then
    raise exception 'Không tìm thấy bảng đối soát HĐ NCC %. ', p_statement_id;
  end if;

  if not app_private.ap_scope_can_mutate(v_statement.project_id, v_statement.construction_site_id) then
    raise exception 'Bạn không có quyền đồng bộ công nợ bảng đối soát này.';
  end if;

  if v_statement.status <> 'posted' then
    raise exception 'Chỉ bảng đối soát đã post mới được ghi nhận phải trả NCC.';
  end if;

  if coalesce(v_statement.total_amount, 0) <= 0 then
    raise exception 'Bảng đối soát chưa có giá trị được duyệt.';
  end if;

  insert into public.supplier_payable_documents (
    code, source_type, source_id, project_id, construction_site_id,
    supplier_id, supplier_name_snapshot, supplier_contract_id, supplier_contract_code,
    document_no, document_date, due_date, committed_amount, recognized_amount,
    credit_amount, status, qr_token, metadata, created_by
  )
  values (
    'AP-' || v_statement.code,
    'supplier_delivery_statement',
    v_statement.id::text,
    v_statement.project_id,
    v_statement.construction_site_id,
    v_statement.supplier_id,
    v_statement.supplier_name_snapshot,
    v_statement.supplier_contract_id,
    v_statement.supplier_contract_code,
    v_statement.code,
    v_statement.statement_date,
    null,
    v_statement.total_amount,
    v_statement.total_amount,
    0,
    'open',
    coalesce(v_statement.qr_token, 'ap_statement_' || replace(v_statement.id::text, '-', '')),
    jsonb_build_object(
      'supplierContractId', v_statement.supplier_contract_id,
      'supplierContractCode', v_statement.supplier_contract_code,
      'periodMonth', v_statement.period_month,
      'statementId', v_statement.id
    ) || coalesce(v_statement.metadata, '{}'::jsonb),
    v_statement.created_by
  )
  on conflict (source_type, source_id) do update
  set
    project_id = excluded.project_id,
    construction_site_id = excluded.construction_site_id,
    supplier_id = excluded.supplier_id,
    supplier_name_snapshot = excluded.supplier_name_snapshot,
    supplier_contract_id = excluded.supplier_contract_id,
    supplier_contract_code = excluded.supplier_contract_code,
    document_no = excluded.document_no,
    document_date = excluded.document_date,
    committed_amount = excluded.committed_amount,
    recognized_amount = excluded.recognized_amount,
    metadata = public.supplier_payable_documents.metadata || excluded.metadata,
    updated_at = now()
  returning * into v_document;

  update public.supplier_delivery_statements
  set payable_document_id = v_document.id, updated_at = now()
  where id = v_statement.id;

  return v_document;
end;
$$;


ALTER FUNCTION "public"."sync_supplier_payable_from_delivery_statement"("p_statement_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_supplier_payable_from_purchase_order"("p_po_id" "text") RETURNS "public"."supplier_payable_documents"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $_$
declare
  v_po public.purchase_orders%rowtype;
  v_recognized numeric(18,2);
  v_committed numeric(18,2);
  v_document public.supplier_payable_documents%rowtype;
begin
  select * into v_po
  from public.purchase_orders
  where id = p_po_id
    and archived_at is null;

  if not found then
    raise exception 'Không tìm thấy PO %. ', p_po_id;
  end if;

  if not app_private.ap_scope_can_mutate(v_po.project_id, v_po.construction_site_id) then
    raise exception 'Bạn không có quyền đồng bộ công nợ PO này.';
  end if;

  v_recognized := app_private.calculate_po_payable_amount(v_po.items)::numeric(18,2);
  v_committed := app_private.calculate_po_committed_amount(v_po.items, v_po.total_amount)::numeric(18,2);

  insert into public.supplier_payable_documents (
    code, source_type, source_id, project_id, construction_site_id,
    supplier_id, supplier_name_snapshot, document_no, document_date, due_date,
    committed_amount, recognized_amount, credit_amount, status, qr_token,
    invoice_number, invoice_date, metadata, created_by
  )
  values (
    'AP-' || coalesce(v_po.po_number, v_po.id),
    'purchase_order',
    v_po.id,
    v_po.project_id,
    v_po.construction_site_id,
    v_po.vendor_id,
    coalesce(v_po.vendor_name, v_po.vendor_id, 'Nhà cung cấp'),
    coalesce(v_po.po_number, v_po.id),
    coalesce(app_private.safe_date(v_po.order_date), v_po.created_at::date, current_date),
    app_private.safe_date(v_po.expected_delivery_date),
    v_committed,
    v_recognized,
    0,
    case when v_recognized > 0 then 'open' else 'draft' end,
    coalesce(v_po.qr_token, 'ap_' || replace(v_po.id, '-', '')),
    v_po.invoice_number,
    v_po.invoice_date,
    jsonb_build_object(
      'sourceMode', v_po.source_mode,
      'targetWarehouseId', v_po.target_warehouse_id,
      'receivedTransactionIds', coalesce(v_po.received_transaction_ids, '[]'::jsonb)
    ),
    case
      when nullif(v_po.created_by_id, '') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$'
        then v_po.created_by_id::uuid
      else null
    end
  )
  on conflict (source_type, source_id) do update
  set
    project_id = excluded.project_id,
    construction_site_id = excluded.construction_site_id,
    supplier_id = excluded.supplier_id,
    supplier_name_snapshot = excluded.supplier_name_snapshot,
    document_no = excluded.document_no,
    document_date = excluded.document_date,
    due_date = excluded.due_date,
    committed_amount = excluded.committed_amount,
    recognized_amount = excluded.recognized_amount,
    invoice_number = excluded.invoice_number,
    invoice_date = excluded.invoice_date,
    metadata = public.supplier_payable_documents.metadata || excluded.metadata,
    updated_at = now()
  returning * into v_document;

  return v_document;
end;
$_$;


ALTER FUNCTION "public"."sync_supplier_payable_from_purchase_order"("p_po_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_supplier_payable_from_site_direct_purchase"("p_direct_purchase_id" "uuid") RETURNS "public"."supplier_payable_documents"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
declare
  v_purchase public.site_direct_purchases%rowtype;
  v_recognized numeric(18,2);
  v_document public.supplier_payable_documents%rowtype;
begin
  select * into v_purchase
  from public.site_direct_purchases
  where id = p_direct_purchase_id;

  if not found then
    raise exception 'Không tìm thấy phiếu mua nóng %. ', p_direct_purchase_id;
  end if;

  if not app_private.ap_scope_can_mutate(v_purchase.project_id, v_purchase.construction_site_id) then
    raise exception 'Bạn không có quyền đồng bộ công nợ phiếu mua nóng này.';
  end if;

  if exists (
    select 1
    from public.site_direct_purchase_lines line
    where line.direct_purchase_id = v_purchase.id
      and line.line_type = 'stock_item'
      and line.status <> 'rejected'
  )
  and not exists (
    select 1
    from public.transactions tx
    where tx.id = v_purchase.wms_transaction_id
      and upper(coalesce(tx.status::text, '')) = 'COMPLETED'
  )
  then
    raise exception 'Mua nóng vật tư tồn kho phải hoàn tất WMS import trước khi ghi nhận AP.';
  end if;

  select coalesce(sum(
    case
      when line.status in ('accepted', 'adjusted') then coalesce(nullif(line.accepted_amount, 0), line.line_amount)
      else 0
    end
  ), 0)::numeric(18,2)
  into v_recognized
  from public.site_direct_purchase_lines line
  where line.direct_purchase_id = v_purchase.id;

  insert into public.supplier_payable_documents (
    code, source_type, source_id, project_id, construction_site_id,
    supplier_id, supplier_name_snapshot, document_no, document_date, due_date,
    committed_amount, recognized_amount, credit_amount, status, qr_token,
    invoice_number, invoice_date, metadata, created_by
  )
  values (
    'AP-' || v_purchase.code,
    'site_direct_purchase',
    v_purchase.id::text,
    v_purchase.project_id,
    v_purchase.construction_site_id,
    v_purchase.supplier_id,
    v_purchase.supplier_name_snapshot,
    v_purchase.code,
    coalesce(v_purchase.purchase_date, current_date),
    null,
    v_purchase.total_amount,
    v_recognized,
    0,
    case when v_recognized > 0 then 'open' else 'draft' end,
    coalesce(v_purchase.qr_token, 'ap_direct_' || replace(v_purchase.id::text, '-', '')),
    v_purchase.invoice_number,
    v_purchase.invoice_date,
    jsonb_build_object(
      'purchaseMode', v_purchase.purchase_mode,
      'paymentSource', v_purchase.payment_source,
      'wmsTransactionId', v_purchase.wms_transaction_id
    ),
    v_purchase.created_by
  )
  on conflict (source_type, source_id) do update
  set
    project_id = excluded.project_id,
    construction_site_id = excluded.construction_site_id,
    supplier_id = excluded.supplier_id,
    supplier_name_snapshot = excluded.supplier_name_snapshot,
    document_no = excluded.document_no,
    document_date = excluded.document_date,
    committed_amount = excluded.committed_amount,
    recognized_amount = excluded.recognized_amount,
    invoice_number = excluded.invoice_number,
    invoice_date = excluded.invoice_date,
    metadata = public.supplier_payable_documents.metadata || excluded.metadata,
    updated_at = now()
  returning * into v_document;

  return v_document;
end;
$$;


ALTER FUNCTION "public"."sync_supplier_payable_from_site_direct_purchase"("p_direct_purchase_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."timeout_stale_user_sessions"("p_timeout_minutes" integer DEFAULT 5) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_count integer := 0;
begin
  if not public.is_admin() then
    raise exception 'Only admin can timeout stale sessions'
      using errcode = '42501';
  end if;

  with timed_out as (
    update public.user_sessions
    set status = 'timeout',
        logout_at = coalesce(logout_at, last_seen_at),
        duration_seconds = greatest(0, floor(extract(epoch from (coalesce(logout_at, last_seen_at) - login_at)))::integer),
        updated_at = now()
    where status = 'active'
      and last_seen_at < now() - make_interval(mins => greatest(1, p_timeout_minutes))
    returning id, user_id
  ),
  inserted as (
    insert into public.user_session_events (session_id, user_id, event_type, metadata)
    select id, user_id, 'timeout', jsonb_build_object('timeoutMinutes', greatest(1, p_timeout_minutes))
    from timed_out
    returning 1
  )
  select count(*) into v_count from inserted;

  return v_count;
end;
$$;


ALTER FUNCTION "public"."timeout_stale_user_sessions"("p_timeout_minutes" integer) OWNER TO "postgres";


