CREATE OR REPLACE FUNCTION "public"."transfer_asset_stock"("p_asset_id" "text", "p_from_stock_id" "text", "p_qty" integer, "p_to_warehouse_id" "text" DEFAULT NULL::"text", "p_to_user_id" "text" DEFAULT NULL::"text", "p_reason" "text" DEFAULT NULL::"text", "p_date" "text" DEFAULT NULL::"text") RETURNS "public"."asset_transfers"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_from public.asset_location_stocks%rowtype;
  v_target_id text;
  v_asset public.assets%rowtype;
  v_transfer public.asset_transfers%rowtype;
  v_user public.users%rowtype;
  v_to_user_name text;
  v_from_label text;
  v_to_label text;
begin
  if not public.is_module_admin('TS') then
    raise exception 'insufficient privilege to transfer asset stock';
  end if;
  if p_qty <= 0 then
    raise exception 'transfer quantity must be positive';
  end if;
  if nullif(p_to_warehouse_id, '') is null and nullif(p_to_user_id, '') is null then
    raise exception 'destination is required';
  end if;

  select * into v_from
  from public.asset_location_stocks
  where id = p_from_stock_id and asset_id = p_asset_id
  for update;
  if not found then
    raise exception 'source stock not found';
  end if;
  if v_from.qty < p_qty then
    raise exception 'insufficient asset stock: available %, requested %', v_from.qty, p_qty;
  end if;

  select * into v_asset from public.assets where id = p_asset_id;
  if not found then
    raise exception 'asset not found';
  end if;

  select * into v_user from public.users where id = public.current_app_user_id();
  select name into v_to_user_name from public.users where id::text = nullif(p_to_user_id, '');

  update public.asset_location_stocks
  set qty = qty - p_qty,
      updated_at = now()
  where id = p_from_stock_id;

  select id into v_target_id
  from public.asset_location_stocks
  where asset_id = p_asset_id
    and warehouse_id is not distinct from nullif(p_to_warehouse_id, '')
    and assigned_to_user_id is not distinct from nullif(p_to_user_id, '')
  limit 1
  for update;

  if v_target_id is null then
    insert into public.asset_location_stocks (
      asset_id, warehouse_id, qty, assigned_to_user_id, assigned_to_name, updated_at
    )
    values (
      p_asset_id, nullif(p_to_warehouse_id, ''), p_qty,
      nullif(p_to_user_id, ''), v_to_user_name, now()
    );
  else
    update public.asset_location_stocks
    set qty = qty + p_qty,
        assigned_to_name = coalesce(v_to_user_name, assigned_to_name),
        updated_at = now()
    where id = v_target_id;
  end if;

  select coalesce(v_from.assigned_to_name, w.name, 'Không xác định')
    into v_from_label
  from (select 1) s
  left join public.warehouses w on w.id = v_from.warehouse_id;

  select coalesce(v_to_user_name, w.name, 'Không xác định')
    into v_to_label
  from (select 1) s
  left join public.warehouses w on w.id = nullif(p_to_warehouse_id, '');

  insert into public.asset_transfers (
    code, asset_id, asset_code, asset_name, qty,
    from_warehouse_id, from_location_label,
    to_warehouse_id, to_location_label,
    received_by_user_id, received_by_name,
    date, reason, status, performed_by, performed_by_name, created_at
  )
  values (
    public.next_asset_transfer_code(), p_asset_id, v_asset.code, v_asset.name, p_qty,
    v_from.warehouse_id, v_from_label,
    nullif(p_to_warehouse_id, ''), v_to_label,
    nullif(p_to_user_id, ''), v_to_user_name,
    coalesce(nullif(p_date, ''), now()::date::text), p_reason, 'completed',
    public.current_app_user_id()::text, coalesce(v_user.name, v_user.username), now()
  )
  returning * into v_transfer;

  return v_transfer;
end;
$$;


ALTER FUNCTION "public"."transfer_asset_stock"("p_asset_id" "text", "p_from_stock_id" "text", "p_qty" integer, "p_to_warehouse_id" "text", "p_to_user_id" "text", "p_reason" "text", "p_date" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."transition_custom_material_request_status"("p_request_id" "uuid", "p_status" "text", "p_actor_user_id" "uuid", "p_note" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_request public.custom_material_requests%rowtype;
  v_user_id uuid := public.current_app_user_id();
  v_required_permission text;
  v_line_status text;
  v_previous_guard text;
  v_result jsonb;
begin
  if v_user_id is null or p_actor_user_id is distinct from v_user_id then
    raise exception 'Không xác định được người dùng chuyển trạng thái phiếu CMR.'
      using errcode = '42501';
  end if;

  select *
  into v_request
  from public.custom_material_requests
  where id = p_request_id
  for update;

  if not found then
    raise exception 'Không tìm thấy phiếu CMR.';
  end if;

  if coalesce(p_status, '') = 'cancelled' then
    raise exception 'Phiếu CMR không được hủy qua luồng duyệt.'
      using errcode = '23514';
  end if;

  v_required_permission := case
    when p_status = 'submitted' then 'project.custom_material.create'
    when p_status in ('po_created') then 'project.material_po.create'
    when p_status in ('partially_received', 'completed') then 'project.material_po.receive'
    else 'project.custom_material.approve'
  end;

  if v_required_permission = 'project.custom_material.approve'
    and (
      v_request.status is distinct from 'submitted'
      or coalesce(p_status, '') not in ('approved', 'returned', 'rejected')
    )
  then
    raise exception 'Chỉ phiếu CMR đang chờ duyệt mới được duyệt, trả lại hoặc từ chối.'
      using errcode = '23514';
  end if;

  if p_status = 'submitted' and coalesce(v_request.status, 'draft') not in ('draft', 'returned') then
    raise exception 'Chỉ phiếu nháp hoặc bị trả lại mới được gửi duyệt.';
  end if;

  if not app_private.material_has_action(v_request.project_id, v_request.construction_site_id, v_required_permission, v_user_id) then
    raise exception 'Bạn cần quyền % để chuyển trạng thái CMR.', v_required_permission
      using errcode = '42501';
  end if;

  v_line_status := case p_status
    when 'submitted' then 'submitted'
    when 'approved' then 'approved'
    when 'rejected' then 'cancelled'
    when 'cancelled' then 'cancelled'
    else null
  end;

  v_previous_guard := current_setting('app.material_transition_context', true);
  perform set_config('app.material_transition_context', 'on', true);

  update public.custom_material_requests
  set
    status = p_status,
    updated_by = v_user_id,
    submitted_at = case when p_status = 'submitted' then now() else submitted_at end,
    approved_at = case when p_status = 'approved' then now() else approved_at end,
    approved_by = case when p_status = 'approved' then v_user_id else approved_by end,
    returned_at = case when p_status = 'returned' then now() else returned_at end,
    returned_by = case when p_status = 'returned' then v_user_id else returned_by end,
    rejected_at = case when p_status = 'rejected' then now() else rejected_at end,
    rejected_by = case when p_status = 'rejected' then v_user_id else rejected_by end,
    cancelled_at = case when p_status = 'cancelled' then now() else cancelled_at end,
    cancelled_by = case when p_status = 'cancelled' then v_user_id else cancelled_by end,
    updated_at = now()
  where id = p_request_id
  returning * into v_request;

  if v_line_status is not null then
    update public.custom_material_request_lines
    set status = v_line_status,
        updated_at = now()
    where request_id = p_request_id
      and status in ('draft', 'submitted');
  end if;

  insert into public.custom_material_request_events (
    request_id,
    event_type,
    actor_user_id,
    from_status,
    to_status,
    note,
    metadata
  )
  values (
    p_request_id,
    p_status,
    v_user_id,
    null,
    p_status,
    p_note,
    '{}'::jsonb
  );

  select to_jsonb(v_request)
    || jsonb_build_object(
      'lines',
      coalesce((
        select jsonb_agg(to_jsonb(l) order by l.sort_order)
        from public.custom_material_request_lines l
        where l.request_id = p_request_id
      ), '[]'::jsonb),
      'attachments',
      coalesce((
        select jsonb_agg(to_jsonb(a) order by a.created_at desc)
        from public.custom_material_request_attachments a
        where a.request_id = p_request_id
      ), '[]'::jsonb)
    )
  into v_result;

  perform set_config('app.material_transition_context', coalesce(v_previous_guard, ''), true);
  return v_result;
end;
$$;


ALTER FUNCTION "public"."transition_custom_material_request_status"("p_request_id" "uuid", "p_status" "text", "p_actor_user_id" "uuid", "p_note" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."transition_daily_log_status"("p_log_id" "text", "p_status" "text", "p_requested_verifier_id" "text" DEFAULT NULL::"text", "p_requested_verifier_name" "text" DEFAULT NULL::"text", "p_rejection_reason" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_log public.daily_logs%rowtype;
  v_actor_user_id uuid := public.current_app_user_id();
  v_actor_user_id_text text := public.current_app_user_id()::text;
  v_actor_name text;
  v_assignment_id uuid;
  v_assignment public.app_assignments%rowtype;
  v_owner_user_id uuid;
  v_previous_guard text;
  v_action text;
begin
  if v_actor_user_id is null then
    raise exception 'Không xác định được người dùng đang thao tác.' using errcode = '42501';
  end if;

  if p_status not in ('submitted', 'verified', 'rejected') then
    raise exception 'Trạng thái nhật ký không hợp lệ: %', p_status using errcode = '22023';
  end if;

  select * into v_log from public.daily_logs where id = p_log_id for update;
  if not found then
    raise exception 'Không tìm thấy nhật ký công trường.' using errcode = 'P0002';
  end if;

  select coalesce(name, username, email, id::text)
  into v_actor_name
  from public.users
  where id = v_actor_user_id;

  v_action := case
    when p_status = 'submitted' then 'submit'
    when p_status = 'verified' and coalesce(v_log.submitted_to_permission, '') = 'approve' then 'approve'
    when p_status = 'verified' then 'verify'
    else 'return'
  end;

  if not app_private.can_act_on_subject_impl('daily_log', p_log_id, v_action) then
    raise exception 'Bạn không có assignment, grant hoặc trạng thái workflow hợp lệ để % nhật ký này.', v_action
      using errcode = '42501';
  end if;

  if p_status = 'rejected' and nullif(btrim(coalesce(p_rejection_reason, '')), '') is null then
    raise exception 'Vui lòng nhập lý do trả lại nhật ký.' using errcode = '22023';
  end if;

  v_previous_guard := current_setting('app.daily_log_transition_context', true);
  perform set_config('app.daily_log_transition_context', 'on', true);

  if p_status = 'submitted' then
    update public.daily_logs
    set status = 'submitted',
        verified = false,
        submitted_by = v_actor_user_id_text,
        submitted_by_id = v_actor_user_id_text,
        submitted_at = now(),
        requested_verifier_id = null,
        requested_verifier_name = null,
        submitted_to_user_id = null,
        submitted_to_name = null,
        submitted_to_permission = case when coalesce(submitted_to_permission, '') = 'approve' then 'approve' else 'verify' end,
        submission_note = null,
        ever_submitted = true,
        rejected_by = null,
        rejected_by_id = null,
        rejected_at = null,
        rejection_reason = null,
        last_action_by = v_actor_user_id_text,
        last_action_at = now()
    where id = p_log_id;

    v_assignment_id := app_private.create_daily_log_assignment(p_log_id, v_actor_user_id);
    select * into v_assignment from public.app_assignments where id = v_assignment_id;

    update public.daily_logs
    set requested_verifier_id = v_assignment.principal_id::text,
        requested_verifier_name = (select coalesce(name, username, email, id::text) from public.users where id = v_assignment.principal_id),
        submitted_to_user_id = v_assignment.principal_id::text,
        submitted_to_name = (select coalesce(name, username, email, id::text) from public.users where id = v_assignment.principal_id),
        submitted_to_permission = case when v_assignment.permission_code = 'project.daily_log.approve' then 'approve' else 'verify' end
    where id = p_log_id;
  elsif p_status = 'verified' then
    update public.daily_logs
    set status = 'verified',
        verified = true,
        verified_by = coalesce(v_actor_name, v_actor_user_id_text),
        verified_by_id = v_actor_user_id_text,
        verified_at = now(),
        rejected_by = null,
        rejected_by_id = null,
        rejected_at = null,
        rejection_reason = null,
        last_action_by = v_actor_user_id_text,
        last_action_at = now()
    where id = p_log_id;

    perform app_private.close_daily_log_assignments(p_log_id, v_actor_user_id, 'completed');
  else
    select owner_user.id
    into v_owner_user_id
    from public.users owner_user
    where owner_user.id::text = coalesce(
      nullif(v_log.created_by_id, ''),
      nullif(v_log.submitted_by_id, ''),
      nullif(v_log.submitted_by, ''),
      nullif(v_log.created_by, '')
    )
    limit 1;

    update public.daily_logs
    set status = 'rejected',
        verified = false,
        rejected_by = coalesce(v_actor_name, v_actor_user_id_text),
        rejected_by_id = v_actor_user_id_text,
        rejected_at = now(),
        rejection_reason = p_rejection_reason,
        submitted_to_user_id = v_owner_user_id::text,
        submitted_to_name = (select coalesce(name, username, email, id::text) from public.users where id = v_owner_user_id),
        submitted_to_permission = 'edit',
        submission_note = p_rejection_reason,
        last_action_by = v_actor_user_id_text,
        last_action_at = now()
    where id = p_log_id;

    perform app_private.close_daily_log_assignments(p_log_id, v_actor_user_id, 'returned');
    perform app_private.create_daily_log_revision_assignment(p_log_id, v_owner_user_id, v_actor_user_id);
  end if;

  perform set_config('app.daily_log_transition_context', coalesce(v_previous_guard, ''), true);
exception
  when others then
    perform set_config('app.daily_log_transition_context', coalesce(v_previous_guard, ''), true);
    raise;
end;
$$;


ALTER FUNCTION "public"."transition_daily_log_status"("p_log_id" "text", "p_status" "text", "p_requested_verifier_id" "text", "p_requested_verifier_name" "text", "p_rejection_reason" "text") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."requests" (
    "id" "text" NOT NULL,
    "code" "text" NOT NULL,
    "site_warehouse_id" "text" NOT NULL,
    "source_warehouse_id" "text",
    "requester_id" "uuid" NOT NULL,
    "status" "public"."request_status" NOT NULL,
    "items" "jsonb" NOT NULL,
    "created_date" timestamp with time zone NOT NULL,
    "expected_date" timestamp with time zone NOT NULL,
    "note" "text",
    "logs" "jsonb" DEFAULT '[]'::"jsonb",
    "created_at" timestamp with time zone DEFAULT "now"(),
    "fulfillment_mode" "text" DEFAULT 'RECEIVE_TO_STOCK'::"text" NOT NULL,
    "override_reason" "text",
    "related_transaction_id" "text",
    "project_id" "text",
    "construction_site_id" "text",
    "request_origin" "text" DEFAULT 'wms'::"text" NOT NULL,
    "submitted_to_user_id" "text",
    "submitted_to_name" "text",
    "submitted_to_permission" "text",
    "submission_note" "text",
    "ever_submitted" boolean DEFAULT false NOT NULL,
    "last_action_by" "text",
    "last_action_at" timestamp with time zone,
    "workflow_step" "text",
    "workflow_step_started_at" timestamp with time zone,
    "workflow_step_due_at" timestamp with time zone,
    "workflow_step_sla_hours" integer,
    "workflow_step_actor_user_id" "text",
    "workflow_instance_id" "uuid",
    "workflow_subject_id" "uuid",
    "workflow_template_id" "uuid",
    "title" "text" DEFAULT 'Đề xuất vật tư'::"text" NOT NULL,
    CONSTRAINT "requests_project_origin_project_id_required" CHECK ((("request_origin" <> 'project'::"text") OR ("project_id" IS NOT NULL))),
    CONSTRAINT "requests_request_origin_check" CHECK (("request_origin" = ANY (ARRAY['wms'::"text", 'project'::"text"]))),
    CONSTRAINT "requests_title_length_check" CHECK ((("length"(TRIM(BOTH FROM "title")) >= 1) AND ("length"(TRIM(BOTH FROM "title")) <= 200))),
    CONSTRAINT "requests_workflow_step_sla_hours_nonnegative" CHECK ((("workflow_step_sla_hours" IS NULL) OR ("workflow_step_sla_hours" >= 0)))
);


ALTER TABLE "public"."requests" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."transition_project_material_request_status"("p_request_id" "text", "p_status" "text", "p_action" "text", "p_actor_user_id" "text", "p_target_user_id" "text" DEFAULT NULL::"text", "p_target_permission" "text" DEFAULT NULL::"text", "p_note" "text" DEFAULT NULL::"text", "p_patch" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "public"."requests"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_request public.requests%rowtype;
  v_user_id uuid := public.current_app_user_id();
  v_required_permission text;
  v_previous_guard text;
begin
  if v_user_id is null or p_actor_user_id is distinct from v_user_id::text then
    raise exception 'Không xác định được người dùng chuyển bước phiếu vật tư.'
      using errcode = '42501';
  end if;

  select *
  into v_request
  from public.requests
  where id = p_request_id
    and coalesce(request_origin, 'wms') = 'project'
  for update;

  if not found then
    raise exception 'Không tìm thấy phiếu vật tư dự án.';
  end if;

  v_required_permission := case
    when upper(coalesce(p_action, '')) in ('SUBMITTED', 'RESUBMITTED') then 'project.material_request.submit'
    when upper(coalesce(p_action, '')) in ('RETURNED', 'REJECTED') then 'project.material_request.return'
    when upper(coalesce(p_action, '')) in ('FULFILLED', 'CONFIRMED', 'CONFIRM_FULFILLMENT') then 'project.material_request.confirm_fulfillment'
    when coalesce(p_patch->>'workflow_step', '') in ('site_quality_check', 'completed')
      or upper(coalesce(p_status, '')) in ('COMPLETED', 'IN_TRANSIT') then 'project.material_request.confirm_fulfillment'
    else 'project.material_request.approve'
  end;

  if v_required_permission = 'project.material_request.approve'
    and (
      v_request.status is distinct from 'PENDING'::public.request_status
      or upper(coalesce(p_status, '')) <> 'APPROVED'
      or upper(coalesce(p_action, '')) <> 'APPROVED'
    )
  then
    raise exception 'Chỉ phiếu đang chờ duyệt mới được duyệt.'
      using errcode = '23514';
  end if;

  if v_required_permission = 'project.material_request.submit' then
    if coalesce(v_request.status::text, 'DRAFT') not in ('DRAFT', 'REJECTED') then
      raise exception 'Chỉ phiếu nháp hoặc bị trả lại mới được gửi duyệt.';
    end if;
    if not (public.is_admin() or public.is_module_admin('DA')) and v_request.requester_id is distinct from v_user_id then
      raise exception 'Chỉ người tạo phiếu mới được gửi duyệt.'
        using errcode = '42501';
    end if;
  elsif not (public.is_admin() or public.is_module_admin('DA')) then
    if v_request.submitted_to_user_id is not null
      and v_request.submitted_to_user_id <> v_user_id::text then
      raise exception 'Bạn không phải người đang được giao xử lý phiếu vật tư này.'
        using errcode = '42501';
    end if;
  end if;

  if not app_private.material_has_action(v_request.project_id, v_request.construction_site_id, v_required_permission, v_user_id) then
    raise exception 'Bạn cần quyền % để chuyển bước phiếu vật tư.', v_required_permission
      using errcode = '42501';
  end if;

  if nullif(p_target_user_id, '') is not null and nullif(p_target_permission, '') is not null then
    if not app_private.material_has_action(
      v_request.project_id,
      v_request.construction_site_id,
      p_target_permission,
      p_target_user_id::uuid
    ) then
      raise exception 'Người được chọn chưa có quyền % trong Tổ chức dự án.', p_target_permission
        using errcode = '42501';
    end if;
  end if;

  v_previous_guard := current_setting('app.material_transition_context', true);
  perform set_config('app.material_transition_context', 'on', true);

  update public.requests
  set
    status = coalesce(nullif(p_status, '')::public.request_status, status),
    logs = case when p_patch ? 'logs' then p_patch->'logs' else logs end,
    ever_submitted = case when p_patch ? 'ever_submitted' then coalesce((p_patch->>'ever_submitted')::boolean, ever_submitted) else ever_submitted end,
    last_action_by = case when p_patch ? 'last_action_by' then nullif(p_patch->>'last_action_by', '') else last_action_by end,
    last_action_at = case when p_patch ? 'last_action_at' then nullif(p_patch->>'last_action_at', '')::timestamptz else last_action_at end,
    workflow_step = case when p_patch ? 'workflow_step' then nullif(p_patch->>'workflow_step', '') else workflow_step end,
    workflow_step_started_at = case when p_patch ? 'workflow_step_started_at' then nullif(p_patch->>'workflow_step_started_at', '')::timestamptz else workflow_step_started_at end,
    workflow_step_due_at = case when p_patch ? 'workflow_step_due_at' then nullif(p_patch->>'workflow_step_due_at', '')::timestamptz else workflow_step_due_at end,
    workflow_step_sla_hours = case when p_patch ? 'workflow_step_sla_hours' then nullif(p_patch->>'workflow_step_sla_hours', '')::integer else workflow_step_sla_hours end,
    workflow_step_actor_user_id = case when p_patch ? 'workflow_step_actor_user_id' then nullif(p_patch->>'workflow_step_actor_user_id', '') else workflow_step_actor_user_id end,
    submitted_to_user_id = case when p_patch ? 'submitted_to_user_id' then nullif(p_patch->>'submitted_to_user_id', '') else submitted_to_user_id end,
    submitted_to_name = case when p_patch ? 'submitted_to_name' then nullif(p_patch->>'submitted_to_name', '') else submitted_to_name end,
    submitted_to_permission = case when p_patch ? 'submitted_to_permission' then nullif(p_patch->>'submitted_to_permission', '') else submitted_to_permission end,
    submission_note = case when p_patch ? 'submission_note' then nullif(p_patch->>'submission_note', '') else submission_note end
  where id = p_request_id
  returning * into v_request;

  perform set_config('app.material_transition_context', coalesce(v_previous_guard, ''), true);
  return v_request;
end;
$$;


ALTER FUNCTION "public"."transition_project_material_request_status"("p_request_id" "text", "p_status" "text", "p_action" "text", "p_actor_user_id" "text", "p_target_user_id" "text", "p_target_permission" "text", "p_note" "text", "p_patch" "jsonb") OWNER TO "postgres";


