ALTER TABLE "public"."payment_certificates" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."transition_project_payment_certificate_status"("p_certificate_id" "uuid", "p_status" "text", "p_actor_user_id" "uuid", "p_reason" "text" DEFAULT NULL::"text", "p_target_user_id" "text" DEFAULT NULL::"text", "p_target_name" "text" DEFAULT NULL::"text", "p_target_permission" "text" DEFAULT NULL::"text", "p_submission_note" "text" DEFAULT NULL::"text") RETURNS "public"."payment_certificates"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_certificate public.payment_certificates%rowtype;
  v_user_id uuid := public.current_app_user_id();
  v_required_permission text;
  v_previous_guard text;
  v_expected_target_permission text;
begin
  if v_user_id is null or p_actor_user_id is distinct from v_user_id then
    raise exception 'Không xác định được người dùng chuyển trạng thái chứng từ thanh toán.'
      using errcode = '42501';
  end if;

  select *
  into v_certificate
  from public.payment_certificates
  where id = p_certificate_id
  for update;

  if not found then
    raise exception 'Không tìm thấy chứng từ thanh toán.';
  end if;

  v_required_permission := case p_status
    when 'submitted' then 'project.payment.submit'
    when 'returned' then 'project.payment.verify'
    when 'approved' then 'project.payment.approve'
    when 'cancelled' then 'project.payment.approve'
    when 'paid' then 'project.payment.confirm'
    else null
  end;

  if v_required_permission is null then
    raise exception 'Trạng thái chứng từ thanh toán không hợp lệ: %', p_status
      using errcode = '23514';
  end if;

  if (p_status = 'submitted' and coalesce(v_certificate.status, 'draft') not in ('draft', 'returned'))
    or (p_status in ('returned', 'approved') and v_certificate.status is distinct from 'submitted')
    or (p_status = 'paid' and v_certificate.status is distinct from 'approved')
    or (p_status = 'cancelled' and coalesce(v_certificate.status, 'draft') not in ('approved', 'paid'))
  then
    raise exception 'Chuyển trạng thái chứng từ thanh toán không hợp lệ: % -> %.', v_certificate.status, p_status
      using errcode = '23514';
  end if;

  if p_status in ('returned', 'cancelled') and nullif(btrim(coalesce(p_reason, '')), '') is null then
    raise exception 'Cần nêu lý do trả lại hoặc hủy chứng từ thanh toán.'
      using errcode = '23514';
  end if;

  if p_status in ('submitted', 'approved', 'paid')
    and coalesce(jsonb_array_length(v_certificate.items), 0) = 0
    and not exists (
      select 1
      from public.payment_certificate_items item_row
      where item_row.payment_certificate_id = p_certificate_id
    )
  then
    raise exception 'Chứng từ thanh toán chưa có hạng mục.'
      using errcode = '23514';
  end if;

  if p_status = 'approved' and v_certificate.acceptance_id is not null and not exists (
    select 1
    from public.quantity_acceptances acceptance_row
    where acceptance_row.id = v_certificate.acceptance_id
      and acceptance_row.status = 'approved'
  ) then
    raise exception 'Phải duyệt nghiệm thu liên kết trước khi duyệt chứng từ thanh toán.'
      using errcode = '23514';
  end if;

  if not public.is_admin()
    and v_certificate.submitted_to_user_id is not null
    and p_status in ('returned', 'approved', 'paid')
    and v_certificate.submitted_to_user_id <> v_user_id::text
  then
    raise exception 'Bạn không phải người đang được giao xử lý chứng từ thanh toán.'
      using errcode = '42501';
  end if;

  if not app_private.project_has_permission_v2(
    v_certificate.project_id::text,
    v_certificate.construction_site_id::text,
    v_required_permission,
    v_user_id
  ) then
    raise exception 'Bạn cần quyền % để chuyển trạng thái chứng từ thanh toán.', v_required_permission
      using errcode = '42501';
  end if;

  v_expected_target_permission := case p_status
    when 'submitted' then 'project.payment.approve'
    when 'approved' then 'project.payment.confirm'
    else null
  end;

  if v_expected_target_permission is not null then
    if nullif(p_target_user_id, '') is null or p_target_permission is distinct from v_expected_target_permission then
      raise exception 'Cần chọn người nhận có quyền %.', v_expected_target_permission
        using errcode = '23514';
    end if;
    if not app_private.project_has_permission_v2(
      v_certificate.project_id::text,
      v_certificate.construction_site_id::text,
      p_target_permission,
      p_target_user_id::uuid
    ) then
      raise exception 'Người được chọn chưa có quyền % trong phạm vi dự án.', p_target_permission
        using errcode = '42501';
    end if;
  end if;

  v_previous_guard := current_setting('app.project_document_transition_context', true);
  perform set_config('app.project_document_transition_context', 'on', true);

  update public.payment_certificates
  set
    status = p_status,
    submitted_by = case when p_status = 'submitted' then v_user_id::text else submitted_by end,
    submitted_at = case when p_status = 'submitted' then now() else submitted_at end,
    returned_by = case when p_status = 'returned' then v_user_id::text else returned_by end,
    returned_at = case when p_status = 'returned' then now() else returned_at end,
    return_reason = case when p_status = 'returned' then p_reason else return_reason end,
    approved_by = case when p_status = 'approved' then v_user_id::text else approved_by end,
    approved_at = case when p_status = 'approved' then now() else approved_at end,
    paid_at = case when p_status = 'paid' then now() else paid_at end,
    submitted_to_user_id = case
      when p_status in ('submitted', 'approved') then p_target_user_id
      when p_status = 'returned' then v_certificate.submitted_by
      when p_status in ('paid', 'cancelled') then null
      else submitted_to_user_id
    end,
    submitted_to_name = case
      when p_status in ('submitted', 'approved') then p_target_name
      when p_status = 'returned' then null
      when p_status in ('paid', 'cancelled') then null
      else submitted_to_name
    end,
    submitted_to_permission = case
      when p_status in ('submitted', 'approved') then p_target_permission
      when p_status = 'returned' then 'edit'
      when p_status in ('paid', 'cancelled') then null
      else submitted_to_permission
    end,
    submission_note = case
      when p_status in ('submitted', 'approved') then p_submission_note
      when p_status in ('returned', 'paid', 'cancelled') then p_reason
      else submission_note
    end,
    updated_at = now()
  where id = p_certificate_id
  returning * into v_certificate;

  perform set_config('app.project_document_transition_context', coalesce(v_previous_guard, ''), true);
  return v_certificate;
end;
$$;


ALTER FUNCTION "public"."transition_project_payment_certificate_status"("p_certificate_id" "uuid", "p_status" "text", "p_actor_user_id" "uuid", "p_reason" "text", "p_target_user_id" "text", "p_target_name" "text", "p_target_permission" "text", "p_submission_note" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."transition_project_purchase_order_status"("p_po_id" "text", "p_status" "text", "p_patch" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_po public.purchase_orders%rowtype;
  v_user_id uuid := public.current_app_user_id();
  v_required_permission text;
  v_previous_guard text;
begin
  if v_user_id is null then
    raise exception 'Không xác định được người dùng chuyển trạng thái PO.'
      using errcode = '42501';
  end if;

  select *
  into v_po
  from public.purchase_orders
  where id = p_po_id
  for update;

  if not found then
    raise exception 'Không tìm thấy PO.';
  end if;

  if coalesce(p_status, '') = 'cancelled' then
    raise exception 'PO không được hủy qua luồng duyệt; dùng luồng Quy trình hoặc Yêu cầu.'
      using errcode = '23514';
  end if;

  v_required_permission := case
    when coalesce(p_status, '') in ('in_transit', 'partial', 'delivered', 'closed')
      or p_patch ? 'received_transaction_ids'
      or p_patch ? 'actual_delivery_date' then 'project.material_po.receive'
    when coalesce(p_status, '') = 'sent' then 'project.material_po.create'
    when coalesce(p_status, '') in ('confirmed', 'returned') then 'project.material_po.approve'
    else 'project.material_po.create'
  end;

  if v_required_permission = 'project.material_po.approve'
    and (
      lower(coalesce(v_po.status, '')) <> 'sent'
      or lower(coalesce(p_status, '')) not in ('confirmed', 'returned')
    )
  then
    raise exception 'Chỉ PO đang chờ duyệt mới được duyệt hoặc trả lại.'
      using errcode = '23514';
  end if;

  if coalesce(p_status, '') = 'sent'
    and lower(coalesce(v_po.status, '')) not in ('draft', 'returned')
  then
    raise exception 'Chỉ PO nháp hoặc bị trả lại mới được gửi duyệt.'
      using errcode = '23514';
  end if;

  if not (
    public.is_admin()
    or public.is_module_admin('DA')
    or (v_po.source_mode = 'company_consolidated' and app_private.company_procurement_can_manage())
    or (
      v_required_permission = 'project.material_po.receive'
      and (
        app_private.current_user_is_global_wms_keeper()
        or app_private.current_user_is_wms_keeper_for(v_po.target_warehouse_id)
      )
    )
    or app_private.material_has_action(v_po.project_id, v_po.construction_site_id, v_required_permission, v_user_id)
  ) then
    raise exception 'Bạn cần quyền % để chuyển trạng thái PO.', v_required_permission
      using errcode = '42501';
  end if;

  v_previous_guard := current_setting('app.material_transition_context', true);
  perform set_config('app.material_transition_context', 'on', true);

  update public.purchase_orders
  set
    status = coalesce(nullif(p_status, ''), status),
    submitted_to_user_id = case when p_patch ? 'submitted_to_user_id' then nullif(p_patch->>'submitted_to_user_id', '') else submitted_to_user_id end,
    submitted_to_name = case when p_patch ? 'submitted_to_name' then nullif(p_patch->>'submitted_to_name', '') else submitted_to_name end,
    submitted_to_permission = case when p_patch ? 'submitted_to_permission' then nullif(p_patch->>'submitted_to_permission', '') else submitted_to_permission end,
    submission_note = case when p_patch ? 'submission_note' then nullif(p_patch->>'submission_note', '') else submission_note end,
    ever_submitted = case when p_patch ? 'ever_submitted' then coalesce((p_patch->>'ever_submitted')::boolean, ever_submitted) else ever_submitted end,
    last_action_by = case when p_patch ? 'last_action_by' then nullif(p_patch->>'last_action_by', '') else last_action_by end,
    last_action_at = case when p_patch ? 'last_action_at' then nullif(p_patch->>'last_action_at', '')::timestamptz else last_action_at end,
    received_transaction_ids = case when p_patch ? 'received_transaction_ids' then coalesce(p_patch->'received_transaction_ids', '[]'::jsonb) else received_transaction_ids end,
    actual_delivery_date = case when p_patch ? 'actual_delivery_date' then nullif(p_patch->>'actual_delivery_date', '') else actual_delivery_date end
  where id = p_po_id;

  perform set_config('app.material_transition_context', coalesce(v_previous_guard, ''), true);
end;
$$;


ALTER FUNCTION "public"."transition_project_purchase_order_status"("p_po_id" "text", "p_status" "text", "p_patch" "jsonb") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."quantity_acceptances" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "contract_id" "uuid" NOT NULL,
    "contract_type" "text" NOT NULL,
    "construction_site_id" "uuid",
    "period_number" integer NOT NULL,
    "period_start" "date" NOT NULL,
    "period_end" "date" NOT NULL,
    "description" "text",
    "status" "text" DEFAULT 'draft'::"text" NOT NULL,
    "total_accepted_amount" numeric DEFAULT 0 NOT NULL,
    "submitted_by" "text",
    "submitted_at" timestamp with time zone,
    "approved_by" "text",
    "approved_at" timestamp with time zone,
    "returned_by" "text",
    "returned_at" timestamp with time zone,
    "return_reason" "text",
    "note" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "project_id" "text",
    "submitted_to_user_id" "text",
    "submitted_to_name" "text",
    "submitted_to_permission" "text",
    "submission_note" "text",
    "ever_submitted" boolean DEFAULT false NOT NULL,
    "last_action_by" "text",
    "last_action_at" timestamp with time zone,
    "acceptance_scope" "text" DEFAULT 'contract'::"text" NOT NULL,
    CONSTRAINT "quantity_acceptances_acceptance_scope_check" CHECK (("acceptance_scope" = ANY (ARRAY['internal'::"text", 'contract'::"text"]))),
    CONSTRAINT "quantity_acceptances_contract_type_check" CHECK (("contract_type" = ANY (ARRAY['customer'::"text", 'subcontractor'::"text"]))),
    CONSTRAINT "quantity_acceptances_status_check" CHECK (("status" = ANY (ARRAY['draft'::"text", 'submitted'::"text", 'returned'::"text", 'approved'::"text", 'cancelled'::"text"])))
);


ALTER TABLE "public"."quantity_acceptances" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."transition_project_quantity_acceptance_status"("p_acceptance_id" "uuid", "p_status" "text", "p_actor_user_id" "uuid", "p_reason" "text" DEFAULT NULL::"text", "p_target_user_id" "text" DEFAULT NULL::"text", "p_target_name" "text" DEFAULT NULL::"text", "p_target_permission" "text" DEFAULT NULL::"text", "p_submission_note" "text" DEFAULT NULL::"text") RETURNS "public"."quantity_acceptances"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_acceptance public.quantity_acceptances%rowtype;
  v_user_id uuid := public.current_app_user_id();
  v_required_permission text;
  v_previous_guard text;
begin
  if v_user_id is null or p_actor_user_id is distinct from v_user_id then
    raise exception 'Không xác định được người dùng chuyển trạng thái nghiệm thu.'
      using errcode = '42501';
  end if;

  select *
  into v_acceptance
  from public.quantity_acceptances
  where id = p_acceptance_id
  for update;

  if not found then
    raise exception 'Không tìm thấy nghiệm thu.';
  end if;

  v_required_permission := case p_status
    when 'submitted' then 'project.quantity_acceptance.submit'
    when 'returned' then 'project.quantity_acceptance.verify'
    when 'approved' then 'project.quantity_acceptance.approve'
    when 'cancelled' then 'project.quantity_acceptance.approve'
    else null
  end;

  if v_required_permission is null then
    raise exception 'Trạng thái nghiệm thu không hợp lệ: %', p_status
      using errcode = '23514';
  end if;

  if (p_status = 'submitted' and coalesce(v_acceptance.status, 'draft') not in ('draft', 'returned'))
    or (p_status in ('returned', 'approved') and v_acceptance.status is distinct from 'submitted')
    or (p_status = 'cancelled' and v_acceptance.status is distinct from 'approved')
  then
    raise exception 'Chuyển trạng thái nghiệm thu không hợp lệ: % -> %.', v_acceptance.status, p_status
      using errcode = '23514';
  end if;

  if p_status in ('returned', 'cancelled') and nullif(btrim(coalesce(p_reason, '')), '') is null then
    raise exception 'Cần nêu lý do trả lại hoặc hủy nghiệm thu.'
      using errcode = '23514';
  end if;

  if p_status in ('submitted', 'approved') and not exists (
    select 1
    from public.quantity_acceptance_items item_row
    where item_row.acceptance_id = p_acceptance_id
  ) then
    raise exception 'Nghiệm thu chưa có hạng mục.'
      using errcode = '23514';
  end if;

  if p_status = 'cancelled' and exists (
    select 1
    from public.payment_certificates certificate_row
    where certificate_row.acceptance_id = p_acceptance_id
  ) then
    raise exception 'Không thể hủy nghiệm thu vì đã có chứng từ thanh toán liên kết.'
      using errcode = '23514';
  end if;

  if not public.is_admin()
    and v_acceptance.submitted_to_user_id is not null
    and p_status in ('returned', 'approved')
    and v_acceptance.submitted_to_user_id <> v_user_id::text
  then
    raise exception 'Bạn không phải người đang được giao xử lý nghiệm thu.'
      using errcode = '42501';
  end if;

  if not app_private.project_has_permission_v2(
    v_acceptance.project_id::text,
    v_acceptance.construction_site_id::text,
    v_required_permission,
    v_user_id
  ) then
    raise exception 'Bạn cần quyền % để chuyển trạng thái nghiệm thu.', v_required_permission
      using errcode = '42501';
  end if;

  if p_status = 'submitted' then
    if nullif(p_target_user_id, '') is null or p_target_permission is distinct from 'project.quantity_acceptance.approve' then
      raise exception 'Cần chọn người nhận có quyền project.quantity_acceptance.approve.'
        using errcode = '23514';
    end if;
    if not app_private.project_has_permission_v2(
      v_acceptance.project_id::text,
      v_acceptance.construction_site_id::text,
      p_target_permission,
      p_target_user_id::uuid
    ) then
      raise exception 'Người được chọn chưa có quyền % trong phạm vi dự án.', p_target_permission
        using errcode = '42501';
    end if;
  end if;

  v_previous_guard := current_setting('app.project_document_transition_context', true);
  perform set_config('app.project_document_transition_context', 'on', true);

  update public.quantity_acceptances
  set
    status = p_status,
    submitted_by = case when p_status = 'submitted' then v_user_id::text else submitted_by end,
    submitted_at = case when p_status = 'submitted' then now() else submitted_at end,
    returned_by = case when p_status = 'returned' then v_user_id::text else returned_by end,
    returned_at = case when p_status = 'returned' then now() else returned_at end,
    return_reason = case when p_status = 'returned' then p_reason else return_reason end,
    approved_by = case when p_status = 'approved' then v_user_id::text else approved_by end,
    approved_at = case when p_status = 'approved' then now() else approved_at end,
    submitted_to_user_id = case
      when p_status = 'submitted' then p_target_user_id
      when p_status = 'returned' then v_acceptance.submitted_by
      when p_status in ('approved', 'cancelled') then null
      else submitted_to_user_id
    end,
    submitted_to_name = case
      when p_status = 'submitted' then p_target_name
      when p_status = 'returned' then null
      when p_status in ('approved', 'cancelled') then null
      else submitted_to_name
    end,
    submitted_to_permission = case
      when p_status = 'submitted' then p_target_permission
      when p_status = 'returned' then 'edit'
      when p_status in ('approved', 'cancelled') then null
      else submitted_to_permission
    end,
    submission_note = case
      when p_status = 'submitted' then p_submission_note
      when p_status in ('returned', 'cancelled') then p_reason
      else submission_note
    end,
    updated_at = now()
  where id = p_acceptance_id
  returning * into v_acceptance;

  perform set_config('app.project_document_transition_context', coalesce(v_previous_guard, ''), true);
  return v_acceptance;
end;
$$;


ALTER FUNCTION "public"."transition_project_quantity_acceptance_status"("p_acceptance_id" "uuid", "p_status" "text", "p_actor_user_id" "uuid", "p_reason" "text", "p_target_user_id" "text", "p_target_name" "text", "p_target_permission" "text", "p_submission_note" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."unrecord_supplier_direct_delivery_note"("p_note_id" "uuid") RETURNS "public"."supplier_direct_delivery_notes"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
declare
  v_note public.supplier_direct_delivery_notes%rowtype;
begin
  select * into v_note
  from public.supplier_direct_delivery_notes
  where id = p_note_id
  for update;

  if not found then
    raise exception 'Không tìm thấy phiếu giao HĐ NCC %. ', p_note_id;
  end if;

  if not app_private.material_flow_has_action_or_legacy(v_note.project_id, v_note.construction_site_id, 'project.material_supplier_delivery.unrecord') then
    raise exception 'Bạn không có quyền bỏ ghi phiếu giao HĐ NCC.';
  end if;

  if exists (
    select 1
    from public.supplier_direct_delivery_lines line
    where line.delivery_note_id = p_note_id
      and (
        line.statement_id is not null
        or line.wms_import_transaction_id is not null
        or line.wms_export_transaction_id is not null
      )
  ) then
    raise exception 'Không thể bỏ ghi phiếu giao HĐ NCC đã phát sinh WMS/đối soát/AP.';
  end if;

  update public.supplier_direct_delivery_lines
  set status = 'pending',
      accepted_quantity = 0,
      accepted_amount = 0,
      updated_at = now()
  where delivery_note_id = p_note_id;

  update public.supplier_direct_delivery_notes
  set status = 'draft',
      gross_amount = 0,
      vat_amount = 0,
      total_amount = 0,
      updated_at = now()
  where id = p_note_id
  returning * into v_note;

  return v_note;
end;
$$;


ALTER FUNCTION "public"."unrecord_supplier_direct_delivery_note"("p_note_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_hrm_doc_search_vector"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  NEW.search_vector :=
    setweight(to_tsvector('simple', COALESCE(NEW.title, '')), 'A') ||
    setweight(to_tsvector('simple', COALESCE(unaccent(NEW.title), '')), 'A') ||
    setweight(to_tsvector('simple', COALESCE(NEW.doc_number, '')), 'A') ||
    setweight(to_tsvector('simple', COALESCE(NEW.description, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(unaccent(COALESCE(NEW.description, '')), '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(NEW.sender, '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(NEW.receiver, '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(NEW.file_name, '')), 'C') ||
    setweight(to_tsvector('simple', array_to_string(COALESCE(NEW.tags, '{}'), ' ')), 'C');
  RETURN NEW;
END;
$$;


