CREATE TABLE IF NOT EXISTS "public"."inventory_ledger_entries" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "inventory_transaction_id" "uuid" NOT NULL,
    "entry_no" integer NOT NULL,
    "document_code" "text" NOT NULL,
    "transaction_date" timestamp with time zone NOT NULL,
    "transaction_type" "text" NOT NULL,
    "movement_direction" "text" NOT NULL,
    "material_id" "text" NOT NULL,
    "warehouse_id" "text" NOT NULL,
    "project_id" "text",
    "construction_site_id" "text",
    "lot_no" "text",
    "batch_no" "text",
    "serial_no" "text",
    "source_type" "text" NOT NULL,
    "source_id" "text" NOT NULL,
    "source_code" "text" NOT NULL,
    "source_line_id" "text",
    "related_request_id" "text",
    "quantity_in" numeric(18,4) DEFAULT 0 NOT NULL,
    "quantity_out" numeric(18,4) DEFAULT 0 NOT NULL,
    "quantity_delta" numeric(18,4) GENERATED ALWAYS AS (("quantity_in" - "quantity_out")) STORED,
    "unit" "text",
    "unit_price" numeric(18,4) DEFAULT 0 NOT NULL,
    "amount" numeric(18,4) GENERATED ALWAYS AS ((("quantity_in" - "quantity_out") * "unit_price")) STORED,
    "balance_after_qty" numeric(18,4) DEFAULT 0 NOT NULL,
    "balance_after_value" numeric(18,4) DEFAULT 0 NOT NULL,
    "description" "text",
    "metadata" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "created_by" "uuid",
    "approved_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "inventory_ledger_entries_direction_qty_check" CHECK (((("movement_direction" = 'in'::"text") AND ("quantity_in" > (0)::numeric) AND ("quantity_out" = (0)::numeric)) OR (("movement_direction" = 'out'::"text") AND ("quantity_out" > (0)::numeric) AND ("quantity_in" = (0)::numeric)))),
    CONSTRAINT "inventory_ledger_entries_movement_direction_check" CHECK (("movement_direction" = ANY (ARRAY['in'::"text", 'out'::"text"]))),
    CONSTRAINT "inventory_ledger_entries_quantity_in_check" CHECK (("quantity_in" >= (0)::numeric)),
    CONSTRAINT "inventory_ledger_entries_quantity_out_check" CHECK (("quantity_out" >= (0)::numeric))
);


