CREATE OR REPLACE VIEW "public"."supplier_payable_document_balances" WITH ("security_invoker"='true') AS
 WITH "paid_allocations" AS (
         SELECT "a"."payable_document_id",
            "sum"("a"."allocated_amount") AS "paid_amount",
            "sum"(("a"."discount_amount" + "a"."withholding_amount")) AS "non_cash_credit_amount"
           FROM ("public"."supplier_payment_allocations" "a"
             JOIN "public"."supplier_payment_batches" "b" ON (("b"."id" = "a"."payment_batch_id")))
          WHERE ("b"."status" = 'paid'::"text")
          GROUP BY "a"."payable_document_id"
        )
 SELECT "d"."id",
    "d"."code",
    "d"."source_type",
    "d"."source_id",
    "d"."project_id",
    "d"."construction_site_id",
    "d"."supplier_id",
    "d"."supplier_name_snapshot",
    "d"."document_no",
    "d"."document_date",
    "d"."due_date",
    "d"."currency",
    "d"."committed_amount",
    "d"."recognized_amount",
    "d"."credit_amount",
    "d"."status",
    "d"."qr_token",
    "d"."invoice_number",
    "d"."invoice_date",
    "d"."metadata",
    "d"."created_by",
    "d"."created_at",
    "d"."updated_at",
    (COALESCE("p"."paid_amount", (0)::numeric))::numeric(18,2) AS "paid_amount",
    (COALESCE("p"."non_cash_credit_amount", (0)::numeric))::numeric(18,2) AS "allocation_credit_amount",
    (GREATEST((0)::numeric, ((("d"."recognized_amount" - "d"."credit_amount") - COALESCE("p"."paid_amount", (0)::numeric)) - COALESCE("p"."non_cash_credit_amount", (0)::numeric))))::numeric(18,2) AS "outstanding_amount",
    (("d"."due_date" IS NOT NULL) AND ("d"."due_date" < CURRENT_DATE) AND (GREATEST((0)::numeric, ((("d"."recognized_amount" - "d"."credit_amount") - COALESCE("p"."paid_amount", (0)::numeric)) - COALESCE("p"."non_cash_credit_amount", (0)::numeric))) > (0)::numeric)) AS "is_overdue",
    "d"."supplier_contract_id",
    "d"."supplier_contract_code"
   FROM ("public"."supplier_payable_documents" "d"
     LEFT JOIN "paid_allocations" "p" ON (("p"."payable_document_id" = "d"."id")));


ALTER VIEW "public"."supplier_payable_document_balances" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."supplier_payable_balances" WITH ("security_invoker"='true') AS
 SELECT "md5"("concat_ws"('|'::"text", COALESCE("project_id", ''::"text"), COALESCE("construction_site_id", ''::"text"), COALESCE("supplier_id", ''::"text"), "currency")) AS "id",
    "project_id",
    "construction_site_id",
    "supplier_id",
    "max"("supplier_name_snapshot") AS "supplier_name_snapshot",
    "currency",
    ("sum"("recognized_amount"))::numeric(18,2) AS "recognized_amount",
    ("sum"("paid_amount"))::numeric(18,2) AS "paid_amount",
    ("sum"(("credit_amount" + "allocation_credit_amount")))::numeric(18,2) AS "credit_amount",
    ("sum"("outstanding_amount"))::numeric(18,2) AS "outstanding_amount",
    ("count"(*))::integer AS "document_count",
    "min"("due_date") FILTER (WHERE ("outstanding_amount" > (0)::numeric)) AS "oldest_due_date",
    "max"("document_date") AS "latest_document_date",
    "bool_or"("is_overdue") AS "is_overdue",
    "max"("updated_at") AS "updated_at"
   FROM "public"."supplier_payable_document_balances"
  WHERE ("status" <> ALL (ARRAY['cancelled'::"text", 'reversed'::"text"]))
  GROUP BY "project_id", "construction_site_id", "supplier_id", "currency";


ALTER VIEW "public"."supplier_payable_balances" OWNER TO "postgres";


