CREATE TABLE IF NOT EXISTS "public"."workflow_instance_comments" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "instance_id" "uuid" NOT NULL,
    "author_user_id" "uuid" NOT NULL,
    "body" "text" DEFAULT ''::"text" NOT NULL,
    "attachments" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "workflow_instance_comments_content_check" CHECK (
CASE
    WHEN ("jsonb_typeof"("attachments") = 'array'::"text") THEN (("jsonb_array_length"("attachments") <= 5) AND ("length"("body") <= 4000) AND (("length"(TRIM(BOTH FROM "body")) > 0) OR ("jsonb_array_length"("attachments") > 0)))
    ELSE false
END)
);


